-- Poems batch 107
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5795be8a-2d91-459a-9e6a-8b2f876de92a','仲春','吳濤','宋','宋诗','song-poetry','','[]','雨餘寒氣淺，園林作春媚。',24,'全唐诗/poet.song.122000.json','["雨餘寒氣淺，園林作春媚。", "不知海棠花，新來著花未。"]'),
('6ef29dcc-d9d5-40f6-960a-b18a47588742','暮春','吳濤','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u7f81\u65c5", "\u5b8b\u8bd7"]','遊子春衫已試單，桃花飛盡野梅酸。',32,'全唐诗/poet.song.122000.json','["遊子春衫已試單，桃花飛盡野梅酸。", "怪來一夜蛙聲歇，又作東風十日寒。"]'),
('56020ff2-4c43-4e0a-9288-531fcf019472','山居','吳濤','宋','宋诗','song-poetry','','[]','村翁習性不浮華，只種桑麻不種花。',32,'全唐诗/poet.song.122000.json','["村翁習性不浮華，只種桑麻不種花。", "聞道野梅開欲遍，好分春色過山家。"]'),
('ae70a7dd-4689-4c17-a170-94468fdbcabf','句  其一','吳濤','宋','宋诗','song-poetry','','[]','文書堆裏形骸苦，竹木陰中日月閒。',16,'全唐诗/poet.song.122000.json','["文書堆裏形骸苦，竹木陰中日月閒。"]'),
('7e0d10cd-d1ea-431e-8730-169003f3d1ac','句  其二','吳濤','宋','宋诗','song-poetry','','[]','窗間常作三獨坐，琴上時彈一再行。',16,'全唐诗/poet.song.122000.json','["窗間常作三獨坐，琴上時彈一再行。"]'),
('dda96832-6f70-4d9c-8a9f-8d7cee68d083','句  其三','吳濤','宋','宋诗','song-poetry','','[]','心緣黄紙紅旗動，氣爲青雲白石降。',16,'全唐诗/poet.song.122000.json','["心緣黄紙紅旗動，氣爲青雲白石降。"]'),
('8137b8b5-1dc1-4e5c-96e7-d5a6840fdc86','苦陰','吳光','宋','宋诗','song-poetry','','[]','荒山乾沒更節序，濁氣擁地愁無邊。',32,'全唐诗/poet.song.122000.json','["荒山乾沒更節序，濁氣擁地愁無邊。", "非烟非霧不見日，欲雨欲雪難爲天。"]'),
('49e42b7b-de7c-44a1-9dc8-bd407f0412a1','回文暮春','吳光','宋','宋诗','song-poetry','','[]','嬌聲囀處藏鸚小，美睡濃時落日斜。',32,'全唐诗/poet.song.122000.json','["嬌聲囀處藏鸚小，美睡濃時落日斜。", "橋拂柳溪深漲水，眼驚春雨過飛花。"]'),
('0abc86a7-f3ab-47e1-8300-a134ffcf0b52','句  其一','吳光','宋','宋诗','song-poetry','','[]','簷頭清響銀匙動，階下寒光玉碗翻。',16,'全唐诗/poet.song.122000.json','["簷頭清響銀匙動，階下寒光玉碗翻。"]'),
('131f5011-bc0b-4181-9397-44d9a6617238','句  其二','吳光','宋','宋诗','song-poetry','','[]','也應只是尋常夜，未必如今分外圓。',16,'全唐诗/poet.song.122000.json','["也應只是尋常夜，未必如今分外圓。"]'),
('a5510061-f4e3-4f8d-8978-67261cd3f5cf','句  其三','吳光','宋','宋诗','song-poetry','','[]','獨鶴下隨雞飲啄，眾星高共月徘徊。',16,'全唐诗/poet.song.122000.json','["獨鶴下隨雞飲啄，眾星高共月徘徊。"]'),
('0b834cb7-01ed-4bad-881a-227232356a51','句  其四','吳光','宋','宋诗','song-poetry','','[]','半塘微漲聚紅皺，幾畝清陰鎖碧鮮。',16,'全唐诗/poet.song.122000.json','["半塘微漲聚紅皺，幾畝清陰鎖碧鮮。"]'),
('76c0b48b-1e08-45b3-9d80-43b5c49bdc76','句  其五','吳光','宋','宋诗','song-poetry','','[]','花蕊有鬚渾带蜜，桑枝無葉已成衣。',16,'全唐诗/poet.song.122000.json','["花蕊有鬚渾带蜜，桑枝無葉已成衣。"]'),
('e7d02d36-1d88-49c1-9de2-1618de5130bc','句  其六','吳光','宋','宋诗','song-poetry','','[]','輕雷入樹驚花魄，白浪浮空漲水脂。',16,'全唐诗/poet.song.122000.json','["輕雷入樹驚花魄，白浪浮空漲水脂。"]'),
('352fc89e-6e21-4f69-87bf-0b35ee6bccb3','句  其七','吳光','宋','宋诗','song-poetry','','[]','日長人靜聞風佩，雨久堂空生水衣。',16,'全唐诗/poet.song.122000.json','["日長人靜聞風佩，雨久堂空生水衣。"]'),
('f1a60ec0-c40f-4b16-af9c-972edb8a145a','句  其八','吳光','宋','宋诗','song-poetry','','[]','二天開佛日，一道羃卿雲。',12,'全唐诗/poet.song.122000.json','["二天開佛日，一道羃卿雲。"]'),
('15a3d987-7f54-49c0-86d5-29aef61c3e17','句  其九','吳光','宋','宋诗','song-poetry','','[]','無苗何處尋黄犢，露地誰家覓白牛。',16,'全唐诗/poet.song.122000.json','["無苗何處尋黄犢，露地誰家覓白牛。"]'),
('383cda4f-2f5d-47fd-8214-6c9e91245559','句  其一○','吳光','宋','宋诗','song-poetry','','[]','簷花謝女雪，徑掃沈郎錢。',12,'全唐诗/poet.song.122000.json','["簷花謝女雪，徑掃沈郎錢。"]'),
('7bfe6653-346e-40b5-93f2-bfff4dcf8af1','句  其一一','吳光','宋','宋诗','song-poetry','','[]','笛弄一聲橫釣艇，月明千里上層樓。',16,'全唐诗/poet.song.122000.json','["笛弄一聲橫釣艇，月明千里上層樓。"]'),
('41e69a85-53ab-45d3-9be3-2581aaf8cf8f','句  其一二','吳光','宋','宋诗','song-poetry','','[]','寫處似移牆上影，捲來如寄隴頭春。',16,'全唐诗/poet.song.122000.json','["寫處似移牆上影，捲來如寄隴頭春。"]'),
('9d611954-ab50-45d4-8526-213b11cd3a23','句  其一三','吳光','宋','宋诗','song-poetry','','[]','朱唇不注曉妝薄，玉頰頻啼夜雨翻。',16,'全唐诗/poet.song.122000.json','["朱唇不注曉妝薄，玉頰頻啼夜雨翻。"]'),
('9f7fe36c-5a7e-443e-afc2-3c3064941769','句  其一四','吳光','宋','宋诗','song-poetry','','[]','農祥待白未爲雪，春榜爭魁欲放梅。',16,'全唐诗/poet.song.122000.json','["農祥待白未爲雪，春榜爭魁欲放梅。"]'),
('bd9e1f66-457c-4082-9d35-7d5f2ed2c987','句  其一五','吳光','宋','宋诗','song-poetry','','[]','泉聲如有語，山色自忘形。',24,'全唐诗/poet.song.122000.json','["泉聲如有語，山色自忘形。", "花覺青春半，山將白晝陰。"]'),
('2c1f6eb2-3533-4f3a-974b-54d0917c0a2f','句  其一六','吳光','宋','宋诗','song-poetry','','[]','冰看時俗薄，雨弄客愁多。',12,'全唐诗/poet.song.122000.json','["冰看時俗薄，雨弄客愁多。"]'),
('aa44894f-9b19-4088-a40a-9e8e2e150e04','句  其一七','吳光','宋','宋诗','song-poetry','','[]','月借窗移疏影轉，風翻雪放一枝高。',16,'全唐诗/poet.song.122000.json','["月借窗移疏影轉，風翻雪放一枝高。"]'),
('bf5afd48-51f1-4240-8776-0fb7c8cbb2fc','句  其一八','吳光','宋','宋诗','song-poetry','','[]','蒹葭露滴思鄉恨，蘆荻風縈羈旅愁。',16,'全唐诗/poet.song.122000.json','["蒹葭露滴思鄉恨，蘆荻風縈羈旅愁。"]'),
('1a591d1b-5e16-4890-bd8e-b137dbb73128','句  其一九','吳光','宋','宋诗','song-poetry','','[]','人情不似溪流水，不改當時枕上聲。',16,'全唐诗/poet.song.122000.json','["人情不似溪流水，不改當時枕上聲。"]'),
('f4349aa3-9017-45fb-bedc-34be82fbc63f','句  其二○','吳光','宋','宋诗','song-poetry','','[]','一軸塵埃古澀體，十年燈火短長檠。',16,'全唐诗/poet.song.122000.json','["一軸塵埃古澀體，十年燈火短長檠。"]'),
('fce8f900-3d0f-46f1-989d-47c9eeac2904','句  其二一','吳光','宋','宋诗','song-poetry','','[]','夢過一年還是魘，心更萬事竟成灰。',16,'全唐诗/poet.song.122000.json','["夢過一年還是魘，心更萬事竟成灰。"]'),
('c04117f2-dcdd-4a9b-aac1-362f30a87524','句  其二二','吳光','宋','宋诗','song-poetry','','[]','道上飛來燕，簾間不避人。',12,'全唐诗/poet.song.122000.json','["道上飛來燕，簾間不避人。"]'),
('38b5fc8c-705a-4efb-8c5d-cbc3e292d93c','句  其二三','吳光','宋','宋诗','song-poetry','','[]','彈壓京畿賢大尹，藩宣上國古賢侯。',16,'全唐诗/poet.song.122000.json','["彈壓京畿賢大尹，藩宣上國古賢侯。"]'),
('2bdc580d-7390-44a3-943b-e7636c256d7f','句','俞秀才','宋','宋诗','song-poetry','','[]','天高日遠雲霧闊，黄金白璧孤虞卿。',32,'全唐诗/poet.song.122000.json','["天高日遠雲霧闊，黄金白璧孤虞卿。", "漢廷無人薦司馬，故山有客呼孔賓。"]'),
('e85684b4-7604-4518-b0e6-7d85b7ac45d9','東西船行','李浩','宋','宋诗','song-poetry','','[]','東船得風帆席高，千里瞬息輕鴻毛。',64,'全唐诗/poet.song.122000.json','["東船得風帆席高，千里瞬息輕鴻毛。", "西船見笑苦遲鈍，汗流撐折百張篙。", "明日風翻波浪異，西笑東船却如此。", "東西相笑無已時，我但行藏任天理。"]'),
('660537a4-ce0f-41b4-893c-73f368eb61b3','寄同參嚴康朝偈','李浩','宋','宋诗','song-poetry','','[]','門有孫臏鋪，家存甘贄妻。',24,'全唐诗/poet.song.122000.json','["門有孫臏鋪，家存甘贄妻。", "夜眠還早起，誰悟復誰迷。"]'),
('a783bbe7-b38c-456c-8a50-2749cf81c676','贈鬻胭脂者偈','李浩','宋','宋诗','song-poetry','','[]','不塗紅粉自風流，往往禪徒到此休。',32,'全唐诗/poet.song.122000.json','["不塗紅粉自風流，往往禪徒到此休。", "透過古今圈後，却來這裏喫拳頭。"]'),
('b6440956-8df5-4751-9e31-d93b0fc5fd77','出疏山','李浩','宋','宋诗','song-poetry','','[]','忙中安得此身閑，杖策西風自往還。',32,'全唐诗/poet.song.122000.json','["忙中安得此身閑，杖策西風自往還。", "今日已償雲水債，籃輿带雨下疏山。"]'),
('747f2dc2-9dcd-4c60-b437-c3c20a10360e','述陂','李浩','宋','宋诗','song-poetry','','[]','數椽臨蒼波，我目得以寓。',96,'全唐诗/poet.song.122000.json','["數椽臨蒼波，我目得以寓。", "長溪山根來，澄潭一回互。", "萬象森可掬，翛翛澹清素。", "草短牛羊饑，沙暖鳧鶩聚。", "枯槎出斷岸，孤艇橫野渡。", "荒寒何代城，隱淪尚門戶。", "昔時歌舞地，今日採樵路。", "回薄萬古心，斜陽在烟樹。"]'),
('96b76553-5a4d-4d3d-be1f-00d4dbdc182c','和朱晦翁作','陳光','宋','宋诗','song-poetry','','[]','去年渭北望卿頻，今日深山屐齒新。',64,'全唐诗/poet.song.122000.json','["去年渭北望卿頻，今日深山屐齒新。", "珠樹香沾千澗雨，蓮峰翠滴四時春。", "漁郎有意休相問，樵子無心可與親。", "石榻盤旋忘歲月，瓶罍羞罄故人貧。"]'),
('b9ad43d5-b0df-4809-a462-51b3408e4f5b','瑞香花','毛幵','宋','宋诗','song-poetry','','[]','眾妙與春競，紛紛持所長。',36,'全唐诗/poet.song.122000.json','["眾妙與春競，紛紛持所長。", "此花最幽遠，如以禮自將。", "猗蘭敢回步，薝蔔亦退藏。"]'),
('749bff38-9b87-4ee0-bb7e-af9aa0e00a17','弔子陵釣臺','毛幵','宋','宋诗','song-poetry','','[]','先生高隱事如何，豈謂功名不足多。',32,'全唐诗/poet.song.122000.json','["先生高隱事如何，豈謂功名不足多。", "知道故人能辨事，一竿贏得釣清波。"]'),
('a9e960e5-cd13-4e98-b6a7-6d5aac13f36f','題闖山亭','毛幵','宋','宋诗','song-poetry','','[]','捲簾新雨霽，伏檻孤雲沒。',24,'全唐诗/poet.song.122000.json','["捲簾新雨霽，伏檻孤雲沒。", "心賞信無同，佳人眇天末。"]'),
('9bb0bd5a-f290-4aa3-81f9-6e2443a3ba95','月坡亭李耆明見菊  其一','毛幵','宋','宋诗','song-poetry','','[]','初陽散微和，晞露耿餘明。',48,'全唐诗/poet.song.122000.json','["初陽散微和，晞露耿餘明。", "引花吸其精，助我養修齡。", "人生憑化遷，日夜枯與榮。", "聊爲寂寞遊，放此真率情。"]'),
('2292f1a0-2db1-4f5c-a235-b64eacd58729','月坡亭李耆明見菊  其二','毛幵','宋','宋诗','song-poetry','','[]','我懷淵明真，千載猶神交。',84,'全唐诗/poet.song.122000.json','["我懷淵明真，千載猶神交。", "重吟九日詩，風節殊未凋。", "良辰不再舉，秋氣日以高。", "凄飚送落景，餘霞歛塵霄。", "萬象爲我役，天機亦良勞。", "摩挲膝間桐，感此爨下焦。", "時時出奇音，散我心鬰陶。"]'),
('4814e56d-e842-4ebf-ac04-1da1935a2edb','泊釣臺  其一','毛幵','宋','宋诗','song-poetry','','[]','衮衣但决妖邪讖，茅土先封不義臣。',32,'全唐诗/poet.song.122000.json','["衮衣但决妖邪讖，茅土先封不義臣。", "須信俛隨雞鶩食，豈如湖海一閑身。"]'),
('a4b9ceec-832d-4490-871d-cac2dec47bb4','泊釣臺  其二','毛幵','宋','宋诗','song-poetry','','[]','白鶴千秋去不歸，山川蕭瑟閟光輝。',32,'全唐诗/poet.song.122000.json','["白鶴千秋去不歸，山川蕭瑟閟光輝。", "孫郎祖墓今無主，不及先生一釣磯。"]'),
('9141eae0-6eca-45ad-bf0e-af1e712e0b3f','泊釣臺  其三','毛幵','宋','宋诗','song-poetry','','[]','漢業中興彼一時，先生名與日星垂。',32,'全唐诗/poet.song.122000.json','["漢業中興彼一時，先生名與日星垂。", "南陽遺廟今荒草，何似桐江百世祠。"]'),
('a65d2b7a-703c-4e8d-8deb-cd20bf492e57','泊釣臺  其四','毛幵','宋','宋诗','song-poetry','','[]','洲渚寒雲薄暮天，蕭蕭燈火落帆邊。',32,'全唐诗/poet.song.122000.json','["洲渚寒雲薄暮天，蕭蕭燈火落帆邊。", "嚴陵灘下孤舟遠，一夜歸心聽雨眠。"]'),
('1caa94ac-3fdd-4fb2-bc36-5f3c48b0cfac','句','毛幵','宋','宋诗','song-poetry','','[]','欲雪盡時携酒去，無人知處得花開。',16,'全唐诗/poet.song.122000.json','["欲雪盡時携酒去，無人知處得花開。"]'),
('85e16c8c-457d-4734-8524-47731f389618','同廖繼道游洞霄','陳伯山','宋','宋诗','song-poetry','','[]','勝日事幽尋，乘興從所適。',84,'全唐诗/poet.song.122000.json','["勝日事幽尋，乘興從所適。", "西風飄杖屨，偶作洞霄客。", "穿雲渡澗崗，捫蘿轉空碧。", "七人今何在，九鎖峰巒密。", "黄冠喜我輩，傾懷論宿昔。", "汲泉煮山苗，異氣穿几席。", "區區名利人，到此塵機息。"]'),
('f5d2aaaa-5670-477e-aeac-56af7f09450f','覽翠亭','王輝','宋','宋诗','song-poetry','','[]','亭倚古臺邊，環亭翠蔚然。',48,'全唐诗/poet.song.122000.json','["亭倚古臺邊，環亭翠蔚然。", "芝蘭深雨露，梧竹老風煙。", "窗戶香霏濕，闌干爽氣連。", "登臨忘世慮，逸興發林泉。"]'),
('071c8f58-87d7-40ec-9434-15057eee27cd','偈二首  其一','釋道樞','宋','宋诗','song-poetry','','[]','仙人張果老，騎驢穿市過。',24,'全唐诗/poet.song.122000.json','["仙人張果老，騎驢穿市過。", "但聞歸撥剌，誰知是紙做。"]'),
('f58973c8-1451-4c6c-8cc3-5206258e4718','偈二首  其二','釋道樞','宋','宋诗','song-poetry','','[]','雪裏梅花春信息，池中月色夜精神。',32,'全唐诗/poet.song.122000.json','["雪裏梅花春信息，池中月色夜精神。", "年來可是無佳趣，莫把家風舉似人。"]'),
('231cdb39-a670-45e6-a983-a14e7b8061b5','頌古三十九首  其一','釋道樞','宋','宋诗','song-poetry','','[]','犯重比丘清浄行，平等性中無損益。',32,'全唐诗/poet.song.122000.json','["犯重比丘清浄行，平等性中無損益。", "水裏不用覓魚蹤，天邊何處觀鳥跡。"]'),
('cc6aa00b-7b21-4563-94e1-de8958de681f','頌古三十九首  其二','釋道樞','宋','宋诗','song-poetry','','[]','後念起時前念滅，起滅之念何嘗別。',32,'全唐诗/poet.song.122000.json','["後念起時前念滅，起滅之念何嘗別。", "喚取機關木人問，從頭弄盡元無說。"]'),
('39587216-284a-45ae-bc7b-770a4839ca64','頌古三十九首  其三','釋道樞','宋','宋诗','song-poetry','','[]','口念木瓜醫脚氣，紙畫鍾馗驅鬼祟。',32,'全唐诗/poet.song.122000.json','["口念木瓜醫脚氣，紙畫鍾馗驅鬼祟。", "一生若解和羅槌，日日喫酒日日醉。"]'),
('02b3e279-e49b-43bb-84cd-f3484b562226','頌古三十九首  其四','釋道樞','宋','宋诗','song-poetry','','[]','鏡凹照人瘦，鏡凸照人肥。',24,'全唐诗/poet.song.122000.json','["鏡凹照人瘦，鏡凸照人肥。", "不如打破鏡，還我舊面皮。"]'),
('90dbff83-6b15-4027-9d05-a1ebe49d310c','頌古三十九首  其五','釋道樞','宋','宋诗','song-poetry','','[]','日應羣機必有方，未知何處覓南陽。',32,'全唐诗/poet.song.122000.json','["日應羣機必有方，未知何處覓南陽。", "自從失却猢孫後，橋上多時不作場。"]'),
('0d19142e-b14e-4b63-a936-78768103c773','頌古三十九首  其六','釋道樞','宋','宋诗','song-poetry','','[]','李下不得整冠，瓜田豈可納履。',28,'全唐诗/poet.song.122000.json','["李下不得整冠，瓜田豈可納履。", "行藏自要分明，免見傍人說你。"]'),
('d947abeb-f83d-415e-be86-01e83e99d1f6','頌古三十九首  其七','釋道樞','宋','宋诗','song-poetry','','[]','垂垂楊柳暗溪頭，不問東西却自由。',32,'全唐诗/poet.song.122000.json','["垂垂楊柳暗溪頭，不問東西却自由。", "幾度醉眠牛背上，數聲橫笛一輪秋。"]'),
('6187402e-68aa-4be4-9afa-9fb444168e19','頌古三十九首  其八','釋道樞','宋','宋诗','song-poetry','','[]','犀牛扇子有來由，幾度拈來幾度休。',32,'全唐诗/poet.song.122000.json','["犀牛扇子有來由，幾度拈來幾度休。", "荷葉亂傾珠的皪，一番雨過碧溪頭。"]'),
('b271659d-fe1d-4475-95a6-28a364b05133','頌古三十九首  其九','釋道樞','宋','宋诗','song-poetry','','[]','同行自古不相肯，峰頂老人何足論。',32,'全唐诗/poet.song.122000.json','["同行自古不相肯，峰頂老人何足論。", "山凹落盡桃花片，流水依前繞竹門。"]'),
('58679132-91db-49da-9746-b51ba0b33d13','頌古三十九首  其一○','釋道樞','宋','宋诗','song-poetry','','[]','筠管釀來應已熟，不辭醉裏帽欹斜。',32,'全唐诗/poet.song.122000.json','["筠管釀來應已熟，不辭醉裏帽欹斜。", "酴醾浪有幽香在，是酒元來不是花。"]'),
('47a3fe5f-1e6e-4350-95ac-dd2da1b389ad','頌古三十九首  其一一','釋道樞','宋','宋诗','song-poetry','','[]','昨夜月初明，柴門猶未閉。',24,'全唐诗/poet.song.122000.json','["昨夜月初明，柴門猶未閉。", "貓兒捉老鼠，引得狗兒吠。"]'),
('7b324d5f-cc7a-48c4-ba4d-359213d206e9','頌古三十九首  其一二','釋道樞','宋','宋诗','song-poetry','','[]','鐘鼓聲聲已喚齋，堂前作舞老公家。',32,'全唐诗/poet.song.122000.json','["鐘鼓聲聲已喚齋，堂前作舞老公家。", "雖然一鉢充饑困，不覺牙生滿口沙。"]'),
('dbe27719-652f-4d38-a790-023c5474a27d','頌古三十九首  其一三','釋道樞','宋','宋诗','song-poetry','','[]','二老機關誰共委，幞頭捋下髮髼鬆。',32,'全唐诗/poet.song.122000.json','["二老機關誰共委，幞頭捋下髮髼鬆。", "山深不記來時路，彷彿猿啼碧澗中。"]'),
('44a9cee8-e794-4ee2-bace-662b9616dbf6','頌古三十九首  其一四','釋道樞','宋','宋诗','song-poetry','','[]','口子喃喃略不休，把却笊籬做火遊。',32,'全唐诗/poet.song.122000.json','["口子喃喃略不休，把却笊籬做火遊。", "有箇女兒不肯嫁，他年定作老丫頭。"]'),
('c2230438-0d3b-4134-909d-8e71fa38b90e','頌古三十九首  其一五','釋道樞','宋','宋诗','song-poetry','','[]','一番雨過一番晴，蠶眼已開桑眼青。',32,'全唐诗/poet.song.122000.json','["一番雨過一番晴，蠶眼已開桑眼青。", "鵓鳩樹頭啼不已，百舌黄鸝相共鳴。"]'),
('b02eaad4-074a-4950-8c62-14b530a412dc','頌古三十九首  其一六','釋道樞','宋','宋诗','song-poetry','','[]','晷運推移事若何，絲來線去定譊訛。',32,'全唐诗/poet.song.122000.json','["晷運推移事若何，絲來線去定譊訛。", "織成蜀錦千般巧，不出當時一隻梭。"]'),
('01b39043-a54e-46eb-90c9-c016abc45895','頌古三十九首  其一七','釋道樞','宋','宋诗','song-poetry','','[]','莫怪相逢無信息，誰能長作置書郵。',32,'全唐诗/poet.song.122000.json','["莫怪相逢無信息，誰能長作置書郵。", "直饒說盡千般事，那箇心中得到頭。"]'),
('76d0660a-0f72-4814-a248-6be805b0d71c','頌古三十九首  其一八','釋道樞','宋','宋诗','song-poetry','','[]','有禪無師真可笑，大唐國裏何處討。',32,'全唐诗/poet.song.122000.json','["有禪無師真可笑，大唐國裏何處討。", "可憐多少路行人，噇却酒糟隨路倒。"]'),
('66f915d3-f57c-4a41-9f87-a896b0ada8a8','頌古三十九首  其一九','釋道樞','宋','宋诗','song-poetry','','[]','百千諸佛問來由，崔顥曾題黄鶴樓。',32,'全唐诗/poet.song.122000.json','["百千諸佛問來由，崔顥曾題黄鶴樓。", "雪後竹籬梅亂放，一枝臨水最風流。"]'),
('059d4a74-3d07-4b81-bd6d-3dc8116d351f','頌古三十九首  其二○','釋道樞','宋','宋诗','song-poetry','','[]','大悲菩薩千手眼，如人背手摸枕頭。',32,'全唐诗/poet.song.122000.json','["大悲菩薩千手眼，如人背手摸枕頭。", "猢孫跳出布袋口，不妨隨處逞風流。"]'),
('89b0aa22-e956-4a42-a004-f2352ae173dc','頌古三十九首  其二一','釋道樞','宋','宋诗','song-poetry','','[]','放出金毛師子，百獸不見蹤由。',28,'全唐诗/poet.song.122000.json','["放出金毛師子，百獸不見蹤由。", "要得爪牙全露，直須自把繩頭。"]'),
('faefeafe-0737-4c9a-b448-aaee10ff05fa','頌古三十九首  其二二','釋道樞','宋','宋诗','song-poetry','','[]','脫得驢頭載馬頭，東家西家卒未休。',34,'全唐诗/poet.song.122000.json','["脫得驢頭載馬頭，東家西家卒未休。", "問君還有幾多愁，恰似一江春水向東流。"]'),
('34f2b46b-1f1e-412c-8277-203beaa6bd24','頌古三十九首  其二三','釋道樞','宋','宋诗','song-poetry','','[]','風吹雨打節還枯，千尺龍蛇插太虛。',32,'全唐诗/poet.song.122000.json','["風吹雨打節還枯，千尺龍蛇插太虛。", "堪笑兒孫無伎倆，一生從此被搽糊。"]'),
('bc45a932-cd7c-43c1-ba48-70ac3fd76536','頌古三十九首  其二四','釋道樞','宋','宋诗','song-poetry','','[]','半斤是八兩，八兩是半斤。',24,'全唐诗/poet.song.122000.json','["半斤是八兩，八兩是半斤。", "不識耀州鐵，喚作出山銀。"]'),
('be27d678-7c00-4679-882d-9bed7753bdb2','頌古三十九首  其二五','釋道樞','宋','宋诗','song-poetry','','[]','朴寔頭禪無伎倆，一句分明如撲相。',32,'全唐诗/poet.song.122000.json','["朴寔頭禪無伎倆，一句分明如撲相。", "客來只是叫擔板，不知的當誰擔板。"]'),
('5e877388-2edd-4194-980a-63592d477e20','頌古三十九首  其二六','釋道樞','宋','宋诗','song-poetry','','[]','等閒一問垂千古，從此叢林共播揚。',32,'全唐诗/poet.song.122000.json','["等閒一問垂千古，從此叢林共播揚。", "堪笑睦州無相度，饆饠䭔子要先嘗。"]'),
('0414ea3e-229a-49dd-91d9-307581865bed','頌古三十九首  其二七','釋道樞','宋','宋诗','song-poetry','','[]','花萼樓前春正濃，濛濛柳絮舞晴空。',32,'全唐诗/poet.song.122000.json','["花萼樓前春正濃，濛濛柳絮舞晴空。", "金錢擲罷嬌無力，笑倚闌干屈曲中。"]'),
('f366f52b-d5d4-49f5-a07b-fa7f8ee27117','頌古三十九首  其二八','釋道樞','宋','宋诗','song-poetry','','[]','看人騎馬打毬子，不覺今朝入院遲。',32,'全唐诗/poet.song.122000.json','["看人騎馬打毬子，不覺今朝入院遲。", "官路雪殘春正好，江梅著意要題詩。"]'),
('23309f89-0897-4dc0-9bbd-437bf035a9da','頌古三十九首  其二九','釋道樞','宋','宋诗','song-poetry','','[]','旻德一喝如雷響，興化一喝響如雷。',32,'全唐诗/poet.song.122000.json','["旻德一喝如雷響，興化一喝響如雷。", "錦袍玉带真瀟灑，記得當年老萬回。"]'),
('dd918583-5f98-43f2-b46c-f6ee31d69b42','頌古三十九首  其三○','釋道樞','宋','宋诗','song-poetry','','[]','山寺裏頭無可作，輥出木毬兩三箇。',32,'全唐诗/poet.song.122000.json','["山寺裏頭無可作，輥出木毬兩三箇。", "不獨玄沙遭一攧，雪峰老人亦話墮。"]'),
('871fc5af-1c84-4a35-ac74-63bab0a305e0','頌古三十九首  其三一','釋道樞','宋','宋诗','song-poetry','','[]','十方世界一面鏡，鏡裏看形未足真。',32,'全唐诗/poet.song.122000.json','["十方世界一面鏡，鏡裏看形未足真。", "摸著鼻頭渠是我，那時方見本來人。"]'),
('857870f5-8a31-4a6d-b444-640b1a78b43a','頌古三十九首  其三二','釋道樞','宋','宋诗','song-poetry','','[]','大地是箇解脫門，三世諸佛一口吞。',32,'全唐诗/poet.song.122000.json','["大地是箇解脫門，三世諸佛一口吞。", "將爲雪峰有奇特，却來謾我好兒孫。"]'),
('90598c6c-f8c1-4046-a7b2-c56b05cd6052','頌古三十九首  其三三','釋道樞','宋','宋诗','song-poetry','','[]','父子相携入故園，篾頭時過短籬邊。',32,'全唐诗/poet.song.122000.json','["父子相携入故園，篾頭時過短籬邊。", "爛泥有刺無人見，踏著方知脚底穿。"]'),
('4240502d-8703-40f2-a063-57ea438dc589','頌古三十九首  其三四','釋道樞','宋','宋诗','song-poetry','','[]','清浄法身無可比，病後依前滴滴膿。',32,'全唐诗/poet.song.122000.json','["清浄法身無可比，病後依前滴滴膿。", "燕鴻叫斷秋光老，落葉飄來一樣紅。"]'),
('6ed81df3-322d-4000-8740-d6981b3c7b03','頌古三十九首  其三五','釋道樞','宋','宋诗','song-poetry','','[]','新年佛法答云有，小盡依前二十九。',32,'全唐诗/poet.song.122000.json','["新年佛法答云有，小盡依前二十九。", "玉麟掣斷黄金勒，却向雲中大哮吼。"]'),
('5fcd2680-8e14-46ea-b095-22a58482e6b0','頌古三十九首  其三六','釋道樞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','新年佛法答云無，會得依前在半途。',32,'全唐诗/poet.song.122000.json','["新年佛法答云無，會得依前在半途。", "誰把扁舟清夜笛，月明吹過洞庭湖。"]'),
('5f2124be-303b-4e19-98a8-be6e5b2c1ded','頌古三十九首  其三七','釋道樞','宋','宋诗','song-poetry','','[]','誰將畫角吹江城，一曲梅花隔岸聽。',32,'全唐诗/poet.song.122000.json','["誰將畫角吹江城，一曲梅花隔岸聽。", "宿酒乍醒金鴨泠，海棠枝上月猶明。"]'),
('d3794ffb-6fc8-4a22-afc4-e50de7e2542a','頌古三十九首  其三八','釋道樞','宋','宋诗','song-poetry','','[]','雲門是箇老闍黎，衲僧巴鼻幾時知。',32,'全唐诗/poet.song.122000.json','["雲門是箇老闍黎，衲僧巴鼻幾時知。", "拄杖從教不得動，春來未免倒抽枝。"]'),
('c39e5739-38f9-4c05-9b2d-c858c57677d6','頌古三十九首  其三九','釋道樞','宋','宋诗','song-poetry','','[]','舊歲新年作問端，同安從此放顢頇。',32,'全唐诗/poet.song.122000.json','["舊歲新年作問端，同安從此放顢頇。", "憑仗高樓莫吹笛，大家留取倚闌干。"]'),
('a0bfa198-c645-4e29-9a3b-1e28b6bf4d8f','偈','呂生','宋','宋诗','song-poetry','','[]','六十年來此地居，靈臺光耀勝冰壺。',32,'全唐诗/poet.song.122000.json','["六十年來此地居，靈臺光耀勝冰壺。", "一朝破屋遂傾倒，且喜家中事事無。"]'),
('f8357bca-628a-4148-9983-cbb0d6843a8b','青山辭','陳天麟','宋','宋诗','song-poetry','','[]','青山崔崔，白雲溶溶。',130,'全唐诗/poet.song.122000.json','["青山崔崔，白雲溶溶。", "我疑其中，仙人所宮。", "風馬雲輿，霓旌羽幢。", "游行太空，翩然相從。", "望而不見，使我心忡。", "我本金華，牧羊之童。", "口誦蕊笈，有聲如鐘。", "震撼巖壑，無礙不通。", "謫居下土，黄塵濛濛。", "五色之氣，布滿西東。", "秋高露清，陟彼危峰。", "呼吸元氣，精神內融。", "嘯傲萬物，後天而終。"]'),
('baf0d9b0-aeb6-411a-a3f0-f989df1d2bd2','青山道中','陳天麟','宋','宋诗','song-poetry','','[]','田舍雞升屋，山家犬應門。',48,'全唐诗/poet.song.122000.json','["田舍雞升屋，山家犬應門。", "馬行黄葉路，水遶夕陽村。", "老覺貧爲累，吾知道可尊。", "此行聊復爾，萬事信乾坤。"]'),
('0ceef557-5f99-42ff-acf7-e5f2f2b25937','舟中','陳天麟','宋','宋诗','song-poetry','','[]','湖闊帆風飽，山長眼力疲。',48,'全唐诗/poet.song.122000.json','["湖闊帆風飽，山長眼力疲。", "晚凉行進酒，秋色最宜詩。", "別意果作惡，虛名難療饑。", "此生無住著，投老欲何之。"]'),
('3bcab6ed-caca-496e-ab65-9169b0740110','用梁漕韻','陳天麟','宋','宋诗','song-poetry','','[]','千里岷峨外，三年漢漾西。',48,'全唐诗/poet.song.122000.json','["千里岷峨外，三年漢漾西。", "急流衝水馬，腐壤伏樗雞。", "伐樹驚遭宋，聞韶喜在齊。", "何時燈火夜，重與拆紅泥。"]'),
('91924214-4a0b-4dde-a294-d32d9869d9ea','上瀘帥梁公  其一','陳天麟','宋','宋诗','song-poetry','','[]','舊已元樞幕，今猶大將牙。',48,'全唐诗/poet.song.122000.json','["舊已元樞幕，今猶大將牙。", "恩威伸六詔，封域總三巴。", "早晚看鳴佩，軒翔入判花。", "不妨乘駟馬，上冢一還家。"]'),
('34ba6ff4-2c6c-428f-976d-93d023339640','上瀘帥梁公  其二','陳天麟','宋','宋诗','song-poetry','','[]','冊府推前輩，文場慣主盟。',48,'全唐诗/poet.song.122000.json','["冊府推前輩，文場慣主盟。", "冀閑收汗血，崑圃出連城。", "料想金甌覆，遥知水鑑明。", "從今青與紫，四海盡門生。"]'),
('5ba97917-cc9c-4001-a7de-0aef277d73bf','上瀘帥梁公  其三','陳天麟','宋','宋诗','song-poetry','','[]','六轡澄清日，三軍指顧中。',48,'全唐诗/poet.song.122000.json','["六轡澄清日，三軍指顧中。", "關山都識面，草木尚傾風。", "飲馬伊吾北，回鑾澗水東。", "廟謨應富有，傾倒莫匆匆。"]'),
('86f879aa-bc3d-41be-aea5-8844c06db797','旌德道中','陳天麟','宋','宋诗','song-poetry','','[]','山邑無郵傳，農夫半甲兵。',48,'全唐诗/poet.song.122000.json','["山邑無郵傳，農夫半甲兵。", "石橋橫斷岸，草徑入荒城。", "聞道甘泉駕，將臨細柳營。", "風塵何日靖，留眼看昇平。"]'),
('350dcd6a-92e4-41e1-948b-caa9e540fd97','壽洋川李守昌諤二首  其一','陳天麟','宋','宋诗','song-poetry','','[]','桂子風高瑞靄浮，曉來無處不懽謳。',64,'全唐诗/poet.song.122000.json','["桂子風高瑞靄浮，曉來無處不懽謳。", "共懷襦袴歌廉范，更指龜蒙祝魯侯。", "風月莫辜三十詠，星霜行閱八千秋。", "皇家正重惟良寄，衮服歸公正黑頭。"]'),
('348c7e5e-38c8-4e0d-b290-6f9fbacccfaa','壽洋川李守昌諤二首  其二','陳天麟','宋','宋诗','song-poetry','','[]','朱輪畫戟擁高牙，散作棠陰十萬家。',64,'全唐诗/poet.song.122000.json','["朱輪畫戟擁高牙，散作棠陰十萬家。", "漸向瑶階對紅藥，長傾玉斝壽黄花。", "僊風自是騎鯨客，逸興行飛犯斗槎。", "誰爲淮南門下客，願隨雞犬上雲霞。"]'),
('abc26adb-75a4-4ba7-9482-b9e27f89d532','用齊正韻送叔勤歸湖北','陳天麟','宋','宋诗','song-poetry','','[]','霜點螭坳侍紫皇，高文大冊玉鏘鏘。',64,'全唐诗/poet.song.122000.json','["霜點螭坳侍紫皇，高文大冊玉鏘鏘。", "傳家信有青袍物，當代爭推古戰場。", "故國未應窮地脈，難兄先已破天荒。", "相逢若話情親事，分我朝回滿袖香。"]'),
('b3a6394f-2b6b-4ac4-a058-2484db6c52ca','憶舊','陳天麟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖當日雨如絲，尚記移家去國時。',64,'全唐诗/poet.song.122000.json','["西湖當日雨如絲，尚記移家去國時。", "髮短自憐今種種，印懸那得更纍纍。", "身如烏鵲空三匝，家似鷦鷯寄一枝。", "萬事此心俱不計，尚容開口細論詩。"]'),
('4ce521b9-eddb-4c1b-8120-d715e32c55db','席上和統制傅公韻','陳天麟','宋','宋诗','song-poetry','','[]','遲遲春永晝如年，芳草池塘屬惠連。',64,'全唐诗/poet.song.122000.json','["遲遲春永晝如年，芳草池塘屬惠連。", "一笑誰云今易得，四并須信古難全。", "山圍錦繡將軍樹，雲遏笙歌刺史天。", "不向風光共流轉，恐辜柳絮與榆錢。"]'),
('6c209843-8e6a-4cb0-a966-7443dafe1af2','除夕偶成呈同舍兼簡陳仲恕','陳天麟','宋','宋诗','song-poetry','','[]','東皇送煖下青都，雪在梅梢半有無。',64,'全唐诗/poet.song.122000.json','["東皇送煖下青都，雪在梅梢半有無。", "爆竹舊聞驅罔象，傳杯今怕飲屠蘇。", "暗中石火頻過眼，忙裏銀絲欲上鬚。", "不解玉堂供帖子，雙扉聊與換桃符。"]'),
('bda88bc2-ec4c-4c03-bcd2-94bd5199cbf5','又次前韻','陳天麟','宋','宋诗','song-poetry','','[]','積陰元自宅幽都，昨夜東風一掃無。',64,'全唐诗/poet.song.122000.json','["積陰元自宅幽都，昨夜東風一掃無。", "玉殿仙班摇雜珮，銀罌御膳染香酥。", "柳縈翠带方眠眼，梅褪紅粧已露鬚。", "拭目太平知有日，兩宮勤儉過祥符。"]'),
('33f76bec-a448-4b61-a919-4898eed5b4a8','送太守李公','陳天麟','宋','宋诗','song-poetry','','[]','亂花翻陣雨，飛絮轉輕毬。',264,'全唐诗/poet.song.122000.json','["亂花翻陣雨，飛絮轉輕毬。", "別思昏如醉，征鞍挽不留。", "職循今列郡，秩視古諸侯。", "當代人爭仰，惟公政最優。", "洋川佳景物，勝跡舊經遊。", "未定中原擾，猶懷傍塞憂。", "九重爰錫命，千里藉承流。", "德逐祥雲偃，恩隨瑞靄浮。", "带刀還隴畝，挾纊動貔貅。", "烽柝開邊月，犂鋤慶麥秋。", "二天舒士氣，五袴沸民謳。", "虞氏三年考，河南第一州。", "霜臺方薦墨，黼座想凝旒。", "早晚頒綸綍，東西走置郵。", "遲遲姑去魯，几几定歸周。", "明月湖光遠，凌雲氣象幽。", "煙波浮畫鷁，雪浪遶烏牛。", "好逐桃花漲，輕飛竹葉舟。", "徑歸調玉鉉，莫待覆金甌。", "賤吏傷萍梗，終年仰庇休。", "龍門曾御李，驥坂會依劉。", "不作癡兒女，孜孜話別愁。"]'),
('1f31738b-dcf0-4850-8efe-a2a3a8de15d0','題南金慎獨齋','陳天麟','宋','宋诗','song-poetry','','[]','聖道不可窮，探取隨己欲。',156,'全唐诗/poet.song.122000.json','["聖道不可窮，探取隨己欲。", "平生所受用，政可一言足。", "子思著中庸，暗室戒慎獨。", "危微恐懼心，此念施已熟。", "學從西洛來，標榜相品目。", "袖手看屋梁，表表知鴻鵠。", "誰知胸中塵，往往盈斗斛。", "伋也而有知，寧不貽彼忸。", "吳侯蚤作吏，未肯事邊幅。", "得妙自聖處，了不關世俗。", "頗知幽隱中，日月所照燭。", "不敢欺秋毫，高情潔冰玉。", "願言從君遊，著鞭蹈前躅。"]'),
('1028feb9-acc4-4375-956d-8321a8e2c312','訪張元明山齋','陳天麟','宋','宋诗','song-poetry','','[]','張侯詩似嶺雲閑，飛鳥何心只念還。',64,'全唐诗/poet.song.122000.json','["張侯詩似嶺雲閑，飛鳥何心只念還。", "醉裏有官如物外，眼前無客似山間。", "來聽春枕連宵雨，看畫秋屏著色山。", "老去此身無處用，固應容我作躋攀。"]'),
('97012731-b9cd-48bd-8c99-9aeb2aba8365','題王季恭蓬齋','陳天麟','宋','宋诗','song-poetry','','[]','小結茅廬寄一椽，夜燈聊與客周旋。',64,'全唐诗/poet.song.122000.json','["小結茅廬寄一椽，夜燈聊與客周旋。", "問知急雨來何處，題作蓬齋亦偶然。", "政欲撩君江上句，莫嫌驚我醉中眠。", "老翁辜負漁竿久，何日烟簑止釣舡。"]'),
('7dcc267b-e825-4b44-b418-cc0950f74877','趙觀察作齋名煙艇孫耘老作唐律相邀同賦乃次其韻','陳天麟','宋','宋诗','song-poetry','','[]','知君心本在滄洲，故揭寒齋作釣舟。',64,'全唐诗/poet.song.122000.json','["知君心本在滄洲，故揭寒齋作釣舟。", "已遣江湖頻入夢，便呼鷗鳥與同遊。", "浮驂未可追前事，畫舫猶堪擬勝流。", "笠澤有家歸未得，斷腸蘆葉荻先秋。"]'),
('64dbfd0f-9b98-4336-976d-dd045b42c66a','越香臺','陳天麟','宋','宋诗','song-poetry','','[]','佳木寄深塢，自與春有期。',48,'全唐诗/poet.song.122000.json','["佳木寄深塢，自與春有期。", "幽姿誰復省，軒軒頗矜持。", "真賞儻已逢，清香襲人衣。", "士爲知己死，此語良不欺。"]'),
('af5caab3-bf48-4f26-9d88-bf901f4a75ff','與客飲乾明寺東古梅下','陳天麟','宋','宋诗','song-poetry','','[]','寥寥耆舊盡，欣欣花木新。',120,'全唐诗/poet.song.122000.json','["寥寥耆舊盡，欣欣花木新。", "十梅亦老矣，手植知何人。", "不種官路傍，社櫟同百春。", "想當太平時，來者紛蹄輪。", "我來幾世後，尋芳披棘榛。", "眾枝疊玉蕊，光風卷香塵。", "坐客稍稍醉，墜英欲成茵。", "老圃亦後來，始園從誰詢。", "淵明飲松下，故事良可遵。", "飲散棄花去，明日迹已陳。"]'),
('1fa97f7b-9a5c-4a95-bcc2-cfc58f378f80','呂仲及適安堂','陳天麟','宋','宋诗','song-poetry','','[]','事如昨夢本來空，正在黄粱一熟中。',64,'全唐诗/poet.song.122000.json','["事如昨夢本來空，正在黄粱一熟中。", "到處隨緣是安樂，人生何地有窮通。", "飛花不到東風舞，霜葉空憐醉面紅。", "只恐他年終未免，傳家重說小申公。"]'),
('9f1e81d7-d735-4503-b921-adf4674d4f57','柳下','陳天麟','宋','宋诗','song-poetry','','[]','春餘暑氣已駸駸，喚取胡床坐柳陰。',64,'全唐诗/poet.song.122000.json','["春餘暑氣已駸駸，喚取胡床坐柳陰。", "風裏禽聲來木杪，日斜樹影倒溪心。", "不知昨夜雨多少，幻出數峰雲淺深。", "老子此間殊不惡，爲收佳趣入微吟。"]'),
('a6a0559b-b176-4a00-a8be-9c841375bd40','田間','陳天麟','宋','宋诗','song-poetry','','[]','經營一飽慰枯腸，稻作黄雲带雨香。',64,'全唐诗/poet.song.122000.json','["經營一飽慰枯腸，稻作黄雲带雨香。", "溪上烟橫秋入畫，樹梢風細晚分凉。", "交游斷絕山當戶，歲月侵尋竹過牆。", "斗酒隻雞田舍好，枉將襏襫換軒裳。"]'),
('300c832a-16aa-432e-8d0c-a8d7e3ef5b1b','雨中發崇福院','陳天麟','宋','宋诗','song-poetry','','[]','僕奴頗厭穿雲路，老子方欣在眼山。',64,'全唐诗/poet.song.122000.json','["僕奴頗厭穿雲路，老子方欣在眼山。", "四面人家高下住，一川烟雨有無間。", "時聞鳥語作歌吹，更遣泉聲鳴珮環。", "沮洳崎嶇飽諳歷，只餘多病鬢毛斑。"]'),
('da23946e-409f-4899-85ab-47180ad401ac','偶作','陳天麟','宋','宋诗','song-poetry','','[]','蹇步青雲晚，疏慵白髮多。',48,'全唐诗/poet.song.122000.json','["蹇步青雲晚，疏慵白髮多。", "生涯聊爾耳，功業定如何。", "坐與此君語，誰携歡伯過。", "向來湖海氣，老矣付烟波。"]'),
('44ccf67c-ee39-4c36-b9c1-884b1f2df287','紀頌','陳天麟','宋','宋诗','song-poetry','','[]','宅家圖任久虛懷，鎮撫三年輟弼諧。',64,'全唐诗/poet.song.122000.json','["宅家圖任久虛懷，鎮撫三年輟弼諧。", "鵷鷺傾心望歸洛，貔貅賈勇待平淮。", "已擎天柱旋坤軸，會正杓衡拱泰階。", "多少中興勳業事，未知誰□頌磨崖。"]'),
('048a5948-dc55-48d8-83b7-cd7b9a1ddcaf','揚州瓊花','陳天麟','宋','宋诗','song-poetry','','[]','髣髴猶稱是漢粧，五花刻玉傳輕黄。',64,'全唐诗/poet.song.122000.json','["髣髴猶稱是漢粧，五花刻玉傳輕黄。", "隔江坐想紅樓裏，插鬢應宜錦瑟傍。", "疑似聚仙非我類，近鄰芍藥許同芳。", "將軍且與花爲主，免使叢祠作戰場。"]'),
('c05e29f9-66f0-49d6-ae5a-d2909df7cf73','後林寺','陳天麟','宋','宋诗','song-poetry','','[]','凉颸發遠軔，殘暑促歸輪。',48,'全唐诗/poet.song.122000.json','["凉颸發遠軔，殘暑促歸輪。", "山色不厭客，蟬聲强聒人。", "功名塵外累，身世醉中真。", "更上高樓望，何峰可卜鄰。"]'),
('058ee968-80ce-45d4-a1bd-a06d9014978a','延壽寺','陳天麟','宋','宋诗','song-poetry','','[]','一溪寒玉佩環聲，兩徑徘徊管送迎。',32,'全唐诗/poet.song.122000.json','["一溪寒玉佩環聲，兩徑徘徊管送迎。", "寺學鷲峰侵漢起，山如龍尾撇波行。"]'),
('895e2843-bf92-4481-b196-96835159e273','秋霜閣','陳天麟','宋','宋诗','song-poetry','','[]','登臺坐想遺民釣，入寺行歌李白詩。',64,'全唐诗/poet.song.122000.json','["登臺坐想遺民釣，入寺行歌李白詩。", "竹榻蒲團僧定早，清鞋布襪我歸遲。", "雲邊掃石留題處，月下憑欄把酒時。", "百尺蒼松唐舊物，問渠嘗閱幾興衰。"]'),
('2d9c82e1-ea2a-45f7-af40-980789c340fa','風光閣','陳天麟','宋','宋诗','song-poetry','','[]','三千里外帝王鄉，當日龍潜涇水旁。',64,'全唐诗/poet.song.122000.json','["三千里外帝王鄉，當日龍潜涇水旁。", "不擬璽符歸掌握，故因斧藻話風光。", "一時事往留遺迹，百尺樓空倚夕陽。", "英武照靈略相似，元無野史記興唐。"]'),
('47a2c0f8-0493-4edb-aaed-40605e465bc3','呂城舟行晚晴','陳天麟','宋','宋诗','song-poetry','','[]','楊柳堤長月一灣，芙蓉花小蓼初斑。',64,'全唐诗/poet.song.122000.json','["楊柳堤長月一灣，芙蓉花小蓼初斑。", "孤帆白鳥無邊水，殘日斷雲何處山。", "遠客自應歸興動，新詩都在晚晴間。", "功名有底催人去，只合漁樵作往還。"]'),
('0f2efef7-23b8-46a1-be69-547283ea72b7','登上嶺遊黄山  其一','陳天麟','宋','宋诗','song-poetry','','[]','朝陽滉漾水朦朧，曉烟橫抹天微風。',128,'全唐诗/poet.song.122000.json','["朝陽滉漾水朦朧，曉烟橫抹天微風。", "三十六峰不著色，點綴淡墨排秋空。", "小山連延大山倨，林深無人但雲樹。", "平生愛山真成癖，我以意行本無住。", "黄山之路何欹危，黄山之溪何漣漪。", "登山度水亦勞止，正要行役發吾詩。", "仙家與世不相遠，徑入桃源亦良便。", "向來父老亦嘗行，竹籜桃花大於扇。"]'),
('d0756eba-fe5e-4d12-8b5e-9220a277c9b3','登上嶺遊黄山  其二','陳天麟','宋','宋诗','song-poetry','','[]','風掃烟嵐一萬重，平生佳處始相逢。',64,'全唐诗/poet.song.122000.json','["風掃烟嵐一萬重，平生佳處始相逢。", "未驂軒后浮丘駕，已見天都石柱峰。", "閬苑欲傳青鳥信，壺天安用白雲封。", "朝真我亦通仙籍，况復年來訪赤松。"]'),
('9c77eef2-341e-420e-a943-db4046955a25','過雙梅草堂','陳天麟','宋','宋诗','song-poetry','','[]','一識園林勝，知君有遠心。',48,'全唐诗/poet.song.122000.json','["一識園林勝，知君有遠心。", "看林延野色，卧日只空林。", "山水閑中領，詩書靜處深。", "秋光度林際，留得半庭陰。"]'),
('35eb7ab1-a793-4b9c-8e9d-2603452777d2','贈水西寺舉老','陳天麟','宋','宋诗','song-poetry','','[]','山前流水化平陸，溪上羣山疊寒玉。',126,'全唐诗/poet.song.122000.json','["山前流水化平陸，溪上羣山疊寒玉。", "寺逢劫火一再遷，唯有浮圖立於獨。", "江南佛法多衰謝，主張名教一夔足。", "詩人江西派，更是真如舊尊宿。", "我生遍參未究竟，布襪青鞋走林谷。", "師言子歸有余師，留飯青精盤苜蓿。", "杖藜並語松林路，行聽松聲如度曲。", "尚寒三十六峰盟，遊罷同回把黄菊。"]'),
('3bc1ca9b-effb-4a6c-b97a-8a15483945dd','遊巖豅寺','陳天麟','宋','宋诗','song-poetry','','[]','山疑夢裏槐安國，僧住壺公小隱天。',64,'全唐诗/poet.song.122000.json','["山疑夢裏槐安國，僧住壺公小隱天。", "門橫一水與世隔，不知魚鼓今幾年。", "真人陰崖結茅屋，大千世界一粒粟。", "佛言芥子納須彌，我亦來尋贊公宿。"]'),
('ada067be-ac8f-49d9-8f6e-8d47f476f0ca','妙相寺風雨亭','陳天麟','宋','宋诗','song-poetry','','[]','夜聞騷屑此君語，晨起急登風雨亭。',32,'全唐诗/poet.song.122000.json','["夜聞騷屑此君語，晨起急登風雨亭。", "一笑相逢珍重別，不隨人改舊時青。"]'),
('c0a584f5-5799-4382-b839-2f3cbd8621ab','石壁道中','陳天麟','宋','宋诗','song-poetry','','[]','雲山疊疊石齒齒，山色溪聲三十里。',64,'全唐诗/poet.song.122000.json','["雲山疊疊石齒齒，山色溪聲三十里。", "霜餘木葉半丹青，道上松風雜宮徵。", "捨車而徒度險艱，邇來趼足愁躋攀。", "官閑無祿與王事，不妨拄杖對潺湲。"]'),
('be836069-2361-426c-b765-cf90493e6f06','勝因寺','陳天麟','宋','宋诗','song-poetry','','[]','山行詰曲到禪林，臺殿丹青歲月深。',64,'全唐诗/poet.song.122000.json','["山行詰曲到禪林，臺殿丹青歲月深。", "薄晚春寒生几席，逼人空翠撲衣襟。", "客塵冉冉凌清思，俗狀紛紛費苦吟。", "若得一丘容我老，便携藜杖事幽尋。"]'),
('d4ad7267-91a5-4966-a06f-34eb1e3ba7f8','深塢寺','陳天麟','宋','宋诗','song-poetry','','[]','古寺深深陰，籃輿得得來。',48,'全唐诗/poet.song.122000.json','["古寺深深陰，籃輿得得來。", "三休登隴首，百轉入巖隈。", "喬木千章老，鳴泉萬石哀。", "無人同此趣，獨爲少徘徊。"]'),
('1b8a33f9-8b55-44d3-97e8-44e06c1cb0a9','福田寺','陳天麟','宋','宋诗','song-poetry','','[]','逵市前朝寺，何年古佛廬。',48,'全唐诗/poet.song.122000.json','["逵市前朝寺，何年古佛廬。", "上方分勝業，小筑寄幽居。", "坡隴青相接，川原綠自如。", "欹眠聽秋雨，懷抱稍虛徐。"]'),
('8e9b17e4-37ca-4a6e-afdd-6a85be48313b','茅殿寺','陳天麟','宋','宋诗','song-poetry','','[]','伊昔高人隱，誅茅此殿陰。',48,'全唐诗/poet.song.122000.json','["伊昔高人隱，誅茅此殿陰。", "丹青妙輪奐，香火閟幽深。", "朝市有遷換，溪山無古今。", "蕭齋午睡覺，欹枕一長吟。"]'),
('32b9e5e5-f40c-4d6e-8fd9-70faf8aeae0a','句  其一','陳天麟','宋','宋诗','song-poetry','','[]','笋槊秧斜入圖畫，令人魂夢到家山。',16,'全唐诗/poet.song.122000.json','["笋槊秧斜入圖畫，令人魂夢到家山。"]'),
('565648e0-0eb4-48ad-bd8e-0cbcbf855107','句  其二','陳天麟','宋','宋诗','song-poetry','','[]','白雲樓荒危堞在，莫愁村近暮烟橫。',16,'全唐诗/poet.song.122000.json','["白雲樓荒危堞在，莫愁村近暮烟橫。"]'),
('c05b0c1f-a94d-48ad-ab50-baa2ed83e05c','句  其三','陳天麟','宋','宋诗','song-poetry','','[]','紫芝秀出何年日，碧藕開成幾丈花。',16,'全唐诗/poet.song.122000.json','["紫芝秀出何年日，碧藕開成幾丈花。"]'),
('8da01b6e-ed11-451e-ab66-51bba1ba7b6c','九日泛舟同朱元晦','傅自得','宋','宋诗','song-poetry','','[]','秋月天然白，溪流鏡樣平。',48,'全唐诗/poet.song.122000.json','["秋月天然白，溪流鏡樣平。", "喚船同勝賞，把盞話平生。", "擊楫魚頻躍，忘機鳥尚驚。", "茲遊還可繼，家釀爲君傾。"]'),
('cc00093e-c727-42bb-a773-1c9d5f0e23a5','題濠上齋二絕  其一','傅自修','宋','宋诗','song-poetry','','[]','焉知魚樂我非魚，夢裏榮枯覺則無。',32,'全唐诗/poet.song.122000.json','["焉知魚樂我非魚，夢裏榮枯覺則無。", "休學癡蠅貪紙穴，小窗烘日謾跏趺。"]'),
('0ae28bc1-4cbb-44de-a1ee-7ac58d302e45','題濠上齋二絕  其二','傅自修','宋','宋诗','song-poetry','','[]','小齋斗大四壁立，只著匡牀與瓦爐。',32,'全唐诗/poet.song.122000.json','["小齋斗大四壁立，只著匡牀與瓦爐。", "不涉語言君識否，莫從門外著工夫。"]'),
('4f39ce34-fcff-4f3f-a784-a3d654d0706d','偶成  其一','傅自修','宋','宋诗','song-poetry','','[]','疊翠亭前秋水深，思韓亭下木成林。',32,'全唐诗/poet.song.122000.json','["疊翠亭前秋水深，思韓亭下木成林。", "一生不得文章力，且向潮陽度歲陰。"]'),
('6215e753-e11d-4cf2-98fd-aefeb77c0222','偶成  其二','傅自修','宋','宋诗','song-poetry','','[]','訟牒無多公事希，道心已熟壯心微。',32,'全唐诗/poet.song.122000.json','["訟牒無多公事希，道心已熟壯心微。", "晚來吏散閑携杖，步到金山趁月歸。"]'),
('1d93834a-f250-4781-adb5-ad557db0dbdd','再題濠上齋','傅自修','宋','宋诗','song-poetry','','[]','外物爲藩籬，障此道之徑。',48,'全唐诗/poet.song.122000.json','["外物爲藩籬，障此道之徑。", "昧則終日迷，達者默爾靜。", "子夏出入間，悅樂猶異境。", "誰能入吾鄉，節令四時正。"]'),
('8487b7ce-9e66-4034-a6ff-47ca9918acd3','呈東林道顔禪師頌','釋彥充','宋','宋诗','song-poetry','','[]','爲人須爲徹，殺人不見血。',24,'全唐诗/poet.song.122000.json','["爲人須爲徹，殺人不見血。", "德山與巖頭，萬里一條鐵。"]'),
('5ee6c296-5184-42d9-a8cf-f516ac604ce5','偈','釋彥充','宋','宋诗','song-poetry','','[]','世尊不說說，迦葉不聞聞。',28,'全唐诗/poet.song.122000.json','["世尊不說說，迦葉不聞聞。", "水流黄葉來何處，牛带寒鴉過遠村。"]'),
('d71eee05-3b4e-4711-a3bf-84f7a4e8fe1f','偈二首  其一','安分庵主','宋','宋诗','song-poetry','','[]','幾年箇事掛胸懷，問盡諸方眼不開。',32,'全唐诗/poet.song.122000.json','["幾年箇事掛胸懷，問盡諸方眼不開。", "肝膽此時俱裂破，一聲江上侍郎來。"]'),
('5b794f03-552c-4493-9c94-a9be39a21920','偈二首  其二','安分庵主','宋','宋诗','song-poetry','','[]','十五日已前，天上有星皆拱北。',44,'全唐诗/poet.song.122000.json','["十五日已前，天上有星皆拱北。", "十五日已後，人間無水不朝東。", "已前已後總拈却，到處鄉談各不同。"]'),
('90498c9f-b865-4bc5-9c1a-c1020425b6a1','偈三首  其一','釋子涓','宋','宋诗','song-poetry','','[]','一二三四五六七，七六五四三二一。',62,'全唐诗/poet.song.122000.json','["一二三四五六七，七六五四三二一。", "循環逆順數將來，數到未來無盡日。", "因七見一，見一亡七。", "踏破太虛空，鐵牛也汗出。", "絕氣息，無蹤跡。"]'),
('699bd447-a263-4ea4-b901-73ca56486c8b','偈三首  其二','釋子涓','宋','宋诗','song-poetry','','[]','見見之時，見非是見。',32,'全唐诗/poet.song.122000.json','["見見之時，見非是見。", "見猶離見，見不能及。", "鯨吞海水盡，露出珊瑚枝。"]'),
('91d05b62-203d-462f-8f14-8b20f28b04b7','偈三首  其三','釋子涓','宋','宋诗','song-poetry','','[]','伴我行千里，携君過萬山。',24,'全唐诗/poet.song.122000.json','["伴我行千里，携君過萬山。", "未明心地印，難透祖師關。"]'),
('e560f835-d9ee-4fa5-a074-a2fe06a53594','頌古二首  其一','釋子涓','宋','宋诗','song-poetry','','[]','狗子佛性無，門上釘桃符。',24,'全唐诗/poet.song.122000.json','["狗子佛性無，門上釘桃符。", "邪魔并百怪，一見便消除。"]'),
('0a815600-2fec-41de-b4a4-ca0005bde3f5','頌古二首  其二','釋子涓','宋','宋诗','song-poetry','','[]','乍雨乍晴山裏寺，或來或去洞中雲。',32,'全唐诗/poet.song.122000.json','["乍雨乍晴山裏寺，或來或去洞中雲。", "滿天星月明如晝，此境此時誰欲分。"]'),
('fe841f6f-f373-4646-814b-432f3c040af7','郭將軍廟','陳份','宋','宋诗','song-poetry','','[]','天欲亡佗開漢境，將軍英武契風雲。',64,'全唐诗/poet.song.122000.json','["天欲亡佗開漢境，將軍英武契風雲。", "遠驅函谷三千騎，南下番禺十萬兵。", "自此河山消壘拒，至今民俗荷庸勳。", "後來扼腕征蠻者，祿重功輕不似君。"]'),
('4cdd274d-c594-47ed-b849-91d0135db422','不欺堂','蘇邦','宋','宋诗','song-poetry','','[]','室明室暗兩相宜，方寸長存不可欺。',32,'全唐诗/poet.song.122000.json','["室明室暗兩相宜，方寸長存不可欺。", "勿謂天高鬼神遠，要須常畏自家知。"]'),
('9d0c4b9d-68ef-4e47-83a7-e5e3ee7f9a1a','奉繼馮使君韻  其一','夏世雄','宋','宋诗','song-poetry','','[]','恭覽新詩清徹骨，揮毫落處耀名山。',64,'全唐诗/poet.song.122000.json','["恭覽新詩清徹骨，揮毫落處耀名山。", "寒蹤久已知恩地，杖屨今朝得喜攀。", "翳雨堙風遮遠目，等閑軒豁爲誰開。", "天公豈是藏幽景，留待使君持節來。"]'),
('1e70893e-a806-4254-a193-6dfaa93fc7a9','奉繼馮使君韻  其二','夏世雄','宋','宋诗','song-poetry','','[]','神物堅持多聖境，新詩開僻信賢能。',32,'全唐诗/poet.song.122000.json','["神物堅持多聖境，新詩開僻信賢能。", "磨崖永作山中景，讀處留行亦好憎。"]'),
('0928d43d-35c1-4940-b47f-2b99dece3a06','贈蕭韡','陳嶠','宋','宋诗','song-poetry','','[]','一寸功名心已灰，翩然解組賦歸來。',32,'全唐诗/poet.song.122000.json','["一寸功名心已灰，翩然解組賦歸來。", "中興天子登耆舊，二十餘年挽不回。"]'),
('1312e236-e8d4-4678-80e2-8fd49b7424df','句','陳熊','宋','宋诗','song-poetry','','[]','水落舟橫露淺沙，粉垣松桂古禪家。',16,'全唐诗/poet.song.122000.json','["水落舟橫露淺沙，粉垣松桂古禪家。"]'),
('8a068e09-f766-45cf-8eb6-187d364d294e','黄陵題詠  其一','周炎','宋','宋诗','song-poetry','','[]','卧隨流水下煙汀，暫泊扁舟謁廟靈。',64,'全唐诗/poet.song.122000.json','["卧隨流水下煙汀，暫泊扁舟謁廟靈。", "古屋淒凉庭不掃，斷碑漫滅戶空扃。", "林藏宿鳥春聲好，潭躍金鱗夜氣腥。", "簫鼓送神人去後，滿江莎草自青青。"]'),
('b45af693-c24a-4859-afcb-87a0158d7e5f','黄陵題詠  其二','周炎','宋','宋诗','song-poetry','','[]','鶴駕雲軿去不迴，空遺廟貌古山隈。',32,'全唐诗/poet.song.122000.json','["鶴駕雲軿去不迴，空遺廟貌古山隈。", "鐵心石骨昌黎伯，也向黄陵擲珓杯。"]'),
('1705796f-dcb4-438f-8a89-a32077a6f17c','玉泉','黄朴','宋','宋诗','song-poetry','','[]','水性能方圓，泉色常珪璧。',48,'全唐诗/poet.song.122000.json','["水性能方圓，泉色常珪璧。", "雲山靜有輝，瓊液來無迹。", "泉上修禪人，曹溪分一滴。", "鑑止更澄源，紛紛萬緣息。"]'),
('9bcc9ee0-a372-47d3-bcb1-4edca2105197','茶嶺','陳中孚','宋','宋诗','song-poetry','','[]','天柱峰頭撥曉雲，靈芽一寸得先春。',32,'全唐诗/poet.song.122000.json','["天柱峰頭撥曉雲，靈芽一寸得先春。", "紫芹綠筍方知貴，雷發鎗旗未足珍。"]'),
('19545d30-1c14-4e5b-bba9-909cea334e17','崇仁縣後白蓮花','韓曉','宋','宋诗','song-poetry','','[]','東皇發生無賢愚，祝融長養無枯偏。',256,'全唐诗/poet.song.122000.json','["東皇發生無賢愚，祝融長養無枯偏。", "一般薰風同芊芊，何獨芙蕖多靚妍。", "小荷出水浮青烟，沈郎拋下買春錢。", "相看高柄綠又圓，誰家紺幰馳長川。", "美人酡顔立幰邊，疑是水府集諸仙。", "嚴粧一一皆青鈿，凌波羅襪行蹁躚。", "望中娟麗未足憐，別有一種尤天然。", "珍珠簾捲水晶軿，不在鉛華施紫綿。", "冰肌玉骨妙無前，恍若廣寒墜嬋娟。", "層臺細蕊黄最鮮，儼然玉女侍堯天。", "揚州盤盂休獨傳，拱手宜推先著鞭。", "雖云紅紫難差肩，未必時人眼所便。", "一杯勸花且盤旋，慰我天涯塵土緣。", "回首水鄉興益堅，鑑湖十里花相連。", "無端名利苦縈牽，簿書叢裏將三年。", "何當歸去守一廛，月明重上採蓮船。"]'),
('46c9549e-c73e-4350-ba90-edb2fe61352f','莞爾堂夏日偶成','向滈','宋','宋诗','song-poetry','','[]','槐蔭參差日轉廊，時看野鳥下橫塘。',64,'全唐诗/poet.song.122000.json','["槐蔭參差日轉廊，時看野鳥下橫塘。", "閑窗綠映篔簹浄，流水紅浮菡萏香。", "座有琴觴真道院，徑通花木似禪房。", "文楸珍簟疏簾裏，與子同消夏日長。"]'),
('d908d25f-3add-440f-b463-74db99754a6c','莞爾堂春晚書懷呈同僚','向滈','宋','宋诗','song-poetry','','[]','三分春色二分休，是處紅稀綠已稠。',64,'全唐诗/poet.song.122000.json','["三分春色二分休，是處紅稀綠已稠。", "芳草池塘空有思，落花亭館不勝愁。", "人情似昔猶難合，身世如今豈易謀。", "若欲忘憂須是酒，醉鄉安穩勝封侯。"]'),
('71114f1f-7321-4389-bf57-09ea03dacaae','莞爾堂和柳樞密韻','向滈','宋','宋诗','song-poetry','','[]','平生麋鹿性，從仕匪所娛。',192,'全唐诗/poet.song.122000.json','["平生麋鹿性，從仕匪所娛。", "要非折腰具，悠然慕潜夫。", "賦歸恨不蚤，空悲歲云徂。", "世情固險薄，官路徒驚呼。", "君看得失際，豈問戚與疏。", "論心未必爾，反眼何所無。", "嗟我與世忤，正坐所見殊。", "强顔戀五斗，我豈不足與。", "湖南有良田，亦有宅一區。", "會當拂衣去，俯仰聊自如。", "誰能揖上官，迫促畏簡書。", "遂令湖海上，坐覺豪氣除。", "君言浪見許，眾口方罵予。", "不學望塵輩，甘心履危途。", "所得俱可恥，山巖等豪銖。", "古人惟事道，吾行端不迂。"]'),
('54032e1d-a92b-4945-8da0-8d02f9f30f25','二月四日約同寮勸耕萬安院已而不至書於彭氏酒家壁','向滈','宋','宋诗','song-poetry','','[]','滿目風光二月時，小桃無數柳依依。',64,'全唐诗/poet.song.122000.json','["滿目風光二月時，小桃無數柳依依。", "松間野寺臨清淺，花底旗亭倚翠微。", "人意不隨春意好，此心端與賞心違。", "目斜望斷高陽侶，贏得惺惺騎馬歸。"]'),
('e0716acc-6606-43e4-8b08-6b201e713edc','句','向滈','宋','宋诗','song-poetry','','[]','人情甚似吳江冷，世路真如蜀道難。',16,'全唐诗/poet.song.122000.json','["人情甚似吳江冷，世路真如蜀道難。"]'),
('776f06c6-4bef-4788-a956-b667ae3633ce','烏君山','江逌','宋','宋诗','song-poetry','','[]','洞中烟鎖五雲樓，洞口寒泉今古流。',32,'全唐诗/poet.song.122000.json','["洞中烟鎖五雲樓，洞口寒泉今古流。", "見說秋高風雨夜，徐郎騎鶴更來遊。"]'),
('a34896f7-0c6c-4cfc-84dd-fe32e8c050c3','仙都山','丁宣','宋','宋诗','song-poetry','','[]','世上洞天三十六，縉雲第二十九區。',288,'全唐诗/poet.song.122000.json','["世上洞天三十六，縉雲第二十九區。", "古木參天架雲屋，總真靈迹號仙都。", "獨峰壁立二千尺，凌空聳翠屹然孤。", "仰瞻絕頂烟嵐際，曾開菡萏名鼎湖。", "舊說軒轅駐車轍，雲駢風馭經此塗。", "石釜鍊竈丹砂就，乘龍帝鄉纔須臾。", "紫虛碧落超塵世，侍臣無路攀龍鬚。", "唐朝天子仙李裔，德格天心來瑞符。", "祥煙嘉氣卿雲布，山中九傳萬歲呼。", "步虛對峙雲斷續，東西互雲高下殊。", "澗邊幽徑登鳥道，上有鏡巖如方壺。", "巖中乳水瀝嵌罅，滴石成穴如仰盂。", "水一晝夜斛加半，潦不泛溢旱不枯。", "魯望曾記周景復，絕粒餐霞黄老徒。", "棲真妙入懸珠會，八十餘年隱此居。", "千古寥寥桑海變，仙跡渺邈還有無。", "石門瀑布雖云好，此間殊勝未易俱。", "特然造化鍾神秀，虎頭妙手亦難圖。"]'),
('20b34d7b-ce2c-4975-95ed-b1ae1050d2f5','到官郡□之餘即新眾樂亭爲州人游觀之所因成拙句','方希覺','宋','宋诗','song-poetry','','[]','重尋佳景冠南州，天與邦人作勝游。',64,'全唐诗/poet.song.122000.json','["重尋佳景冠南州，天與邦人作勝游。", "百尺臺成偏得月，四時花放不知秋。", "當軒疊嶂高還下，傍檻長溪咽復流。", "只道使君能共樂，有誰能會使君憂。"]'),
('3cb91840-b49a-43d0-9471-c24da3e20ecb','及瓜將行留別南山','方希覺','宋','宋诗','song-poetry','','[]','南山陳迹徧搜尋，好景森羅直萬金。',32,'全唐诗/poet.song.122000.json','["南山陳迹徧搜尋，好景森羅直萬金。", "別後不知誰念我，經營偏費主人心。"]'),
('9ee87db9-cba9-47a6-bbdc-971cea6692a3','句  其一','張鎰','宋','宋诗','song-poetry','','[]','山中宰相晉遺民，下視雄特何僕臣。',16,'全唐诗/poet.song.122000.json','["山中宰相晉遺民，下視雄特何僕臣。"]'),
('d1451919-5db1-4f7d-b15f-3068a754aad4','句  其二','張鎰','宋','宋诗','song-poetry','','[]','老龍拏空欲輕舉，山靈地衹挽之住。',16,'全唐诗/poet.song.122000.json','["老龍拏空欲輕舉，山靈地衹挽之住。"]'),
('61f577d3-7738-488d-8028-94280866853f','西軒賞芍藥  其一','羅原知','宋','宋诗','song-poetry','','[]','絳羅高捲隔屏幃，一見令人思欲飛。',32,'全唐诗/poet.song.122000.json','["絳羅高捲隔屏幃，一見令人思欲飛。", "若使風前能解語，何人開口說楊妃。"]'),
('78d7d005-72c9-45de-9671-2dcecd072d96','西軒賞芍藥  其二','羅原知','宋','宋诗','song-poetry','','[]','不用胭脂涴玉姿，精神偏在月明時。',32,'全唐诗/poet.song.122000.json','["不用胭脂涴玉姿，精神偏在月明時。", "憑將一盞澆妝酒，博得花陰無限詩。"]'),
('13cda2cf-c57c-4788-8106-34559feaef92','三韻雜詠七首  其一','李若川','宋','宋诗','song-poetry','','[]','礎潤濕欲雨，月暈知有風。',36,'全唐诗/poet.song.122000.json','["礎潤濕欲雨，月暈知有風。", "大哉天地理，機熟潜可通。", "念彼在世人，心隱無由窮。"]'),
('12fe36fc-b39f-4479-952b-6ea03bf95887','三韻雜詠七首  其二','李若川','宋','宋诗','song-poetry','','[]','斯人異好惡，是非汩真情。',36,'全唐诗/poet.song.122000.json','["斯人異好惡，是非汩真情。", "鵝有翅莫飛，蛇無足能行。", "世事亦如此，未可一概評。"]'),
('fce78538-c1bf-47b9-b05d-c373534ebc92','三韻雜詠七首  其三','李若川','宋','宋诗','song-poetry','','[]','足隨意以行，目惟心所視。',36,'全唐诗/poet.song.122000.json','["足隨意以行，目惟心所視。", "若必待使之，動行即相戾。", "是故造自然，斯爲理之至。"]'),
('dc9114fc-029c-426e-a67d-ec3107499fb4','三韻雜詠七首  其四','李若川','宋','宋诗','song-poetry','','[]','鷺白固匪珍，鴉黑亦非貴。',36,'全唐诗/poet.song.122000.json','["鷺白固匪珍，鴉黑亦非貴。", "使其色相反，人皆競稱瑞。", "世情惟尚奇，在理則爲蔽。"]'),
('2017eb5e-ca99-4620-b77b-0dc3b59045ba','三韻雜詠七首  其五','李若川','宋','宋诗','song-poetry','','[]','足安咫尺地，臨險生憂危。',36,'全唐诗/poet.song.122000.json','["足安咫尺地，臨險生憂危。", "世故日紛擾，逐物心難持。", "心定境亦定，禍福安能移。"]'),
('0928698f-f7f7-48bf-a866-80107654e1af','三韻雜詠七首  其六','李若川','宋','宋诗','song-poetry','','[]','一氣有清濁，二儀成覆載。',36,'全唐诗/poet.song.122000.json','["一氣有清濁，二儀成覆載。", "魚鳥各飛潜，草木異榮敗。", "不齊乃至齊，造化所以大。"]'),
('10ed295d-bfa5-4605-aeec-9e32d021c733','三韻雜詠七首  其七','李若川','宋','宋诗','song-poetry','','[]','瞽者不視色，聾者不聽聲。',36,'全唐诗/poet.song.122000.json','["瞽者不視色，聾者不聽聲。", "觀其動作間，視聽由心生。", "一心苟有蔽，耳目絕聰明。"]'),
('dae8e295-909a-4964-88c6-4efd6ac9a969','途中阻雨','李若川','宋','宋诗','song-poetry','','[]','高雲無急雨，飛灑如絲輕。',72,'全唐诗/poet.song.122000.json','["高雲無急雨，飛灑如絲輕。", "幽人動羈思，冒雨登歸程。", "風來曉煙亂，雲破春山明。", "眷言憩荒館，我懷有餘情。", "壺中載濁酒，飲罷還自傾。", "酒盡興不盡，關關山鳥鳴。"]'),
('2712a88a-1c24-40a5-892f-62b7dae6bebb','夜泊富陽','李若川','宋','宋诗','song-poetry','','[]','弭節富春岸，江潮侵夜生。',84,'全唐诗/poet.song.122000.json','["弭節富春岸，江潮侵夜生。", "扁舟人未寐，風動菰蒲聲。", "羣物漸以息，客懷有餘清。", "開篷坐深夜，月在雲間明。", "遠眺江水闊，仰視天河橫。", "念此復何極，曠然千古情。", "恨阻心中侶，濁醪相與傾。"]'),
('5d2316a7-876b-459f-8e1b-0aac29aa686e','理舟','李若川','宋','宋诗','song-poetry','','[]','爲客始逾月，迢迢若經年。',72,'全唐诗/poet.song.122000.json','["爲客始逾月，迢迢若經年。", "晝永空館寂，古木參雲煙。", "我生聞道淺，未能超世緣。", "念此方寸地，憂來相縈纏。", "今晨動幽興，沙岸泊歸船。", "岸遠望不極，歸思隨長川。"]'),
('680523b3-d184-4ef9-832d-2f2d151ef3f2','獨酌','李若川','宋','宋诗','song-poetry','','[]','兀坐起往念，新愁忽來侵。',96,'全唐诗/poet.song.122000.json','["兀坐起往念，新愁忽來侵。", "鬰鬰不自怡，開尊獨盈斟。", "舉杯對孤影，浩蕩生幽襟。", "百慮遂消散，無復縈我心。", "修篁爾何情，風中來清音。", "不覺日已晏，四面山沈沈。", "超遥醉中適，頹然忘古今。", "染翰記所寓，音屬自成吟。"]'),
('b8f31c00-4d20-41d3-bad2-c3acf87fbdda','村社歌','李若川','宋','宋诗','song-poetry','','[]','清曉鼕鼕鳴社鼓，前村後村走兒女。',96,'全唐诗/poet.song.122000.json','["清曉鼕鼕鳴社鼓，前村後村走兒女。", "田家醵錢共賽神，謝神時晴復時雨。", "案有肴酒爐有香，老巫禱祝躬案傍。", "願得年年被神福，秋宜稻穀春宜桑。", "人淳禮簡酒無數，歌笑喧闐日將暮。", "田翁欹側醉歸來，山頭明月山前路。"]'),
('1d0bd1e8-5475-4f9b-8ee1-30d5bc4ad1af','蠶婦詞','李若川','宋','宋诗','song-poetry','','[]','舍前舍後桑成林，鋤墾不放青草侵。',96,'全唐诗/poet.song.122000.json','["舍前舍後桑成林，鋤墾不放青草侵。", "東風滿條新葉大，村家愛此輕黄金。", "日暖春蠶大眠起，戢戢盈箱齊若指。", "看蠶新婦夜不眠，蠶老登山滿家喜。", "阿姑嗔辦繰車遲，小姑已催修織機。", "殺雞沽酒賽神福，今歲不怕寒無衣。"]'),
('06fe48be-ada6-4487-adbf-785c5a5c1794','南紀樓','馮杞','宋','宋诗','song-poetry','','[]','豈忍輕離江漢州，去思日夜逐東流。',32,'全唐诗/poet.song.122000.json','["豈忍輕離江漢州，去思日夜逐東流。", "可憐南紀樓前路，常與邦人憶蔡侯。"]'),
('600653ad-385f-42fe-a59a-e54213909497','句  其一','馮杞','宋','宋诗','song-poetry','','[]','人物英雄故沔州，嶓岷千古奉雙流。',16,'全唐诗/poet.song.122000.json','["人物英雄故沔州，嶓岷千古奉雙流。"]'),
('b57fad7c-e192-4be6-a344-96a8f8c5e334','句  其二','馮杞','宋','宋诗','song-poetry','','[]','誰知江漢壺中地，別有蓬瀛物外天。',16,'全唐诗/poet.song.122000.json','["誰知江漢壺中地，別有蓬瀛物外天。"]'),
('96f0b388-c4e7-4ec7-bedd-2359f389f255','和李侍郎移竹','鄭將','宋','宋诗','song-poetry','','[]','仲夏竹迷日，長竿带筍移。',56,'全唐诗/poet.song.122000.json','["仲夏竹迷日，長竿带筍移。", "地生宜雨潤，根淺畏風吹。", "斸破沿階蘚，添成宿鳳枝。", "子猷清洒（鐸案：當爲酒）意，應與渭川期。"]'),
('2cb58f45-4bad-4dad-9e89-9df7d856a3d9','濡須塢','龔相','宋','宋诗','song-poetry','','[]','南北安危限兩關，迅流一去幾時還。',32,'全唐诗/poet.song.122000.json','["南北安危限兩關，迅流一去幾時還。", "淒凉千古干戈地，春水方生鷗自閒。"]'),
('fa03b9e4-dd17-4b0c-9ea7-eef5cb2a5562','學詩  其一','龔相','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，悟了方知歲是年。',32,'全唐诗/poet.song.122000.json','["學詩渾似學參禪，悟了方知歲是年。", "點鐵成金猶是妄，高山流水自依然。"]'),
('ea5f7284-a998-4dff-a51b-1aa2bb90d03e','學詩  其二','龔相','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，語可安排意莫傳。',32,'全唐诗/poet.song.122000.json','["學詩渾似學參禪，語可安排意莫傳。", "會意即超聲律界，不須鍊石補青天。"]'),
('e160891e-6421-443d-b5aa-82d72f8f4aee','學詩  其三','龔相','宋','宋诗','song-poetry','','[]','學詩渾似學參禪，幾許搜腸覓句聯。',32,'全唐诗/poet.song.122000.json','["學詩渾似學參禪，幾許搜腸覓句聯。", "欲識少陵奇絕處，初無言句與人傳。"]'),
('e2407a6c-358a-4a2a-addb-99d340776736','句','龔相','宋','宋诗','song-poetry','','[]','夜半微雨濕，凌晨春草長。',12,'全唐诗/poet.song.122000.json','["夜半微雨濕，凌晨春草長。"]'),
('2b04d40e-bb1e-4f93-b7fd-1db8c0bb9c30','送舉人','徐璋','宋','宋诗','song-poetry','','[]','揭陽多士天下都，聲名籍籍南海隅。',128,'全唐诗/poet.song.122000.json','["揭陽多士天下都，聲名籍籍南海隅。", "往往能騎龍馬駒，唾手可捋於菟鬚。", "大食刀斫赤瓠壺，綠沈弓迸金僕姑。", "太阿何止敵萬夫，四海可歸輿地圖。", "一舉旌旗到三吳，全軍接上甘泉書。", "不比白面謝石奴，漢庭挺出萬卷儒。", "至尊含笑御玉虛，此時賢傑氣焰舒。", "更看相踵昇亨衢，鳳池雞省爭鳧趨。"]'),
('186c0bea-81b3-4263-b97a-76e7d5c2d9af','探梅過西湖','鄭安恭','宋','宋诗','song-poetry','','["\u897f\u6e56"]','郊坰一到眼偏明，古寺寂無鐘磬聲。',64,'全唐诗/poet.song.122000.json','["郊坰一到眼偏明，古寺寂無鐘磬聲。", "共上籃輿尋勝事，獨先冠蓋愧雙旌。", "探梅載酒成幽趣，縱步登山喜晚晴。", "自顧遨頭最衰老，不才何幸守邊城。"]'),
('cc84e808-c647-40cc-b270-1bf4d5045cc4','次太守鄭安恭探梅過西湖韻  其一','張棟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','亭亭冰質照溪明，异常异常如聞環佩聲。',66,'全唐诗/poet.song.122000.json','["亭亭冰質照溪明，异常异常如聞環佩聲。", "初訝玉妃遊月地，但無他仗引霓旌。", "使君再約慇懃賞，天意從教爛漫晴。", "詩律清嚴誰敢犯，七言今始見長城。"]'),
('a7739256-edf8-4a96-b6d0-996678c83a92','次太守鄭安恭探梅過西湖韻  其二','張棟','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金方正位鑿平湖，物景堪將入畫圖。',64,'全唐诗/poet.song.122000.json','["金方正位鑿平湖，物景堪將入畫圖。", "兩岸雨垂楊柳重，一汀沙立鷺鷥孤。", "泓澄良夜摇明月，瀲灧高秋蘸碧蘆。", "寓目瀟湘徒有約，殘陽歸去獨躊躇。"]'),
('efec5249-580c-4ca5-a683-d97894be16f7','寄崔嘉彥','張棟','宋','宋诗','song-poetry','','[]','厭踏千山折，欣逢屋數椽。',48,'全唐诗/poet.song.122000.json','["厭踏千山折，欣逢屋數椽。", "衣冠存古制，松雪對華巔。", "自漉甕中酒，仍烹澗底泉。", "桃源疑此是，不必問神仙。"]'),
('b33627b3-c58c-458a-8b0a-4c8a529cc8f0','思政堂','唐時','宋','宋诗','song-poetry','','[]','邵陽府第之西，湖山之東，耽耽大厦磨蒼穹。',103,'全唐诗/poet.song.122000.json','["邵陽府第之西，湖山之東，耽耽大厦磨蒼穹。", "賢哉鄭侯爲棟隆，朝夕思政於其中。", "取君子之九思以謹行，取季子三思以盡忠。", "及思治道貴清靜，又效曹參舍蓋公。", "之子于歸筑百堵，已見豐年詠華黍。", "周公待旦復何爲，贊贊宣王之復古。"]'),
('59e3f52a-1593-446f-a691-ef23813aa0f8','監樂堂','王灼','宋','宋诗','song-poetry','','[]','隆然新堂，治所中間。',160,'全唐诗/poet.song.122000.json','["隆然新堂，治所中間。", "江嶺環匝，州瘠以寒。", "吾氓蚩蚩，吏有奪欺。", "侯登新堂，來輯來綏。", "新堂隆然，侯遠近望。", "力紓吾氓，俾獲其仰。", "瘠吾與食，寒吾與纊。", "導爾嬉娛，廢爾悽悵。", "堂富眾產，左右後前。", "沼魴嶼鳥，春棠夏蓮。", "莫莫者葛，蔭五畝餘。", "爾動爾植，其寧爾居。", "侯讌新堂，賓僚接席。", "觀者牆立，垂髫戴白。", "歌鐘既合，手之舞之。", "祝侯壽考，與江嶺期。"]'),
('fe8ff935-fc76-48e4-b165-462b2b8ec73d','銅馬歌','王灼','宋','宋诗','song-poetry','','[]','君不見武皇逸志凌九垓，追風躡影思龍媒。',136,'全唐诗/poet.song.122000.json','["君不見武皇逸志凌九垓，追風躡影思龍媒。", "魯班門外立銅馬，天廐萬匹皆塵埃。", "又不見伏波將軍破交賊，歸來殿前獻馬式。", "據鞍習氣殊未衰，想見老子真矍鑠。", "兩京翻覆知幾秋，只有山河供客愁。", "孤煙落日蠶叢國，出此神物於荒丘。", "千年黄壤誰作主，猶把歸心泣風雨。", "但恐一朝去無蹤，有似豐城寶劍化雙龍。"]'),
('5894752c-184e-481e-8278-b2e8a7e6eb63','葛仙化','王灼','宋','宋诗','song-poetry','','[]','靈山信多異，孤起一萬尋。',144,'全唐诗/poet.song.122000.json','["靈山信多異，孤起一萬尋。", "其上羅諸峰，聳秀欲相臨。", "危磴巧盤折，古洞閟清深。", "叢木開錦帳，飛泉鳴玉琴。", "三仙班龍駕，長往無歸音。", "高閣儼像設，霓衣紫霞衿。", "故知飛昇骨，偕來幽絕岑。", "聲利豈不好，奈此老境侵。", "吾家窮子安，登覽動悲吟。", "盛時亦云遇，志大力叵任。", "今人已笑古，後人復視今。", "天命儻可順，吾將守素心。"]'),
('dddc301d-73e3-467f-a05a-889b31100b28','大隋山','王灼','宋','宋诗','song-poetry','','[]','天彭對峙闢兩門，群山左右爭駿奔。',192,'全唐诗/poet.song.122000.json','["天彭對峙闢兩門，群山左右爭駿奔。", "金城中間作几案，大隋踞坐何其尊。", "境勝地靈誰敢宅，古佛來自東家村。", "結茅三間初未暇，一庵聊寄枯木根。", "緇徒駢擁助薪水，王侯漸次迂華軒。", "翫月峰深崇棟宇，瀑布巖冷清心魂。", "至今西南推望剎，十世說法雲仍孫。", "病夫垂老寡所嗜，獨於要妙欲細論。", "當時戲出隨他語，坐斷報化轉乾坤。", "邇來衲子多異解，白玉面上加瘢痕。", "山蔬煮餅姑恣飽，雲氣漠漠連黄昏。", "空堂附火耿不寐，聽徹猿鳥迎朝暾。"]'),
('beb95ff8-e48b-4510-920a-6701305f129c','曲尺山雲居寺','王灼','宋','宋诗','song-poetry','','[]','循溪上坡坨，溪亦因山曲。',120,'全唐诗/poet.song.122000.json','["循溪上坡坨，溪亦因山曲。", "行盡高深處，招提隱山腹。", "往者灰燼餘，白塔但孤矗。", "十年鬧斤斧，有此千間屋。", "阿師笑相語，異事子當卜。", "今日鐘報客，振響非人觸。", "病悴優婆塞，歸夢到松菊。", "諸聖惠三昧，警我煩惱毒。", "卧聽夜雨喧，起看曉雲族。", "去路猶恐迷，主人費齋粥。"]'),
('fecfff8a-714e-46b2-af11-7e3a4ea67491','讀王尼傳','王灼','宋','宋诗','song-poetry','','[]','處世常多憂，政坐口復牽。',132,'全唐诗/poet.song.122000.json','["處世常多憂，政坐口復牽。", "誰能百無營，飲露如寒蟬。", "原野足餓殍，山澤漫臞僊。", "作計苦不早，身窮乃怨天。", "劉石擾河洛，孝孫方南遷。", "庇無一區宅，耕無一畝田。", "牛車不自救，枯骸枕道邊。", "君看董與葛，見幾預著鞭。", "智慮故不同，禍福仍相懸。", "關輔已荆棘，江淮復戎旃。", "吾生亦可料，速辦買山錢。"]'),
('81bbec5c-938d-47ac-ad1a-1fc2bfe97ec4','風蓬蓬一首贈范德承','王灼','宋','宋诗','song-poetry','','[]','風蓬蓬，雨窣窣，客子中夜寒侵骨。',96,'全唐诗/poet.song.122000.json','["風蓬蓬，雨窣窣，客子中夜寒侵骨。", "青燈也解照孤愁，歸夢不到涪江側。", "晚來天氣猶未佳，萬里濕雲遮日華。", "僧房僻寂無來轍，踏遍長廊占晚霞。", "聞道比鄰酒初熟，能來澆我空洞腹。", "爲君痛飲不苦辭，世路紛紛蠻與觸。"]'),
('bebb86d9-7538-4a9d-b7fa-e63d1ba53edc','贈王先生','王灼','宋','宋诗','song-poetry','','[]','隴種健兒鬚如棘，幼事秦府持鞭靮。',131,'全唐诗/poet.song.122000.json','["隴種健兒鬚如棘，幼事秦府持鞭靮。", "戰塵撲面心已灰，徑上三峰弄泉石。", "乾坤變化五百年，人間未識地行僊。", "布裘落魄荆州市，丹經秘法爲君傳。", "散盡千金何所有，腹中氣作蛟龍吼。", "功成直欲凌紫虛，尚愛岷峨山下酒。", "年來我亦厭樊籠，乞取微言爲指蹤。", "君不見葉縣雙鳧緱嶺鶴，古來度世多吾宗。"]'),
('ddacc7a2-c9b3-4659-b960-b950c5beb221','前年一首投贈劉荆州','王灼','宋','宋诗','song-poetry','','[]','前年別公東南馳，正當六騩還宮時。',192,'全唐诗/poet.song.122000.json','["前年別公東南馳，正當六騩還宮時。", "都人歡傳好消息，慈寧首問公何之。", "氈裘不復恃軍馬，潁上一戰中興基。", "青天白日呈萬象，向來讒吻真成癡。", "數從西府伺行李，樞筦政要人扶持。", "吳江再見丹楓落，寧料我公猶在茲。", "呼鷹臺邊閑鼓角，望沙樓上陳書詩。", "夕烽平安置莫問，賢牧自當十萬師。", "維昔全荆號强國，近者賊火仍瘡痍。", "形勝之地勳名集，端使前輩相追隨。", "衰宗依劉有故事，自憐遠去作兒嬉。", "明朝爛醉沙頭酒，不管春風吹鬢絲。"]'),
('b6daaef4-ec1c-4b1f-9388-dd8fdfdf93ff','贈趙當可  其一','王灼','宋','宋诗','song-poetry','','[]','元子稱漫浪，嚴生資苦勁。',48,'全唐诗/poet.song.122000.json','["元子稱漫浪，嚴生資苦勁。", "海內無賞音，秋風入衰鬢。", "東江一茅屋，但欲安性命。", "頗怪澤畔翁，煩詞寄天問。"]'),
('ceff44f1-f828-42b7-88ad-f52f40b10829','贈趙當可  其二','王灼','宋','宋诗','song-poetry','','[]','晚交得王孫，每見心輒醉。',48,'全唐诗/poet.song.122000.json','["晚交得王孫，每見心輒醉。", "平生虎豹韜，近者詩酒累。", "流光迫壯懷，撫事我亦欷。", "不如從君飲，此外淡無味。"]'),
('5df77a67-99a4-4eab-a385-37fe1d13361a','張元舉惠江南李王帳中香','王灼','宋','宋诗','song-poetry','','[]','西樓北苑春色濃，日日醉倒駢齒翁。',128,'全唐诗/poet.song.122000.json','["西樓北苑春色濃，日日醉倒駢齒翁。", "歸來萬事不整理，笑倚娥皇冰雪容。", "疊箋共寫霓裳譜，更作新聲邀醉舞。", "瑶光殿裏帳拖紅，一尺爐煙日亭午。", "事去時移二百年，金陵空有舊山川。", "此香那得到君手，妙訣無乃當時傳。", "慚君爲我供愁絕，年來辦得心如鐵。", "但能飲酒讀離騷，竹枕藤床卧明月。"]'),
('76aee98c-c75c-4e6a-8cf6-7c7abf07582f','范元通見和仍邀再賦','王灼','宋','宋诗','song-poetry','','[]','新橋酒作琥珀濃，平生頗羨江南翁。',128,'全唐诗/poet.song.122000.json','["新橋酒作琥珀濃，平生頗羨江南翁。", "扁舟尚繫清涪尾，却對爐香開病容。", "何必探囊尋舊譜，一見詩筒喜欲舞。", "奇芬麗句兩爭雄，蘇合芝蘭謾旁午。", "當時俊氣輕百年，父老而今悲逝川。", "得公操筆弔興廢，定知詩與香俱傳。", "我生自是癡中絕，懶學諸儒議鹽鐵。", "枯腸空洞費搜尋，兀坐忍饑三百月。"]'),
('5d232e5e-4858-48fb-984b-31f68b4d04e3','李彥澤從余求衛公兵法','王灼','宋','宋诗','song-poetry','','[]','衛公少時已知兵，坐談壓倒韓擒虎。',160,'全唐诗/poet.song.122000.json','["衛公少時已知兵，坐談壓倒韓擒虎。", "一朝委事虬鬚帝，南殲荆盜北鋤虜。", "出其緒餘教君集，猶謂四夷莫予侮。", "乃知機略妙無比，攻城破陣一仰俯。", "當時傳公挾異術，雲祲孤虛自默數。", "可憐癡兒尚詭怪，至作齊東野人語。", "我家舊畜公遺書，片段飄零十得五。", "開囊取拾送君讀，想見明窗口如皷。", "玉輿消息渺吳越，鐵騎縱橫暗江浦。", "學成出去清胡塵，莫道儒生不能武。"]'),
('59fcc837-c361-4317-99dd-85808394d6f3','得孫以詩邀立夫兄次明丈作看客','王灼','宋','宋诗','song-poetry','','[]','我生苦不諧，所向如登天。',120,'全唐诗/poet.song.122000.json','["我生苦不諧，所向如登天。", "老眼始見孫，便覺了世緣。", "一陽謹初度，剝極宜復旋。", "神氣已秀發，玉虹照晴川。", "家書或有託，似能守青編。", "免翁費十牛，令渠受一廛。", "使君與別駕，同是峨眉僊。", "肯來摩其頂，飛蓋相聯翩。", "丘也親抱送，已輸徐氏先。", "游夏實高弟，庶幾文學傳。"]'),
('936f7b3e-315f-4d89-9358-f8bbb1448ba0','次韻子春','王灼','宋','宋诗','song-poetry','','[]','微風度疏竹，青燈照孤影。',216,'全唐诗/poet.song.122000.json','["微風度疏竹，青燈照孤影。", "起尋千載書，坐對一夕永。", "念昔走京師，噉蔗入佳境。", "注傳擬杜癖，說詩配康鼎。", "詎識豹霧深，但愛虎文炳。", "薦紳滿朱紫，人物稱袖領。", "經義有寸長，富貴在食頃。", "彈冠欲慕貢，洗耳寧思潁。", "自從鐵林騎，來污金華省。", "幾年强求活，百事付幽屏。", "慵便麈柄閑，病怯牛衣冷。", "借書試探討，掩關謝馳騁。", "新聞渺無得，舊學粗可整。", "鉛筆伴曹褒，蟣蝨欺王猛。", "自憐亡奇者，才拙乃素稟。", "誓爲漫浪叟，畢此須臾景。", "升沉豈殊致，行止貴深省。", "嘉言誰起予，虛心期一請。"]'),
('032b9e11-a80b-43b1-b62f-fa7a1760456a','宿毗沙院諸友相送','王灼','宋','宋诗','song-poetry','','[]','出門風喧號，半道雨飄洒。',168,'全唐诗/poet.song.122000.json','["出門風喧號，半道雨飄洒。", "行役已堪厭，投宿小蘭若。", "葱籠林樾中，一徑僅容馬。", "古屋數十椽，佛事走村社。", "王趙兩故人，清詩壁間寫。", "讀徧已曛黑，尚有相送者。", "見可逞雄辯，譊譊欲脣哆。", "伯威弄長笛，哀音振原野。", "子仁喜捷敏，德常號醇雅。", "來共一夕寒，罇酒肯屢把。", "明朝定西去，山路泥沒踝。", "此地當迴首，想見煙苒惹。", "平生受性僻，所至徒侶寡。", "因詩記離憂，踟躕孤燈下。"]'),
('7b9e1429-8321-44e3-8479-62ad94f2f348','戲王和先張齊望','王灼','宋','宋诗','song-poetry','','[]','王家二瓊芙蕖妖，張家阿倩海棠魄。',85,'全唐诗/poet.song.122000.json','["王家二瓊芙蕖妖，張家阿倩海棠魄。", "露香亭前占秋光，紅雲島邊弄春色。", "滿城錢癡買娉婷，風卷畫樓絲竹聲。", "誰似兩家喜看客，新翻歌舞勸飛觥。", "君不見東州鈍漢髮半縞，日日醉踏碧雞三井道。"]'),
('dea4f183-3291-4657-a027-f10b62c52401','次韻韶美義夫兩家舉孫','王灼','宋','宋诗','song-poetry','','[]','兩翁連詩軸，誇我新生孫。',96,'全唐诗/poet.song.122000.json','["兩翁連詩軸，誇我新生孫。", "種德固有後，擾龍同一門。", "祥應偶然耳，矯激笑劉昆。", "要令百世祀，那止一飯恩。", "遥知湯餅局，歡傳溪上村。", "茅堂滿賓客，秫酒對雞豚。", "我亦勸兩翁，自放琴與罇。", "此生復何事，醉吟閱朝昏。"]'),
('e0a5df9c-45ed-4f99-b486-4da9bfc207ea','次何子應登賦樓韻','王灼','宋','宋诗','song-poetry','','[]','使君來作牧，眾若倚南山。',72,'全唐诗/poet.song.122000.json','["使君來作牧，眾若倚南山。", "時節當授衣，已念赤子寒。", "駕言出登眺，豈爲景趣繁。", "民風指顧中，惠術良欲殫。", "紓懷有佳句，伏誦一再歎。", "從今安田里，不度百牢關。"]'),
('f78eaeba-4c7c-4113-8a9f-9cee70f9ba72','以朝雞送樊氏兄弟效魯直體作兩絕  其一','王灼','宋','宋诗','song-poetry','','[]','平生自許屠龍學，歲晚擬作祝雞翁。',32,'全唐诗/poet.song.122000.json','["平生自許屠龍學，歲晚擬作祝雞翁。", "長鳴分送君識取，腷腷膊膊風雨中。"]'),
('d7099b03-369f-4c8d-ba48-4ca2f8c6467c','以朝雞送樊氏兄弟效魯直體作兩絕  其二','王灼','宋','宋诗','song-poetry','','[]','麈柄知君談亹亹，雞群笑我喚朱朱。',32,'全唐诗/poet.song.122000.json','["麈柄知君談亹亹，雞群笑我喚朱朱。", "曉窗試渠作人語，絕勝蠹簡用工夫。"]'),
('f5bda496-0169-4eb4-bc17-0352317820c8','李仲高石君堂','王灼','宋','宋诗','song-poetry','','["\u592a\u6e56"]','三吳黑風吹地拆，太湖浪高一千尺。',320,'全唐诗/poet.song.122000.json','["三吳黑風吹地拆，太湖浪高一千尺。", "龜黿兩山壓湖心，歲歲飛濤恣衝射。", "山骨雖堅亦破碎，穴穿根斷瑰奇出。", "古來石品稱上首，羅浮天竺乃其乙。", "吳蜀相望天東西，而從何處得此石。", "初逢頗驚醜怪狀，徐視不見鎸鑱跡。", "月暗煙昏鬼神怒，沙平草短狻猊擲。", "或云王孟竊據時，曾是宣華苑中物。", "姦雄敗滅化爲土，獨此頑然蒼玉立。", "流落幾家到李氏，命名以君相主客。", "爲君榜堂詫鄉人，愛賞不啻連城璧。", "金璫中官來奉使，一時氣燄手可炙。", "利誘威脅擬奪去，仲高誓死君之側。", "先世所寶吾敢墜，貴人縮首三嘆息。", "會昌丞相乃遠祖，嗜好夙有煙霞癖。", "平泉山居付夢想，石上刻字空照日。", "朱崖精爽雖可畏，洛陽群盜旋充斥。", "故知幽勝豈易保，天公似向人間惜。", "政須洒掃堂上下，置酒招我無難色。", "酒闌氣壯拂衣起，摩挲石君話疇昔。"]'),
('5d404e67-e653-41ed-8524-3d1aaba50db6','招隱亭','王灼','宋','宋诗','song-poetry','','[]','層崖壓西城，半空矗孤峭。',144,'全唐诗/poet.song.122000.json','["層崖壓西城，半空矗孤峭。", "何人結斯宇，想見胸次妙。", "叢林開蒙密，江山得樞要。", "拂拂幽草香，嘖嘖群鳥叫。", "我作謝公屐，來學阮生嘯。", "披襟待凉吹，停盃延落照。", "永嗟區中人，嗜慾昏九竅。", "誰賦招隱辭，此病政難療。", "我亦裹青衫，俛首入選調。", "平昔志萬里，自省成大笑。", "才術幸無取，曷不返耕釣。", "雄飛或有時，一拜蒲車詔。"]'),
('0afade4a-414e-4092-860c-29ee1a756555','任氏園二詠 騖遠樓','王灼','宋','宋诗','song-poetry','','[]','世論尚迫隘，吾道亦摧藏。',72,'全唐诗/poet.song.122000.json','["世論尚迫隘，吾道亦摧藏。", "行歌碧雲暮，坐怨瑶草芳。", "不如寄層梯，轉盼盡八荒。", "飛霞曳爲裾，明月綴爲璫。", "舉手招盧敖，振步謁紫皇。", "歸續大人賦，一笑遥相望。"]'),
('2bb21cb9-9d7a-404c-961d-1fe32aabb388','任氏園二詠 舫齋','王灼','宋','宋诗','song-poetry','','[]','平生江海志，煙雨一莎衣。',72,'全唐诗/poet.song.122000.json','["平生江海志，煙雨一莎衣。", "掛帆恨不早，白首心事違。", "作齋跨幽塘，想像未覺非。", "時傾半樽綠，自釣尺鯉肥。", "蘆花卧秋風，柳带摇春暉。", "寄言宣城守，何必天際歸。"]'),
('0055d493-b606-4a1c-a5ce-39cb8d8219a6','王氏碧雞園六詠 露香亭','王灼','宋','宋诗','song-poetry','','[]','北渚一帝子，洛川一宓妃。',72,'全唐诗/poet.song.122000.json','["北渚一帝子，洛川一宓妃。", "池有十種蓮，平生所見稀。", "纖穠各態度，紅白爭光輝。", "我來亭上飲，夜久未忍歸。", "翁家採香人，但愛香滿衣。", "豈知清露濕，圓荷瀉珠璣。"]'),
('019789d1-7893-454d-8083-2b5d69f1dde0','王氏碧雞園六詠 鈍庵','王灼','宋','宋诗','song-poetry','','[]','俗子如錐利，達士如椎鈍。',72,'全唐诗/poet.song.122000.json','["俗子如錐利，達士如椎鈍。", "乘除付造物，多智反自困。", "君看庵中翁，漫浪出方寸。", "卧聽松聲老，行觸蘭芳嫩。", "謀身固未快，事過了無恨。", "今人豈辦此，勸翁慎勿論。"]'),
('fb59b8ea-ec36-42cf-92c2-0b52aca5b3e7','王氏碧雞園六詠 清室','王灼','宋','宋诗','song-poetry','','[]','碧雞古名坊，奔騰車馬塵。',72,'全唐诗/poet.song.122000.json','["碧雞古名坊，奔騰車馬塵。", "那知小洞天，清絕欲無鄰。", "一室對林樾，四時禽語新。", "焚香讀周易，意得氣自伸。", "明月落盃酒，冷風弄衣巾。", "寄言朝市客，聲利恐汙人。"]'),
('46461b32-c0b5-4f86-a62d-478d217215c3','王氏碧雞園六詠 鑑泉','王灼','宋','宋诗','song-poetry','','[]','分來何處泉，注此團欒池。',72,'全唐诗/poet.song.122000.json','["分來何處泉，注此團欒池。", "有如大圓鑑，玉匣初開時。", "瑩然絕纖埃，萬象見毫氂。", "主人湖海士，曳杖日娛嬉。", "應照兩侍女，新粧弄妍姿。", "亦復照主人，鬢髮白絲絲。"]'),
('e3ceeed6-9288-4023-ae33-9a8d73e90812','王氏碧雞園六詠 凉榭','王灼','宋','宋诗','song-poetry','','[]','窈窈林影深，澹澹波光冷。',72,'全唐诗/poet.song.122000.json','["窈窈林影深，澹澹波光冷。", "異哉濁惡世，有此清凉境。", "側身朱欄上，風煙得幾頃。", "嘯聲出奇響，疑在蘇門嶺。", "荷氣遞遥馥，如窺太華井。", "要須從翁遊，岸巾閑日永。"]'),
('ae83d8cd-6f23-482c-9b02-1c6c34f60d6a','王氏碧雞園六詠 層蘭','王灼','宋','宋诗','song-poetry','','[]','僊翁有蘭癖，肆意搜林坰。',72,'全唐诗/poet.song.122000.json','["僊翁有蘭癖，肆意搜林坰。", "負牆累爲臺，移此萬紫青。", "九畹與九層，異世皆可銘。", "收拾眾妙香，逍遥醉魄醒。", "隱几光風度，開簾皎月停。", "門前勿通客，翁續離騷經。"]'),
('2b56040e-3c65-4d14-ab3b-e3d8142f7974','宿崇德祠下望青城諸山','王灼','宋','宋诗','song-poetry','','[]','昔年來就學，頗熟青城面。',120,'全唐诗/poet.song.122000.json','["昔年來就學，頗熟青城面。", "雖無尋山分，猶喜旦暮見。", "違去八寒暑，夢想無時休。", "誰意俗士駕，復作山下遊。", "晚雲蔽高峰，悵望久拄頰。", "山靈豈猜我，未許相投接。", "晨興雲散盡，秀色矗亭亭。", "還如故人眼，不改舊時青。", "愧非自由身，又復塵中去。", "他日訪麻姑，問訊山頭路。"]'),
('a3ea1c4f-76cd-450c-b946-338ba4d76c23','浄明長老睡庵','王灼','宋','宋诗','song-poetry','','[]','阿師睡三昧，有如飽葉蠶。',48,'全唐诗/poet.song.122000.json','["阿師睡三昧，有如飽葉蠶。", "以睡作佛事，復名所住庵。", "夢覺本何擇，月行影在潭。", "勿笑脇尊者，二子正同參。"]'),
('0188b62e-e8e1-4886-8ecc-eaf6c3781c72','懷安光孝寺觀空軒遺圓長老','王灼','宋','宋诗','song-poetry','','[]','寶坊鬰鬰滿松檜，獨有小軒花數輩。',128,'全唐诗/poet.song.122000.json','["寶坊鬰鬰滿松檜，獨有小軒花數輩。", "榜以觀空作正觀，要識轉物大三昧。", "世間眩人萬紅紫，心君已落色界內。", "那知心境無異法，真見元非色塵外。", "色空雙忘未奇特，非非想處亦橫潰。", "誰因拈花發微笑，嚼蕊嗅香不相礙。", "吾儕跛鼈望千里，安得還都如歷塊。", "詩成懷藏擬不出，彼上人者難酬對。"]'),
('ffdc0cf7-83bb-413e-90c8-026fd2cfe909','置酒登賦樓觀月立夫有詩序別次韻','王灼','宋','宋诗','song-poetry','','[]','西山自高爽，更上百尺樓。',76,'全唐诗/poet.song.122000.json','["西山自高爽，更上百尺樓。", "月華出萬象，獨以寸目收。", "寒光增灝氣，山影接江流。", "相從更幾日，醉賞同一甌。", "諸君有大志，應銷別去愁。", "衣食纔足守墳墓，記取龍鍾馬少游。"]'),
('c5c63755-6026-4177-bcf1-a65190e3a341','九日同韶美誼夫登妙明分韻得光字','王灼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','野迥半留日，雲薄初護霜。',120,'全唐诗/poet.song.122000.json','["野迥半留日，雲薄初護霜。", "一傾萸菊酒，三肅翰墨場。", "諸君黨友賢，獨我鬢毛蒼。", "滿引雖云樂，分携亦自傷。", "平生子劉子，趣歸謁建章。", "勳業定指取，富貴肯相忘。", "古人重佳節，酬酢無餘觴。", "龍山丹葉飛，騎臺白草荒。", "但使修名立，豈識離緒長。", "明年未可料，共飲西湖光。"]'),
('267b47af-11c4-4bf7-a2cf-ab018049d6a4','呈蘇企道漢良呂默夫','王灼','宋','宋诗','song-poetry','','[]','半生岷山下，心與岷山親。',96,'全唐诗/poet.song.122000.json','["半生岷山下，心與岷山親。", "幾蠟登山屐，不作山間人。", "茲遊愜所願，晴暄送餘春。", "山意欲相招，縷脈就我陳。", "同行二三友，懷抱無一塵。", "久矣煙霞癖，佳哉笑語新。", "歲華迫人老，世故遣人嗔。", "努力造窮絕，樂事當及辰。"]'),
('b24ba568-507c-4803-826b-eea2e58f33dc','次韻李士舉丈感春','王灼','宋','宋诗','song-poetry','','[]','四時平分春大好，春雖强半未甘老。',128,'全唐诗/poet.song.122000.json','["四時平分春大好，春雖强半未甘老。", "輕車矮馬恣搜尋，始信天工爲春巧。", "中園層層亂風花，長路青青被煙草。", "詎知陽熙變陰慘，頓令樂事成憂悄。", "兒曹浪語甜如蜜，欲觀俘囚數軍實。", "貔貅萬屯移蜀塞，胡人喜躍秦人泣。", "孤坐唯防酒盞空，餘寒頗覺鶯聲澀。", "貪嗜五斗不自謀，幾時歸作山林客。"]'),
('95ca4c46-44b8-4933-bbaf-3cd811811676','次馮申之遊靈泉韻','王灼','宋','宋诗','song-poetry','','[]','名山起高興，不惜馬首東。',132,'全唐诗/poet.song.122000.json','["名山起高興，不惜馬首東。", "沙邊一著眼，翠光已浮空。", "踏遍桑柘村，所向漸不同。", "溪細山疑合，谷轉路始窮。", "瑩浄白玉界，芬馥青蓮宮。", "元知境過清，乘春乃昭融。", "尚餘半殘花，伴我酒頰紅。", "拂石愛少蘚，披林怯多風。", "安得身無事，來對禪寂翁。", "慮沉燈影外，慧發鳥聲中。", "庶遂老巖壑，此行太匆匆。"]'),
('03ea4fac-379f-44fa-ba2a-c34608a52844','李安撫生日','王灼','宋','宋诗','song-poetry','','[]','沙溝紫氣如隴雲，涇城冬律變陽春。',96,'全唐诗/poet.song.122000.json','["沙溝紫氣如隴雲，涇城冬律變陽春。", "天工爲國巧謀帥，生此摽摽七尺人。", "坐揮白羽歷三紀，胡兒奔迸塵頭起。", "緩驅小隊來漢中，甲光冷射清江水。", "金爐著火焚寶香，願公壽考仍康强。", "門外祝公更多有，軍民十萬指中梁。"]'),
('a20412d5-f026-46bf-b81a-bac1931c2bb2','范漕生日','王灼','宋','宋诗','song-poetry','','[]','治忽本天運，賢哲豈浪出。',264,'全唐诗/poet.song.122000.json','["治忽本天運，賢哲豈浪出。", "中興信可期，帝爲賚良弼。", "嶄嶄岷峨山，西南著第一。", "山靈借英氣，成此垂雲翼。", "才多浩江海，道大迷畛域。", "磊落萬卷腹，斕斑五色筆。", "曩參相君幙，謀入九地密。", "復佩太守章，化行千里溢。", "紫詔從東來，畀之使者節。", "旋兼蜀大尹，繡衣擁彫戟。", "談笑百城聳，指顧萬事集。", "但恐被賜環，台衮輔王室。", "有如老忠文，殊勳照簡冊。", "佳時過重五，適當懸弧日。", "遠邇祈公壽，歡聲共一律。", "伶俜涪江生，獨以文爲業。", "不敢嚴香火，不敢具芝朮。", "拂拭舊破硯，胸次先突兀。", "公掃河朔塵，請飛聊城檄。", "公蹀定襄血，請勒燕然石。", "待公黄髮年，几杖付閑逸。", "從公綠野堂，哦詩繼元白。"]'),
('48bda527-e606-46fa-b412-15f870fca3aa','中秋大雨','王灼','宋','宋诗','song-poetry','','[]','癡情愛佳月，樂事期中秋。',72,'全唐诗/poet.song.122000.json','["癡情愛佳月，樂事期中秋。", "造物故相戲，不遣金波流。", "玄雲如塗墨，急雨欲漲溝。", "瞑色暗無際，壯聲浩莫收。", "揖謝雲雨師，努力勿罷休。", "歸來坐書室，盃酒自獻酬。"]'),
('484b4487-e7a0-4ae2-8796-2ce6701f00af','遊空山','王灼','宋','宋诗','song-poetry','','[]','閱遍平川至山足，投鞭下馬緣山腹。',224,'全唐诗/poet.song.122000.json','["閱遍平川至山足，投鞭下馬緣山腹。", "古柏屹如蒼龍起，絕磴盤作長蛇曲。", "氣力已憊意未歇，市聲不到境尤肅。", "款門徑謁紫金像，邃殿苒苒來香馥。", "褰衣却上清虛閣，叢林障我千里目。", "嘉名大榜起何人，來者先自嘆煩促。", "時於缺罅見一一，煙江黛嶂堆青綠。", "先人昔此斷還往，三年學古忘幽獨。", "當時詩板今無在，只餘石刻記經軸。", "拂塵再誦心欲折，世態萬變流光速。", "我方投迹隨喧鬨，文字堆床未盡讀。", "山中宴坐亦所願，那得寬閑繼前躅。", "留連兩日同僧飯，更念重來幾凉燠。", "作詩强寫無窮悲，天風爲我號寒木。"]'),
('1f5f8e8a-8c9f-489a-b79a-e9f98954de1f','遊雲靈觀','王灼','宋','宋诗','song-poetry','','[]','茲山雖特起，遠窺殊未豪。',120,'全唐诗/poet.song.122000.json','["茲山雖特起，遠窺殊未豪。", "三休出雲際，始知盤踞高。", "大江分一線，眾峰環千遭。", "溪谷粗可辨，綠樹皆蓬蒿。", "羽衣何年來，釣取海上鼇。", "盛衰伸臂頃，古屋風颾颾。", "元和有遺刻，雙旌挾時髦。", "想見飲清曠，秀句含春醪。", "萬世同一兀，名字空嘈嘈。", "吾其鍊僊骨，玉京摘蟠桃。"]'),
('c0ea2033-6b4b-442b-96f5-66cd38e0c437','遊靈泉呈性老','王灼','宋','宋诗','song-poetry','','[]','曉發雲靈山，午憩靈泉山。',108,'全唐诗/poet.song.122000.json','["曉發雲靈山，午憩靈泉山。", "兩山信有靈，相對各開顔。", "阿師達磨孫，文字昔所刪。", "戲出香積供，憐我半生孱。", "時維春物老，餘花見班班。", "杜宇鬧蒙密，胡蝶舞清閑。", "大似師說法，奧路闢重關。", "市區巧攘奪，日中誰先還。", "請以一枝筇，從師兩山間。"]'),
('478ea65b-d53f-4fc0-9030-67a1be2fece9','再遊雲靈','王灼','宋','宋诗','song-poetry','','[]','生緣墮城市，日與塵坱俱。',132,'全唐诗/poet.song.122000.json','["生緣墮城市，日與塵坱俱。", "豈無青霞志，不得閑須臾。", "李君實吾黨，半歲相招呼。", "今晨始能來，羞汗先霑濡。", "奇峰出天半，虎據東一隅。", "絕頂所見異，眾山巧奔趨。", "危坐送落日，萬象爭環鋪。", "隱公老益壯，我亦窮而迂。", "同行二三友，文采得自娛。", "少待月波上，歸騎當徐驅。", "醉中語黄冠，此心何時刳。"]'),
('d0dbd41e-ff10-4761-8c42-51c563e82455','遊樊氏阡分韻得事字','王灼','宋','宋诗','song-poetry','','[]','山深少車轍，雨餘多空翠。',96,'全唐诗/poet.song.122000.json','["山深少車轍，雨餘多空翠。", "不知窮秋中，草木乃爾媚。", "隱君一抔土，諸子幾掬淚。", "盛年喜邁種，末路等幽閟。", "村酒敢嫌濁，喚起吾渴睡。", "勿聽松風哀，姑對山月醉。", "從今棄書冊，獨以醉爲事。", "不然持禿箒，浄掃清凉寺。"]'),
('076fb851-1328-4a18-b15b-da49ebdf2251','再次韻','王灼','宋','宋诗','song-poetry','','[]','寒齋編簡香，溫室紈綺翠。',96,'全唐诗/poet.song.122000.json','["寒齋編簡香，溫室紈綺翠。", "疇昔徇所好，外物巧相媚。", "晚驚生死變，洒盡闌干淚。", "誓求無上法，不問天所閟。", "休悲夜臺客，萬年供一睡。", "我亦老將死，何苦逐昏醉。", "歸從浮圖師，了此一大事。", "試問八督州，何如三入寺。"]'),
('6046d6f6-af7c-45fa-a0e0-38576c271249','閬州新井豐山鎮慈光院殿柱有咸平三年寇萊公書海棠花絕句云喧風花雜滿欄香盡日幽吟嘆異常翻笑牡丹虛得地玉階開落對君王近歲邑令刳取墨跡寘邑之廳柱今獨石刻在','王灼','宋','宋诗','song-poetry','','[]','荒山古剎殿柱頭，萊公題詩說羈遊。',96,'全唐诗/poet.song.122000.json','["荒山古剎殿柱頭，萊公題詩說羈遊。", "當時海棠不擇地，有似野水橫孤舟。", "澶淵功成返黄屋，東府夜宴燒椽燭。", "老向雷州著綠衫，蜀芳剪棄吳舡覆。", "一驥向來超萬群，誰與九原呼相君。", "天寒酒淺不供醉，卧看北風吹陣雲。"]'),
('3f30d924-0776-41bc-a745-e23d73aa0152','大雷雨中舟過蒼溪懷杜子美','王灼','宋','宋诗','song-poetry','','[]','疾雷欲破嶽，疾風欲翻海。',120,'全唐诗/poet.song.122000.json','["疾雷欲破嶽，疾風欲翻海。", "昏昏雲氣中，稍辨□𡾋嵬。", "飄雨雜飛雹，蓬屋響珠琲。", "舟子紛相呼，□篙入旁匯。", "罅漏何所避，庶幾無大悔。", "萬鈞寄弱纜，掣斷危可待。", "過午天氣佳，起視江浼浼。", "書生强遊衍，有神司其罪。", "不見少陵翁，蒼溪遺句在。", "我老更可憎，比翁窮十倍。"]'),
('01e0d210-f08e-4aa5-97a0-d26cea0852ba','次韻次尹俊卿梅花絕句  其一','王灼','宋','宋诗','song-poetry','','[]','人間幾桃李，漫漫化泥塵。',24,'全唐诗/poet.song.122000.json','["人間幾桃李，漫漫化泥塵。", "不恨收功晚，新年第一春。"]'),
('a946404e-bb4a-4bf2-a39c-f9c8512db1e6','次韻次尹俊卿梅花絕句  其二','王灼','宋','宋诗','song-poetry','','[]','飯顆從嘲瘦，湘流獨占清。',24,'全唐诗/poet.song.122000.json','["飯顆從嘲瘦，湘流獨占清。", "失身到東閣，聊復對簪纓。"]'),
('dd6ff22b-0ae9-447a-932a-5b1af5b185b1','次韻次尹俊卿梅花絕句  其三','王灼','宋','宋诗','song-poetry','','[]','未學迴風舞，初成拜月粧。',24,'全唐诗/poet.song.122000.json','["未學迴風舞，初成拜月粧。", "故令青女妬，一夕月階霜。"]'),
('a7f1ed25-8822-4378-9a29-1b00473f9773','次韻次尹俊卿梅花絕句  其四','王灼','宋','宋诗','song-poetry','','[]','急霰爭璀璨，僊摽不解寒。',24,'全唐诗/poet.song.122000.json','["急霰爭璀璨，僊摽不解寒。", "漢家趙飛燕，偏許雪中看。"]'),
('e441b0a9-e5b2-491c-abd1-f614726e2f8d','次韻次尹俊卿梅花絕句  其五','王灼','宋','宋诗','song-poetry','','[]','雲澹江臯晚，飛香到短蓬。',24,'全唐诗/poet.song.122000.json','["雲澹江臯晚，飛香到短蓬。", "望窮渾不見，恨滿白蘋風。"]'),
('bf9f0798-877d-4e0a-9216-65e67317295f','次韻次尹俊卿梅花絕句  其六','王灼','宋','宋诗','song-poetry','','[]','袖寒倚脩竹，暗起著人香。',24,'全唐诗/poet.song.122000.json','["袖寒倚脩竹，暗起著人香。", "聯影黄昏月，亭亭上璧璫。"]'),
('4dc576d7-f5cf-42ff-92eb-7b81b5c2be3c','次韻次尹俊卿梅花絕句  其七','王灼','宋','宋诗','song-poetry','','[]','雖無適俗韻，亦有可憐香。',24,'全唐诗/poet.song.122000.json','["雖無適俗韻，亦有可憐香。", "定自嫌朱粉，翻成點點黄。"]'),
('8cf2e8d9-02e8-4413-9da8-39eb52d1c861','次韻次尹俊卿梅花絕句  其八','王灼','宋','宋诗','song-poetry','','[]','墮蕊香猶嫩，空枝影半橫。',24,'全唐诗/poet.song.122000.json','["墮蕊香猶嫩，空枝影半橫。", "江湖無限思，不獨爲蓴羹。"]'),
('8ca3ebe1-fec3-454d-b255-9acb57bef73a','往成都八客餞飲得同字','王灼','宋','宋诗','song-poetry','','[]','鎬京有八士，淮南有八公。',72,'全唐诗/poet.song.122000.json','["鎬京有八士，淮南有八公。", "紛呶一夕醉，緬邈千古同。", "我思錦江曲，駕言涪水東。", "神交設華宴，妙語穆清風。", "合坐燈炯炯，投曉山叢叢。", "別去復何道，勿使酒盃空。"]'),
('a0f458cf-4c53-4ad9-a3b6-b69b46a18655','與諸友遊楊氏池上呼王隱居小飲晚登書臺  其一','王灼','宋','宋诗','song-poetry','','[]','微風度竹氣，澹煙增樹色。',96,'全唐诗/poet.song.122000.json','["微風度竹氣，澹煙增樹色。", "探尋得佳境，灧灧一池碧。", "藻荇紛縱橫，魚蝦時跳擲。", "同遊好事者，喜我有此僻。", "置酒助清賞，環坐藤陰側。", "白鬚比鄰翁，怪語不自惜。", "欲學三盃醉，相付一笑適。", "酒罷循歸途，翁亦返舊宅。"]'),
('a753fcb0-fe9b-435a-bc55-ff11923ad941','與諸友遊楊氏池上呼王隱居小飲晚登書臺  其二','王灼','宋','宋诗','song-poetry','','[]','臺山如招人，突兀城南隅。',96,'全唐诗/poet.song.122000.json','["臺山如招人，突兀城南隅。", "我來有佳興，不辭石磴紆。", "步窮孤絕頂，局局萬丈餘。", "永懷舊刺史，儒冠此研書。", "竟以印綬歸，榮光燭鄉閭。", "世事幾反覆，百年等須臾。", "地閑芳草積，樹暗怪禽呼。", "空留好書名，永與此山俱。"]'),
('6c84ccb7-b53a-4d59-9eb6-0702cb936ceb','山雞送范元通','王灼','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.122000.json','["無正文。"]'),
('1a6ddb70-fb59-4aef-84d5-156f0671f028','送王逸','王灼','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',96,'全唐诗/poet.song.122000.json','["□□□□□，□□□□□。", "□□□□□，□□□□□。", "□□□□□，□□□□□。", "□□□□□，□我離別胸。", "文字子所負，騰踏會有逢。", "勿使豪邁氣，衰颯隨霜蓬。", "或歌歸去來，徒爲白髮翁。", "男兒富事業，高名配華嵩。"]'),
('d5b2e40d-7cef-4200-9c78-a5f320a43387','送雍堯咨遊青城','王灼','宋','宋诗','song-poetry','','[]','曾遊玉壘市，長揖岷山雲。',96,'全唐诗/poet.song.122000.json','["曾遊玉壘市，長揖岷山雲。", "塵緣不暇往，今日翻送君。", "丈人紫霞服，麻姑青練裙。", "鹿車時出遊，俗眼了難分。", "猶聞老人村，鶴髮自耕耘。", "豈無抱德士，可與立奇勳。", "勿求不死藥，自苦骨與筋。", "胡兒正南牧，兩河如聚蚊。"]'),
('1d1af722-5fcf-4abd-9145-9cf0f60e8730','送胡康老  其一','王灼','宋','宋诗','song-poetry','','[]','胡公起三晉，才如山河雄。',120,'全唐诗/poet.song.122000.json','["胡公起三晉，才如山河雄。", "弊裘走上都，氣壓洛與嵩。", "豈無濟時策，入對明光宮。", "戰塵一飄蕩，隻影隨疏蓬。", "虎符靜爲治，使節凜生風。", "所出毫末耳，照眼驚兒童。", "朅來墮閑冷，玉匣藏霜鋒。", "忽買巫峽舟，飄飄指吳中。", "遥知遷擢近，黼座思夔龍。", "他時卧華省，清夢來巴邛。"]'),
('58547e19-a1be-42fd-9244-965b2daaae39','送胡康老  其二','王灼','宋','宋诗','song-poetry','','[]','北人事鞍馬，笑誇太行高。',120,'全唐诗/poet.song.122000.json','["北人事鞍馬，笑誇太行高。", "豈知相風色，孤帆寄江濤。", "雄圖攪方寸，不憚舟師勞。", "一見武功天，騰踏當有遭。", "皇綱餘絲髮，海宇半弓刀。", "誰人念恢復，此事付英髦。", "蓴羹伴鱸膾，酒船載蟹螯。", "何如噉羊酪，春醅潑蒲萄。", "願言雲路穩，勿使閑豹韜。", "功成儻乞身，故園剪蓬蒿。"]'),
('b7d73cd9-c117-47e7-83f7-53711491acb3','送普州守','王灼','宋','宋诗','song-poetry','','[]','寧可鈍如槌，不可曲如鈎。',120,'全唐诗/poet.song.122000.json','["寧可鈍如槌，不可曲如鈎。", "毛銖夸爭奪，所喪乃山丘。", "向誰巧相中，機穽險且幽。", "十年彈指頃，死骨埋荒陬。", "細看天定後，人力豈易謀。", "一洗謗書毒，近鄉仍典州。", "惟此詩書窟，俗比魯與鄒。", "老手亦何事，坐嘯群吏休。", "政成有異等，時至或封侯。", "期公如鐵山，屹立千萬秋。"]'),
('866aacb9-f0b1-4045-b529-73625107d786','用舊韻送普守赴闕  其一','王灼','宋','宋诗','song-poetry','','[]','圜牆閑木索，南畝富鉏鈎。',119,'全唐诗/poet.song.122000.json','["圜牆閑木索，南畝富鉏鈎。", "人謂賢使君，治術本軻丘。", "丹禁頗念遠，白簡頻黜幽。", "那知養手，安坐窮山陬。", "國是久已定，諒非卿士謀。", "除書下八行，仁風被九州。", "自憐登門舊，長裾曳齊鄒。", "送公朝帝所，別語不忍休。", "腰組掛銀黄，刻日賜通侯。", "應記遠宗子，茅簷卧高秋。"]'),
('c949e236-f20f-41d7-963e-04807ca2569f','用舊韻送普守赴闕  其二','王灼','宋','宋诗','song-poetry','','[]','虛名强逐臭，小智矜藏鈎。',120,'全唐诗/poet.song.122000.json','["虛名强逐臭，小智矜藏鈎。", "蠻觸蝸兩角，古今貉一丘。", "念昔齒方壯，抱愁山之幽。", "誓從東南尉，策勳西北陬。", "人事乃大謬，天命不少謀。", "雲梯乏僊骨，車轍半神州。", "廉頗故思趙，韋孟欲徙鄒。", "錦水清堪濯，草堂靚可休。", "儻有一區宅，不願萬戶侯。", "尚及公掛冠，共飽黄雞秋。"]'),
('f96858e6-c80b-4e9b-857c-613395ffcdbc','送何熙載之官鄰山因簡虞并父','王灼','宋','宋诗','song-poetry','','[]','力學收名第，指作青雲梯。',96,'全唐诗/poet.song.122000.json','["力學收名第，指作青雲梯。", "向來杏園伴，盛者直金閨。", "天工亦善戲，淹速乃不齊。", "三年得一尉，初挈孥與妻。", "邑居大山底，積翠蟠東西。", "瘦馬當緩驅，石磴裂馬蹄。", "寄謝循良守，桃李想成蹊。", "行春有餘暇，書尺到耕犁。"]'),
('bc204832-17f5-471a-9b10-4fae4df9b23f','效東坡送顧子敦體送趙子功令資陽','王灼','宋','宋诗','song-poetry','','[]','子功宗室雋，一柱屹蒼蒼。',144,'全唐诗/poet.song.122000.json','["子功宗室雋，一柱屹蒼蒼。", "投身冠蓋窟，所向率披猖。", "宏論震俚耳，百川吸滿觴。", "頗笑中壘尉，豈羨執戟郎。", "胡爲學蠹魚，夢入編簡香。", "作字擬羲獻，賦詩逼齊梁。", "茲行宰劇邑，人謂挾風霜。", "我言百里小，未得施寸長。", "上司督租賦，文檄日一箱。", "捫此空洞腹，餘事皆粃糠。", "耆舊王與董，骨朽神不僵。", "努力肥百姓，二子立道傍。"]'),
('af312ecd-d577-4db1-bd2e-ebbb12075349','同誼夫國才餞季然于普門院取壁間五字詩各探一句爲韻賦五詩某得共飲碧苔畔  其一','王灼','宋','宋诗','song-poetry','','[]','投分前日歡，愴別古人重。',24,'全唐诗/poet.song.122000.json','["投分前日歡，愴別古人重。", "相望一千里，獨許明月共。"]'),
('1d6cb68e-3259-433a-b4be-ccb0f2ec9d55','同誼夫國才餞季然于普門院取壁間五字詩各探一句爲韻賦五詩某得共飲碧苔畔  其二','王灼','宋','宋诗','song-poetry','','[]','滿酌青甆杯，醉卧白石枕。',24,'全唐诗/poet.song.122000.json','["滿酌青甆杯，醉卧白石枕。", "借予驪駒曲，侑我河朔飲。"]'),
('e7f8411e-5ff1-40a3-92f9-3646521129c0','同誼夫國才餞季然于普門院取壁間五字詩各探一句爲韻賦五詩某得共飲碧苔畔  其三','王灼','宋','宋诗','song-poetry','','[]','暑塗勸加餐，養成摩天翮。',24,'全唐诗/poet.song.122000.json','["暑塗勸加餐，養成摩天翮。", "中車寶带黄，小隊油幢碧。"]'),
('817e7338-d566-4b8d-b70b-e456e364c882','同誼夫國才餞季然于普門院取壁間五字詩各探一句爲韻賦五詩某得共飲碧苔畔  其四','王灼','宋','宋诗','song-poetry','','[]','塵榻爲子下，柴扉爲子開。',24,'全唐诗/poet.song.122000.json','["塵榻爲子下，柴扉爲子開。", "從今斷還往，一室長莓苔。"]'),
('a67b0319-b013-4470-a0e7-d00eebd99efd','同誼夫國才餞季然于普門院取壁間五字詩各探一句爲韻賦五詩某得共飲碧苔畔  其五','王灼','宋','宋诗','song-poetry','','[]','來時金蘭集，去日風雨散。',24,'全唐诗/poet.song.122000.json','["來時金蘭集，去日風雨散。", "別語慎勿忘，短書寄澤畔。"]'),
('5e4b364d-65c9-4312-8250-2e881b5276cd','贈瑄上人  其一','王灼','宋','宋诗','song-poetry','','[]','日日登南樓，支頤望西山。',72,'全唐诗/poet.song.122000.json','["日日登南樓，支頤望西山。", "念我知心友，一榻栖孱顔。", "詩如山中雲，婆娑意自閑。", "世無飛僊術，塵步愁躋攀。", "我懶久不出，碧蘚封柴關。", "床頭五字稿，期師一來刪。"]'),
('3268a862-d1a8-45cb-89de-f14e14b25685','贈瑄上人  其二','王灼','宋','宋诗','song-poetry','','[]','諸公爭談詩，健舌秋河傾。',72,'全唐诗/poet.song.122000.json','["諸公爭談詩，健舌秋河傾。", "袖手但兀坐，欲語不敢聲。", "獨喜圓顱師，嗜好與我并。", "相見不言他，古律同細評。", "愛惜丈八矛，徐攻劉長城。", "向人勿浪出，三年戒飛鳴。"]'),
('e3724cd7-83e9-4810-9c6c-cbac163e6ca2','贈瑄上人  其三','王灼','宋','宋诗','song-poetry','','[]','白髮潜庵老，近者焚翰墨。',72,'全唐诗/poet.song.122000.json','["白髮潜庵老，近者焚翰墨。", "長身書臺子，江湖斷信息。", "肥宗與短演，見面應不識。", "桑門減詩侶，熟念氣填臆。", "惟師兩無擇，同我滯鄉國。", "努力事唱酬，異時亦南北。"]'),
('4440ce4d-cfb8-4aa1-b7e9-57cd9dec7c13','送緣庵主','王灼','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','上人久習靜，閉門守一龕。',144,'全唐诗/poet.song.122000.json','["上人久習靜，閉門守一龕。", "猶恐市塵染，西岷撥晴嵐。", "歸來非本心，退結山中庵。", "秋風入我袂，又往天之南。", "南方盛法窟，誓志必窮探。", "雙徑卧老龍，懷珠千丈潭。", "東鄰嘯乳虎，眼光見眈眈。", "禮足受半偈，安坐十年參。", "我昔客吳楚，但愛雲水涵。", "不聞清廟瑟，浪走雪滿簪。", "相逢儻有日，爲我舉二三。", "尺書附巴使，勿語洞庭柑。"]'),
('8717987b-c36c-41a8-a6e6-fe2cec0c87be','送元思師','王灼','宋','宋诗','song-poetry','','[]','思師講法華，眾說積丘墳。',96,'全唐诗/poet.song.122000.json','["思師講法華，眾說積丘墳。", "嘗據師子座，受降千人軍。", "猶嫌文字傳，聖域未策勳。", "欲唱江南曲，試披楚塞雲。", "良才大蔽牛，匠者宜揮斤。", "箭鋒或相直，對面同一欣。", "古人得解脫，乃不厭多聞。", "歸來閱故書，請以道眼分。"]'),
('0a43040b-78cb-4d64-a7e6-9e8ab040ad4f','送智齊師出峽','王灼','宋','宋诗','song-poetry','','[]','齊師成都來，春風掀竹笠。',144,'全唐诗/poet.song.122000.json','["齊師成都來，春風掀竹笠。", "自云十五年，參學事未畢。", "得錢買小舟，湖南尋佛日。", "胸中有此老，如飯不下嗌。", "誓竭牛馬走，往供薪水役。", "儻諧一大事，歸來卧蓬蓽。", "此老吾所聞，機用飛霹靂。", "高提倚天劍，萬里無行迹。", "師欲嬰其鋒，意氣真絕出。", "巫峽柁聲轉，湘江帆影急。", "行矣毋滯淫，坐夏猶可及。", "寄語花藥市，爲我留一席。"]'),
('0802b3c5-398e-49ba-a06f-2069a62293b4','送凝上人成都看藥市','王灼','宋','宋诗','song-poetry','','[]','蜀山富奇藥，野老爭藏收。',120,'全唐诗/poet.song.122000.json','["蜀山富奇藥，野老爭藏收。", "九日來成都，塞斷長儀樓。", "權豪競奪去，萬金未得酬。", "問師杖頭錢，免渠失笑不。", "久通安樂法，况復形骸憂。", "知師不應爾，肆意作嬉遊。", "傳聞不死草，往往落鉏耰。", "我欲前市之，請以道眼搜。", "屑屑治編簡，一室方自囚。", "世塗敗人意，寄語韓伯休。"]'),
('634d82c6-6ece-48c5-aeff-fd6d4bd2ebf7','送性上人','王灼','宋','宋诗','song-poetry','','[]','錦官與子別，六聽秋城砧。',84,'全唐诗/poet.song.122000.json','["錦官與子別，六聽秋城砧。", "坐纏兒女愛，夢繞薝葡林。", "子歸能幾日，又起江湖心。", "江湖多幽寺，老衲天機深。", "一言當有契，超諸去來今。", "孤舟出寒渚，停雲結層陰。", "滯留嗟我老，何以開愁襟。"]'),
('b6ffccdf-9359-46cd-91ff-4805fd7f9046','送譯上人出蜀','王灼','宋','宋诗','song-poetry','','[]','久雨敗沼荷，曉風獵巖桂。',132,'全唐诗/poet.song.122000.json','["久雨敗沼荷，曉風獵巖桂。", "人各動歸思，子獨謀遠逝。", "峽門去來舟，日爲聲利計。", "扣舷數得失，子獨尋師銳。", "徑山天尺五，披光出蒙翳。", "雲居接廬阜，薦福踞鄱汭。", "維此三大老，從之可卒歲。", "玉泉亦清冽，縱飲爭挽袂。", "南極百十城，一一盡所詣。", "寧使繭生足，肯畏雪封砌。", "更憶大瞿曇，捐身求半偈。"]'),
('13e14330-780c-460d-a9df-8154058141de','送楊道者永覺','王灼','宋','宋诗','song-poetry','','[]','久修頭陀行，但欠僧伽衣。',84,'全唐诗/poet.song.122000.json','["久修頭陀行，但欠僧伽衣。", "胡爲走紅塵，涴面不忍揮。", "忽覺東州夢，又指西山歸。", "九峰富泉石，百里環翠微。", "買山吾無錢，亦解守釣磯。", "兒女苦牽挽，此身陷重圍。", "臨分一太息，山中音信稀。"]'),
('d9601280-d65c-4950-a3a8-648f1a323aac','送洪上人遊南','王灼','宋','宋诗','song-poetry','','[]','中原百川赴東西，萬折惟有蜀江耳。',128,'全唐诗/poet.song.122000.json','["中原百川赴東西，萬折惟有蜀江耳。", "師之桑梓江干側，扁舟却訪鴟夷子。", "荆楚吳越我未到，每聞談者亦自喜。", "羨師脫去事幽尋，春風滿帆作行李。", "會稽草木朝霞蔚，錢塘波濤夏雷疾。", "桂樹楓葉怨楚人，蓴羹鹽豉詫吳客。", "到處定知有新得，長篇短韻揮椽筆。", "他時我亦探禹穴，一見名字如促膝。"]'),
('6ca19bf4-5758-4993-a940-32c463f4c927','送南平僧歸里','王灼','宋','宋诗','song-poetry','','[]','牂牁水闊嶲山高，什敖君長曾紛搔。',128,'全唐诗/poet.song.122000.json','["牂牁水闊嶲山高，什敖君長曾紛搔。", "時移事變今安有，百里相望皆城壕。", "我住涪江一區宅，頗恨長安遠如日。", "聞師鄉邑愈更南，不覺掉頭三太息。", "送行且學浮圖語，是身於世真逆旅。", "胸中穩處即吾鄉，交益誇辭空自苦。", "北風拂面寒颼颼，遥知去路雪侵裘。", "忍饑奈凍得嘉句，好在濡筆傳中州。"]'),
('311f1a6d-e23f-4b2e-9d04-b6c1adac901f','送演上人','王灼','宋','宋诗','song-poetry','','[]','整整袈裟團團笠，覆此短小精悍質。',96,'全唐诗/poet.song.122000.json','["整整袈裟團團笠，覆此短小精悍質。", "誰知意氣解摩雲，羞對諸兒戀鄉邑。", "江南蕭寺不知數，據堂說法盡龍虎。", "只應飽取一味禪，斷却從來巧章句。", "晝短天寒無定程，孤舟尚倚裝齎輕。", "玉泉度歲亦良策，好在沙頭春水生。"]'),
('f56fbf13-da05-4655-bdd6-16a63f767c13','送月上人南遊','王灼','宋','宋诗','song-poetry','','[]','錦官東郭大蘭若，眼明見子長廊下。',96,'全唐诗/poet.song.122000.json','["錦官東郭大蘭若，眼明見子長廊下。", "春風二月白帝城，一笑相逢手重把。", "羨子遠引如孤鵠，顧我低摧真病馬。", "碧山紅塵不同調，底事胸懷兩傾寫。", "幽尋勝踐我亦喜，夢魂已落瀟湘野。", "扁舟躡子尚可期，幸有此身閑似社。"]'),
('cc7625d1-6700-434d-b8b8-3e4abb1a55d7','送祖月上人','王灼','宋','宋诗','song-poetry','','[]','月公別我浮三峽，欲往南中求大法。',128,'全唐诗/poet.song.122000.json','["月公別我浮三峽，欲往南中求大法。", "此行初爲梅州老，過嶺障烟恐難狎。", "掛帆且指古鄱陽，驥子鳳鶵亦稱甲。", "十年故人我尚記，平視諸方氣嘗壓。", "玉劍無聲血千里，肯就銅盤後先歃。", "相從學道須究竟，半字落耳汗霑洽。", "宗師語言豈不佳，世間傳寫空盈夾。", "歸來趺坐舉其要，莫話衡廬與苕霅。"]'),
('02026362-4b44-4f94-98d8-6c82931838a8','題趙德脩所藏孫太古尹喜傳道圖','王灼','宋','宋诗','song-poetry','','[]','大柏森森護盤石，老聃踞坐三人立。',128,'全唐诗/poet.song.122000.json','["大柏森森護盤石，老聃踞坐三人立。", "盛德之容本和豫，漠然不應豈真實。", "曏者隱奧九九篇，纔示指畫意已傳。", "細看尹喜磬折處，金篦刮膜見全天。", "侍旁二子來何許，無乃徐甲庚桑楚。", "注目拱手氣不吐，畫師筆端更解語。", "函谷關廢河水黄，授經臺傾隴草荒。", "一幅東絹吾無用，要逐青牛歸帝鄉。"]'),
('ed04338d-8186-4db5-9b2f-0fdfc4b38625','題何朝申所藏趙邈卓饞虎圖','王灼','宋','宋诗','song-poetry','','[]','何日老於菟，失脚來空山。',96,'全唐诗/poet.song.122000.json','["何日老於菟，失脚來空山。", "山中無所食，瘦骨見孱顔。", "舐掌鼓餓舌，始信擇肉艱。", "姑求一飽計，未肯藏榛菅。", "畫師有深趣，粉墨不可刪。", "獸心察兇毒，人事戒防閑。", "編鬚固莫敢，强弓亦徒彎。", "吾命儻足惜，斜陽掩柴關。"]'),
('501822a7-a9ab-4914-a22f-a78c4469921d','題馮申之所藏徐皋魚','王灼','宋','宋诗','song-poetry','','[]','菱葉蘋花點水面，水浄如空到底見。',128,'全唐诗/poet.song.122000.json','["菱葉蘋花點水面，水浄如空到底見。", "大魚獨行示閑暇，小魚群嬉誇敏健。", "畫工定自知魚樂，掉尾揚鰭固多變。", "猶勝圖寫吳王鱠，戕滅眾命供一饌。", "南唐徐白稱絕筆，皋實同姓最後出。", "三幅掛我素壁間，恍然又作江湖客。", "吾聞神物久當化，煩君謹護風雨夕。", "一聲霹靂飛上天，回視丹青了無迹。"]'),
('63722c71-1f02-4779-9055-a59763483d5c','題游昭畫牛四圖  其一','王灼','宋','宋诗','song-poetry','','[]','晴暘布陰來灌木，村童地坐弄鸜鵒。',44,'全唐诗/poet.song.122000.json','["晴暘布陰來灌木，村童地坐弄鸜鵒。", "老牸食豐草，側身顧其犢。", "鳥跦跦，牛逐逐，無人見此春波綠。"]'),
('0d0524ef-0cb2-4ade-a4fb-6a0d131e9c91','題游昭畫牛四圖  其二','王灼','宋','宋诗','song-poetry','','[]','游絲如許長，翠影落橫塘。',60,'全唐诗/poet.song.122000.json','["游絲如許長，翠影落橫塘。", "吳牛最畏暑，賴此五月凉。", "想見下飲時，不念芻菽香。", "摇蕩水生痕，凌亂日浮光。", "可惜蓮與蒲，勿涉水中央。"]'),
('7b3dbca2-bf74-47c3-9b0d-8be58010a33f','題游昭畫牛四圖  其三','王灼','宋','宋诗','song-poetry','','[]','山平皋垅低，秋深雲雨晦。',52,'全唐诗/poet.song.122000.json','["山平皋垅低，秋深雲雨晦。", "牧人荷蓑笠，匍伏在牛背。", "穉牛先跳逸，兩牛追不及。", "安得青天出白日，重來緩驅莫相失。"]'),
('a1fdb9cc-d0f0-4098-a7ae-e40c3e9c755e','題游昭畫牛四圖  其四','王灼','宋','宋诗','song-poetry','','[]','雲蔽天，雪欺樹。',56,'全唐诗/poet.song.122000.json','["雲蔽天，雪欺樹。", "山徑之蹊斷來去，飛花撲面朔風吼。", "兒把牛索藏短袖，擁鼻衝過縮其脰。", "茅蘆咫尺且忍寒，兒歸附火牛繫欄。"]'),
('a286b1ef-d7c2-430a-85d6-f990e81a73b1','題王逸竹溪釣艇圖二絕  其一','王灼','宋','宋诗','song-poetry','','[]','斷岸竹如雲，翠色落寒瀨。',24,'全唐诗/poet.song.122000.json','["斷岸竹如雲，翠色落寒瀨。", "艇子何處歸，應轉煙林外。"]'),
('718e074d-a216-4a95-aa0e-bab6524e15c3','題王逸竹溪釣艇圖二絕  其二','王灼','宋','宋诗','song-poetry','','[]','塘影抱林光，樵風接溪浪。',24,'全唐诗/poet.song.122000.json','["塘影抱林光，樵風接溪浪。", "最愛笋蕨時，恰是河豚上。"]'),
('ab662a58-7f0a-4ba8-a01b-7c66541346e8','題政黄牛出山圖  其一','王灼','宋','宋诗','song-poetry','','[]','眼明雙白鷺，身穩一黄牛。',24,'全唐诗/poet.song.122000.json','["眼明雙白鷺，身穩一黄牛。", "玉轡章臺陌，可憐供百憂。"]'),
('f8bda626-ec39-41ca-9bc6-b97703f22550','題政黄牛出山圖  其二','王灼','宋','宋诗','song-poetry','','[]','橋邊路欲迷，林外山猶見。',24,'全唐诗/poet.song.122000.json','["橋邊路欲迷，林外山猶見。", "長歌扣牛角，不讀項羽傳。"]'),
('4f7d87de-4520-4883-b1d5-4b508c4e71ad','題十二溪女圖','王灼','宋','宋诗','song-poetry','','[]','霞珮綴仙班，春風擁髻鬟。',24,'全唐诗/poet.song.122000.json','["霞珮綴仙班，春風擁髻鬟。", "應無世間夢，悵望碧溪灣。"]'),
('8eaa0fd8-8900-41a8-a085-dd1772117797','題昭君圖','王灼','宋','宋诗','song-poetry','','[]','朔風吹鬢影，猶抱琵琶立。',24,'全唐诗/poet.song.122000.json','["朔風吹鬢影，猶抱琵琶立。", "胡兒在何許，邊頭羽書急。"]'),
('f7f192df-330a-49ff-99a7-277306b338bd','題滿公所作陰壑生虛籟','王灼','宋','宋诗','song-poetry','','[]','積霧瑣空巖，寒飚振疏木。',24,'全唐诗/poet.song.122000.json','["積霧瑣空巖，寒飚振疏木。", "遊子勿言歸，山程太幽獨。"]'),
('f6e515fa-3901-4897-a5ca-923b0a94d661','題滿公所作月林散清影','王灼','宋','宋诗','song-poetry','','[]','暝色兼荒遠，初分浦淑煙。',24,'全唐诗/poet.song.122000.json','["暝色兼荒遠，初分浦淑煙。", "應知漢江珮，月竹鬭娟娟。"]'),
('a11da19f-fcca-43bd-89b1-8c4a7c7c2256','題榮首座巴東三峽圖','王灼','宋','宋诗','song-poetry','','[]','白帝城高鼓角罷，巫娥廟冷雲雨空。',32,'全唐诗/poet.song.122000.json','["白帝城高鼓角罷，巫娥廟冷雲雨空。", "只知楚塞明雙眼，不覺神遊尺素中。"]'),
('c5ace863-81f3-479f-9abb-bf98393c582a','題李伯時渭城送客圖用知幾韻','王灼','宋','宋诗','song-poetry','','[]','龍眠幻出摩詰句，想見落筆懷抱空。',32,'全唐诗/poet.song.122000.json','["龍眠幻出摩詰句，想見落筆懷抱空。", "只有古今情不盡，渭城楊柳幾春風。"]'),
('4699faf1-9752-4a28-be5e-edc51b9ca652','題雲月圖  其一','王灼','宋','宋诗','song-poetry','','[]','萬里峨眉夜夜月，千秋巫峽朝朝雲。',32,'全唐诗/poet.song.122000.json','["萬里峨眉夜夜月，千秋巫峽朝朝雲。", "詩句丹青共摹寫，筆端三昧要平分。"]'),
('7e6d585d-f3c9-42bb-aec5-813cd3d5f66b','題雲月圖  其二','王灼','宋','宋诗','song-poetry','','[]','菩薩巖前浄滿月，神女峰上光明雲。',32,'全唐诗/poet.song.122000.json','["菩薩巖前浄滿月，神女峰上光明雲。", "吾人肺腑中流出，詩句丹青無半分。"]'),
('e55a7a6e-9cf3-407d-bbe7-6276016540d3','題南禪方丈壁','王灼','宋','宋诗','song-poetry','','[]','南金楚璞何施爲，出門即取厚利歸。',63,'全唐诗/poet.song.122000.json','["南金楚璞何施爲，出門即取厚利歸。", "古來乃有金玉士，抱冤硉兀人不知。", "君不見呂侯大狩誇凌鑠，車前打折麒麟角。", "徑須歸去來，一丘與一壑。"]'),
('8fafdc4d-4a27-46c9-8a9e-2234b9aea803','題樊氏樓壁','王灼','宋','宋诗','song-poetry','','[]','老秋氣已嚴，今日稍晴和。',96,'全唐诗/poet.song.122000.json','["老秋氣已嚴，今日稍晴和。", "登君樓西翼，相對一酣歌。", "邊烽照仙關，大將方枕戈。", "吾儕無志用，心懾鬢先皤。", "强促半罇綠，各自爭岌峨。", "月影漸髣髴，西山爽氣多。", "坐興兒女念，欲往山之阿。", "諸君祈努力，吾亦假餘波。"]'),
('4f417798-cb44-4faa-a0f2-5529cb0734c6','無題','王灼','宋','宋诗','song-poetry','','[]','桐孫枝有海潮音，玉指初調萬籟沉。',32,'全唐诗/poet.song.122000.json','["桐孫枝有海潮音，玉指初調萬籟沉。", "燭影熒熒鎖窗底，此時端欲見琴心。"]'),
('ff23a163-aa2d-40f8-a03d-d32d711ea657','送祖道師赴長江','王灼','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山林與城市，何地非隱淪。',48,'全唐诗/poet.song.122000.json','["山林與城市，何地非隱淪。", "子意亦易敗，徑投寂寞濱。", "楞嚴有奧章，試爲識者陳。", "歸思落煙艇，尚及秋風新。"]'),
('37890217-3684-4ce9-8f5b-85d2bf016b8b','次韻大受登正法塔見劉王二陵','王灼','宋','宋诗','song-poetry','','[]','試縱浮圖目，閑紓客子情。',120,'全唐诗/poet.song.122000.json','["試縱浮圖目，閑紓客子情。", "軒騰超世界，指點識鄉程。", "天大雲欹野，江蒸氣抱城。", "長風饒振薄，落日倒光晶。", "古色千年在，悲歌百慮盈。", "戰爭初自苦，成敗幾堪驚。", "狐兔穿蓬顆，珠璣入里氓。", "劍關猶北向，巫峽只東傾。", "往意增三嘆，餘蹤付一瞠。", "誓言逃俗網，碧海跨飛鯨。"]'),
('aaebac75-169e-4cea-b58f-358342df6bc4','次尹俊卿見訪有詩次韻','王灼','宋','宋诗','song-poetry','','[]','聯驂來二妙，契好屬兒孫。',48,'全唐诗/poet.song.122000.json','["聯驂來二妙，契好屬兒孫。", "夜半星河轉，談深几席溫。", "能詩飯顆瘦，使酒濮陽髡。", "萬事醉吟裏，那須倚市門。"]'),
('5556f187-b29e-4e5e-b5d6-c44ec26667a1','次尹彥回復來偶予他出用前韻招彥回','王灼','宋','宋诗','song-poetry','','[]','往時傾蓋友，前代湧泉孫。',48,'全唐诗/poet.song.122000.json','["往時傾蓋友，前代湧泉孫。", "肯念三年別，能來一語溫。", "歲華欺老大，功業付鯨髡。", "直爲詩篇好，扶藜日候門。"]'),
('c2daf175-c189-440a-ac3a-9318fdcde360','東禪別新資官令榮安中走筆次韻','王灼','宋','宋诗','song-poetry','','[]','雖念三年別，猶欣一日逢。',48,'全唐诗/poet.song.122000.json','["雖念三年別，猶欣一日逢。", "哦詩能淡佇，作邑想雍容。", "古柏宜秋雨，寒鴉伴曉鐘。", "歸塗莫惆悵，喜事見重重。"]'),
('5a514736-c7d8-40be-84ca-798284c43775','次韻李知幾','王灼','宋','宋诗','song-poetry','','[]','密雨連三日，青天未肯開。',48,'全唐诗/poet.song.122000.json','["密雨連三日，青天未肯開。", "庭除舞蚯蚓，几席上莓苔。", "又說邊聲急，渾無鄉信來。", "愁心似流水，空費寶刀裁。"]'),
('c1505d04-8dce-4cee-b445-d9b81d55403b','醉中走筆次趙彥和韻','王灼','宋','宋诗','song-poetry','','[]','三年相爾汝，一語敢誰何。',48,'全唐诗/poet.song.122000.json','["三年相爾汝，一語敢誰何。", "有學窺黄老，無心戰外魔。", "牛心應易噉，螭首故難磨。", "不識王孫貴，朱門亦許過。"]'),
('12266aac-6652-4749-9d30-a67b4d05b526','拾諸公餘韻贈輝禪師兼奉答勾龍伯秋謁廣利輝禪師  其一','王灼','宋','宋诗','song-poetry','','[]','引泉澆藥圃，編竹護花科。',48,'全唐诗/poet.song.122000.json','["引泉澆藥圃，編竹護花科。", "頓喜高風在，仍聞密義多。", "四山圍翠黛，一水繚青羅。", "誰謂幽師死，來看窣堵波。"]'),
('2c29fbe8-f229-4e16-be91-f5b1318cb087','拾諸公餘韻贈輝禪師兼奉答勾龍伯秋謁廣利輝禪師  其二','王灼','宋','宋诗','song-poetry','','[]','舊飾蓮花座，新繙貝葉科。',48,'全唐诗/poet.song.122000.json','["舊飾蓮花座，新繙貝葉科。", "朝餐葷味少，夜誦篆煙多。", "不執鐵如意，肯偷金叵羅。", "猶堪試綿力，法海激頹波。"]'),
('c8ddc22a-bfcb-4742-9524-1c3389f44592','奉伯秋','王灼','宋','宋诗','song-poetry','','[]','要憑稽古力，尚阻列僊科。',48,'全唐诗/poet.song.122000.json','["要憑稽古力，尚阻列僊科。", "富貴終愁逼，才名已患多。", "廟堂遵故事，經學到新羅。", "拭眼看收拾，天池濯素波。"]'),
('5ca9bdff-61d3-487e-8111-5cc638650ecc','答伯秋  其一','王灼','宋','宋诗','song-poetry','','[]','足爲春遊繭，頭因午醉科。',48,'全唐诗/poet.song.122000.json','["足爲春遊繭，頭因午醉科。", "神交嘗恨少，詩債敢嫌多。", "幾日登廬阜，他年夢苧羅。", "故應三峽外，漁艇老煙波。"]'),
('0f83fa92-8366-4911-9934-d341d5439dda','答伯秋  其二','王灼','宋','宋诗','song-poetry','','[]','芻蕘傳吉語，詔旨緩追科。',48,'全唐诗/poet.song.122000.json','["芻蕘傳吉語，詔旨緩追科。", "疲俗今當復，諸公眾所多。", "誰能齊卓茂，我亦怖閻羅。", "種德無餘事，流光付逝波。"]'),
('edb22173-2f22-491a-997c-38d15ac84d74','答伯秋  其三','王灼','宋','宋诗','song-poetry','','[]','半生沉俗學，中路墮嚴科。',48,'全唐诗/poet.song.122000.json','["半生沉俗學，中路墮嚴科。", "白眼遭非類，黄泉愧阿多。", "無勳封柱國，有志捽何羅。", "慎勿相料理，因風又起波。"]'),
('e3a270d4-b532-4111-a580-2e951a978b2a','又和  其一','王灼','宋','宋诗','song-poetry','','[]','性癖耽杯酒，家貧廢臼科。',48,'全唐诗/poet.song.122000.json','["性癖耽杯酒，家貧廢臼科。", "江山聊作助，崔蔡不須多。", "早歲撐吳榜，春風試越羅。", "只今中夜夢，突怒見潮波。"]'),
('e43526d1-4034-4519-b151-94357462f9cd','又和  其二','王灼','宋','宋诗','song-poetry','','[]','風來雲度屋，雨過水盈科。',48,'全唐诗/poet.song.122000.json','["風來雲度屋，雨過水盈科。", "懶覺詩篇少，閑看景趣多。", "垣間生薜荔，床下長娑羅。", "空法銷諸漏，端如迦葉波。"]'),
('f0505f2e-982e-4b0a-bd83-32eba299bfc0','又和  其三','王灼','宋','宋诗','song-poetry','','[]','可惜通三語，相期中六科。',48,'全唐诗/poet.song.122000.json','["可惜通三語，相期中六科。", "南司章奏好，北闕縉紳多。", "想見趨宣室，真成上鬰羅。", "行裝宜速具，未用歎奔波。"]'),
('e9afe3e5-b6ff-4f5c-9db4-794d4d0abbfb','又和  其四','王灼','宋','宋诗','song-poetry','','[]','從軍思上策，直諫赴賢科。',48,'全唐诗/poet.song.122000.json','["從軍思上策，直諫赴賢科。", "抗志吾何敢，收功眾孰多。", "清詩無競病，小令有來羅。", "今日奇寒甚，明窗試偃波。"]'),
('7319a15d-4d50-4a12-a31a-5c09234d4291','次韻何子應遊金壁池  其一','王灼','宋','宋诗','song-poetry','','[]','柳樹濃垂岸，荷花滿覆塘。',48,'全唐诗/poet.song.122000.json','["柳樹濃垂岸，荷花滿覆塘。", "日供無限影，風遞自然香。", "酒艷浮瑶席，歌聲繞杏梁。", "空慚長卿病，不作次公狂。"]'),
('e51194fd-b056-4109-8226-13e504c65c4d','次韻何子應遊金壁池  其二','王灼','宋','宋诗','song-poetry','','[]','景色遽如許，歡聲阿那邊。',48,'全唐诗/poet.song.122000.json','["景色遽如許，歡聲阿那邊。", "綺羅沽酒市，絲竹泛花船。", "越客知何夕，壺公自有天。", "茲遊傾澤國，寧問壓巴川。"]'),
('cc1b0729-764c-4aa1-abb5-ab0be28f5b6a','次韻子應同遊靈泉','王灼','宋','宋诗','song-poetry','','[]','香火尋幽寺，麾幢度廣川。',48,'全唐诗/poet.song.122000.json','["香火尋幽寺，麾幢度廣川。", "塢深斜透日，溪涸細流泉。", "玉粒新炊飯，金花側布田。", "歸塗動詩興，健筆寫江天。"]'),
('1f1720dc-3099-4e16-a294-f107d9d2ef7d','次韻子應遊鶴鳴','王灼','宋','宋诗','song-poetry','','[]','夕雨方開霽，晨雞亦罷鳴。',48,'全唐诗/poet.song.122000.json','["夕雨方開霽，晨雞亦罷鳴。", "四郊知按堵，千騎得徐行。", "再閱天章麗，還同佛日明。", "抽毫出佳句，壓倒謝宣城。"]'),
('71b731a3-f232-40d5-84ed-e94ec6eddc56','次韻李士舉丈除夕  其一','王灼','宋','宋诗','song-poetry','','[]','藜杖初防老，桃符又換新。',48,'全唐诗/poet.song.122000.json','["藜杖初防老，桃符又換新。", "驚回潼水夢，喜見義城春。", "浪走何爲者，流光豈貸人。", "翻思大儺氏，闊步過天津。"]'),
('0485cba2-811e-4077-8dd7-542d95f59cfc','次韻李士舉丈除夕  其二','王灼','宋','宋诗','song-poetry','','[]','兒孫思故國，詩酒送窮年。',48,'全唐诗/poet.song.122000.json','["兒孫思故國，詩酒送窮年。", "祿近禾三百，人慚員半千。", "壯心非曩昔，尊足幸輕便。", "投曉椒觴盡，春風共醉顛。"]'),
('5962e896-824e-4c85-be86-016a0c1fad88','次韻李士舉丈除夕  其三','王灼','宋','宋诗','song-poetry','','[]','暗燈延鼠輩，殘漏付雞人。',48,'全唐诗/poet.song.122000.json','["暗燈延鼠輩，殘漏付雞人。", "柏酒浮三酌，蔬盤薦五辛。", "凍吟多累句，孤坐絕來賓。", "鏡裏絲絲髮，平明六十春。"]'),
('5e4fd679-5e33-44d5-b773-0f65fabab7c6','次韻呂閬州錦屏之集','王灼','宋','宋诗','song-poetry','','[]','飛簷依絕巘，朱檻俯清流。',48,'全唐诗/poet.song.122000.json','["飛簷依絕巘，朱檻俯清流。", "劍外誰堪似，城南獨占優。", "濃春牽酒興，勝踐與詩謀。", "日落江煙起，旌麾更少留。"]'),
('ec1e91f4-838e-47be-9fc1-758966e2ccad','次韻答張廼直','王灼','宋','宋诗','song-poetry','','[]','才如北海豈云疏，局促從來笑腐儒。',64,'全唐诗/poet.song.122000.json','["才如北海豈云疏，局促從來笑腐儒。", "衹作文章希屈馬，不將門戶敵崔盧。", "公車奏議三千牘，京洛風塵十二衢。", "回首知君幾多恨，肯甘華髮老江湖。"]'),
('0fce5472-8380-45ff-ae8b-243068cf6017','次韻許唐臣丈','王灼','宋','宋诗','song-poetry','','[]','目斷揚州淚似江，龍輿半夜狩南邦。',64,'全唐诗/poet.song.122000.json','["目斷揚州淚似江，龍輿半夜狩南邦。", "徒聞四野方多壘，可惜黄旗漫繞杠。", "濁酒有神磨歲月，愁山無賴入軒窗。", "青萍三尺將生鏽，憤氣崢嶸只自降。"]'),
('96d50f06-2d56-4870-9a10-4af722f4dad8','次韻任元受除夕','王灼','宋','宋诗','song-poetry','','[]','九重無路扣天閽，萬里何時返蓽門。',64,'全唐诗/poet.song.122000.json','["九重無路扣天閽，萬里何時返蓽門。", "歲晚濃愁催白髮，夜來隻影落寒罇。", "誰令興發水雲國，獨憶春歸花柳村。", "知有筆端三昧力，試將些語爲招魂。"]'),
('1308a3bd-3c90-4185-a0c4-4ecad7bfc29a','次韻答趙之源仍簡演師','王灼','宋','宋诗','song-poetry','','[]','年年春事寄征鞍，一笑歸來已强顔。',64,'全唐诗/poet.song.122000.json','["年年春事寄征鞍，一笑歸來已强顔。", "但得從今千日醉，寧論自古四并難。", "憐君不怕憑烏几，顧我猶知愛碧山。", "應許相携學寒拾，同參饒舌老豐干。"]'),
('bb786b94-cdeb-408e-8681-ea62fac2e370','次韻諸公贈將官鹿浩然','王灼','宋','宋诗','song-poetry','','[]','休把長纓便請行，如今正屬泰階平。',64,'全唐诗/poet.song.122000.json','["休把長纓便請行，如今正屬泰階平。", "醉看夜月清罇倒，卧對秋風白髮生。", "羞向熱官稱命薄，喜隨寒士以詩鳴。", "他年採藥鹿門去，不許人間知姓名。"]'),
('39bf5955-40b0-4a92-a1ed-acc6e301310b','次韻馮舜陟見贈','王灼','宋','宋诗','song-poetry','','[]','梁山回首幾悲辛，來對江城拂塞塵。',64,'全唐诗/poet.song.122000.json','["梁山回首幾悲辛，來對江城拂塞塵。", "枕麴漱醪真下策，推書撲筆更癡人。", "如君自是聲華舊，及我相逢笑語新。", "便倒詩筒費褒飾，坐知摇落變青春。"]'),
('1cc8a58e-2776-41c3-a7d0-4f4a98c3520a','次韻趙當可','王灼','宋','宋诗','song-poetry','','[]','元禮門牆豈敢疏，擬題刺字拂塵裾。',64,'全唐诗/poet.song.122000.json','["元禮門牆豈敢疏，擬題刺字拂塵裾。", "頹顔此去歌無奈，聞道從來恨不如。", "食蛤未妨期汗漫，椎蘆或可作蘧蒢。", "西園飛蓋成何事，要見枕中鴻寶書。"]'),
('7b9127d3-ad09-4e5c-a94c-07e315df4124','次韻顧次鳳','王灼','宋','宋诗','song-poetry','','[]','筆端文字照千春，僊籍班聯透幾塵。',64,'全唐诗/poet.song.122000.json','["筆端文字照千春，僊籍班聯透幾塵。", "黄卷肯交同長物，白袍未信裹閑身。", "至言落落常難合，俗眼悠悠少識真。", "誰似江東顧夫子，月臺對影只三人。"]'),
('f75cc2a1-734e-4625-941c-1eedd4bf7df6','和唐山叟所贈三詩  其一','王灼','宋','宋诗','song-poetry','','[]','人品相懸定幾分，十年高卧赤城雲。',64,'全唐诗/poet.song.122000.json','["人品相懸定幾分，十年高卧赤城雲。", "神仙窟宅古多見，泉石膏肓今亦云。", "羽駕擬陪天上樂，麟毫猶寫世間文。", "吳江楓落摇歸棹，更喜新詩愜所聞。"]'),
('c87280b7-2997-46b6-9f3f-b058999f22e8','和唐山叟所贈三詩  其二','王灼','宋','宋诗','song-poetry','','[]','蓑衣芒屨日相逢，仙者誰人識呂鍾。',64,'全唐诗/poet.song.122000.json','["蓑衣芒屨日相逢，仙者誰人識呂鍾。", "已受丹書存夜氣，定除白髮變春容。", "情田舊習雖鋤穢，筆陣餘威尚折衝。", "聞說山間賦招隱，試披雲霧幾多重。"]'),
('7a58b906-9b28-4403-80a1-f1019b994533','和唐山叟所贈三詩  其三','王灼','宋','宋诗','song-poetry','','[]','徧從江海濯清流，歸老岷峨占上游。',64,'全唐诗/poet.song.122000.json','["徧從江海濯清流，歸老岷峨占上游。", "心遠欲聯高士傳，地偏仍似賈胡留。", "何時竹杖閑搘壁，終日繩床懶命儔。", "碧嶂紅塵兩相望，勞生笑我不知休。"]'),
('2e8b6da1-50d7-43bf-a604-322d1bc46dd4','次韻米太初','王灼','宋','宋诗','song-poetry','','[]','元知文采冠多邦，牀下如今拜老龐。',64,'全唐诗/poet.song.122000.json','["元知文采冠多邦，牀下如今拜老龐。", "短刃何能排賈壘，輕舠敢問絕潘江。", "初聞毛穎衹供笑，退誦溪堂但乞降。", "誰擬一臺稱二妙，如公才氣本無雙。"]'),
('95c57a76-258d-4ed9-9af4-4766d7139f35','和榮安中二絕  其一','王灼','宋','宋诗','song-poetry','','[]','射洪春酒舊知名，更得新詩意已傾。',32,'全唐诗/poet.song.122000.json','["射洪春酒舊知名，更得新詩意已傾。", "獨與劉伶敦契好，山王不敢豈人情。"]'),
('ccab2979-2c6b-45ca-b779-b8ab67223604','和榮安中二絕  其二','王灼','宋','宋诗','song-poetry','','[]','醉來不入少年場，只欲問塗何有鄉。',32,'全唐诗/poet.song.122000.json','["醉來不入少年場，只欲問塗何有鄉。", "耽酒玉川貧徹骨，空將鼻觀到糟床。"]'),
('8d4a1735-ad7d-4b43-9fee-2dbe6d2b7d9f','次昭覺圓老韻','王灼','宋','宋诗','song-poetry','','[]','丈室曾窺金錫光，汾陽宗緒故應長。',32,'全唐诗/poet.song.122000.json','["丈室曾窺金錫光，汾陽宗緒故應長。", "不嫌俗子堪傳授，更借餘波到樂浪。"]'),
('98873630-e84c-4bec-b7c3-dc31156565a3','次韻日新見招','王灼','宋','宋诗','song-poetry','','[]','聞道山中熟臘醅，懸知甕面喚春回。',32,'全唐诗/poet.song.122000.json','["聞道山中熟臘醅，懸知甕面喚春回。", "桃花亦解相勾引，前度劉郎擬獨來。"]'),
('7eea4b21-d88d-4a3e-a230-6144f647dfda','次韻師渾甫  其一','王灼','宋','宋诗','song-poetry','','[]','五字長城久讓登，雲梯更羨最高層。',32,'全唐诗/poet.song.122000.json','["五字長城久讓登，雲梯更羨最高層。", "別來大有離群恨，今日西南又得朋。"]'),
('2c765906-b5af-4a4e-ae6e-3fb0ba498948','次韻師渾甫  其二','王灼','宋','宋诗','song-poetry','','[]','春愁早覺費驅除，清酒何人贈百壺。',32,'全唐诗/poet.song.122000.json','["春愁早覺費驅除，清酒何人贈百壺。", "投老殘年無處著，只堪脫帽見霜顱。"]'),
('9f95fc5a-c116-464c-bf5c-f44a977c74d7','次韻何子應留詩爲別  其一','王灼','宋','宋诗','song-poetry','','[]','追攀筆墨幸同時，蘇季如今不願師。',32,'全唐诗/poet.song.122000.json','["追攀筆墨幸同時，蘇季如今不願師。", "自詫柳州曾指授，年來稍稍許言詩。"]'),
('a808a829-dee1-4cf1-9ae9-3e48ffe1f14b','次韻何子應留詩爲別  其二','王灼','宋','宋诗','song-poetry','','[]','周南底事苦淹留，盃水那容萬斛舟。',32,'全唐诗/poet.song.122000.json','["周南底事苦淹留，盃水那容萬斛舟。", "穩駕長風歸去好，鳳凰池上醉遨遊。"]'),
('24c05856-d410-42a5-8280-7442d28da9cd','次韻何子應留詩爲別  其三','王灼','宋','宋诗','song-poetry','','[]','邇迹韓門尚壯年，老陪杖屨本因緣。',32,'全唐诗/poet.song.122000.json','["邇迹韓門尚壯年，老陪杖屨本因緣。", "早知决定書青史，湜籍諸人繼有傳。"]'),
('96328233-8549-4370-b21f-4f51f9a3cfb4','次韻何子應留詩爲別  其四','王灼','宋','宋诗','song-poetry','','[]','出頭自合持文柄，失脚因循作吏師。',32,'全唐诗/poet.song.122000.json','["出頭自合持文柄，失脚因循作吏師。", "記取舂陵好邦伯，臨風對月有清詩。"]'),
('4e5c279b-a735-4eaa-ba26-9da9203bfed2','次韻何子應留詩爲別  其五','王灼','宋','宋诗','song-poetry','','[]','主領風光春復秋，西山蠟屐北池舟。',32,'全唐诗/poet.song.122000.json','["主領風光春復秋，西山蠟屐北池舟。", "羲皇以上同真樂，俯仰之間憶舊遊。"]'),
('9f6b260d-967b-449e-98ab-d4581d197cbe','次韻何子應留詩爲別  其六','王灼','宋','宋诗','song-poetry','','[]','蘭若生祠付百年，曾將秀筆紀夤緣。',32,'全唐诗/poet.song.122000.json','["蘭若生祠付百年，曾將秀筆紀夤緣。", "涪江口口歌遺愛，碑版懸知四裔傳。"]'),
('2b7caa42-d965-44f0-93f8-5df16a016747','次韻晁子與  其一','王灼','宋','宋诗','song-poetry','','[]','清谿西岸作鶉居，敢怨投閑百不如。',32,'全唐诗/poet.song.122000.json','["清谿西岸作鶉居，敢怨投閑百不如。", "喜得君家好兄弟，相逢如對古人書。"]'),
('7b83cfec-72e1-4c76-a020-6fcb652ce629','次韻晁子與  其二','王灼','宋','宋诗','song-poetry','','[]','長貧我欲爲巴叟，高詠君能繼洛生。',32,'全唐诗/poet.song.122000.json','["長貧我欲爲巴叟，高詠君能繼洛生。", "自許一丘成小隱，仰瞻千載立脩名。"]'),
('ddccc1b2-c0aa-42b9-97d3-3133bcf80578','次韻晁子與  其三','王灼','宋','宋诗','song-poetry','','[]','大晁富麗比南金，令弟清新敵楚琳。',32,'全唐诗/poet.song.122000.json','["大晁富麗比南金，令弟清新敵楚琳。", "死却廬陵老居士，二蘇那得有知音。"]'),
('6788f305-3632-4774-9ac7-56ba64b69a7d','次韻晁子與  其四','王灼','宋','宋诗','song-poetry','','[]','韓門今日有真傳，興起斯文四百年。',32,'全唐诗/poet.song.122000.json','["韓門今日有真傳，興起斯文四百年。", "可惜飛龍卧荒櫪，閑看翠翮落虛弦。"]'),
('84c7ee0b-40d4-4e89-bf7d-5b6ed82a59ab','次韻晁子與  其五','王灼','宋','宋诗','song-poetry','','[]','新詩字字救朝饑，仁義之言反類癡。',32,'全唐诗/poet.song.122000.json','["新詩字字救朝饑，仁義之言反類癡。", "誰辦千金收駿骨，大勝列屋養蛾眉。"]'),
('cb3bd2a0-837a-4de0-95c9-ccd40f9a1467','再次韻  其一','王灼','宋','宋诗','song-poetry','','[]','岷江劍棧總寧居，聞道邊頭亦晏如。',32,'全唐诗/poet.song.122000.json','["岷江劍棧總寧居，聞道邊頭亦晏如。", "猛士雲屯方賈勇，胡兒莫送講和書。"]'),
('8182f1b8-4351-4217-b4f2-8add90c5b559','再次韻  其二','王灼','宋','宋诗','song-poetry','','[]','筑壇拜將一軍驚，初識淮陰胯下生。',32,'全唐诗/poet.song.122000.json','["筑壇拜將一軍驚，初識淮陰胯下生。", "能讀父書成底事，可憐世上逐虛名。"]'),
('b0c601e6-506e-40f8-8575-4812cce38ebc','再次韻  其三','王灼','宋','宋诗','song-poetry','','[]','懶擲粗疏地上金，絕知環珮響璆琳。',32,'全唐诗/poet.song.122000.json','["懶擲粗疏地上金，絕知環珮響璆琳。", "歌功頌德今時事，側聽諸公出正音。"]'),
('4328c87a-4704-4a9c-9398-e74469df274f','再次韻  其四','王灼','宋','宋诗','song-poetry','','[]','佛貍已死北人傳，虜馬飲江謠故年。',32,'全唐诗/poet.song.122000.json','["佛貍已死北人傳，虜馬飲江謠故年。", "只有昭君怨青塚，他時心事付鵾弦。"]'),
('a9891471-f937-4386-9e99-6ef64fb2274e','再次韻  其五','王灼','宋','宋诗','song-poetry','','[]','欲細腰圍强忍饑，早知作計太憨癡。',32,'全唐诗/poet.song.122000.json','["欲細腰圍强忍饑，早知作計太憨癡。", "從今百斛收螺黛，學取風流半額眉。"]'),
('2926f4f5-65dc-4507-b8b1-496b668cdced','遊靈泉次性老韻','王灼','宋','宋诗','song-poetry','','[]','盞裏濁醪無宿釀，缾中脫粟有孤炊。',32,'全唐诗/poet.song.122000.json','["盞裏濁醪無宿釀，缾中脫粟有孤炊。", "忍貧不徹來投佛，坐聽松風無限時。"]'),
('c4a1d472-3fee-4eaf-a680-31e3a20893d8','趙和之自鶴鳴泛舟歸城次韻','王灼','宋','宋诗','song-poetry','','[]','斜日撩歸興，飄然李郭舟。',48,'全唐诗/poet.song.122000.json','["斜日撩歸興，飄然李郭舟。", "旄麾明兩岸，管吹落滄洲。", "要與民行樂，那須酒換愁。", "遥知陶靖節，臨賦喜清流。"]'),
('f97d53f4-7cfc-4a30-8e32-f59a1fc04660','趙成甫招飯次默夫韻','王灼','宋','宋诗','song-poetry','','[]','鳥聲呼客急，花影過簾遲。',48,'全唐诗/poet.song.122000.json','["鳥聲呼客急，花影過簾遲。", "酒灧東西玉，枰殘白黑棋。", "稍驚風弄袖，真恐雨催詩。", "一笑留歸騎，斜陽無限時。"]'),
('8cf6e55b-9262-4f4e-9b7c-903dfd2a95f9','答戴時行  其一','王灼','宋','宋诗','song-poetry','','[]','如今四十已知非，誓學宗門第一機。',32,'全唐诗/poet.song.122000.json','["如今四十已知非，誓學宗門第一機。", "養就純乾猶細事，直須空劫問音威。"]'),
('546c431c-716a-456a-aac4-6375e5af06e6','答戴時行  其二','王灼','宋','宋诗','song-poetry','','[]','佛祖由來命脈通，大千世界一光中。',32,'全唐诗/poet.song.122000.json','["佛祖由來命脈通，大千世界一光中。", "藥王菩薩知君是，乞取刀圭救病翁。"]'),
('f833a62d-1980-4ef8-887f-35ca2417fed1','答李知幾','王灼','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.122000.json','["無正文。"]'),
('cdc0daa9-949e-4069-a2f0-f2408fbc6f36','投秦太師  其一','王灼','宋','宋诗','song-poetry','','[]','雙龍闕下五雲新，喜見天元第一春。',64,'全唐诗/poet.song.122000.json','["雙龍闕下五雲新，喜見天元第一春。", "鄰使來輸朝會玉，儒宮望拜屬車塵。", "囊空赤白閑邊將，雨足公私快野人。", "渾是昇平好時節，誰將盛事勒蒼珉。"]'),
('45c03629-71f2-491e-bcd0-2139b7f83474','投秦太師  其二','王灼','宋','宋诗','song-poetry','','[]','今代堂堂有魏公，十方三際指揮中。',64,'全唐诗/poet.song.122000.json','["今代堂堂有魏公，十方三際指揮中。", "勳名已恨古人隘，歌詠端知寸筆窮。", "還第文饒槐蔽日，賭棋安石馬嘶風。", "此時誰作登門客，看吐經綸氣似虹。"]'),
('29be9be2-2883-4f3a-badf-50677b09c1b9','投秦太師  其三','王灼','宋','宋诗','song-poetry','','[]','相府潭潭接斗魁，門披戟带絕纖埃。',64,'全唐诗/poet.song.122000.json','["相府潭潭接斗魁，門披戟带絕纖埃。", "小山叢桂何由識，東閣長裾許暫陪。", "繞木驚烏棲未定，戀軒疲馬望重來。", "酬恩有膽大如斗，造化爐中肯鑄回。"]'),
('3cc7662b-8b70-4377-b80b-2cfd6984151a','投秦太師  其四','王灼','宋','宋诗','song-poetry','','[]','三徑荒蕪釣艇閑，中興冠蓋擬躋攀。',64,'全唐诗/poet.song.122000.json','["三徑荒蕪釣艇閑，中興冠蓋擬躋攀。", "有文數過金閨彥，無籍堪聯玉笋班。", "斷遣鄉愁歸魯酒，安排客服上吳山。", "相門賓帟多珠履，自笑風埃蹭蹬間。"]'),
('6c6fafa6-3385-4162-89bb-52270cf9cb0c','長孺幼安作西湖之遊不以告某與元受明日二公有詩元受率次韻','王灼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿城撲面戰黄塵，蠟屐故尋湖上春。',64,'全唐诗/poet.song.122000.json','["滿城撲面戰黄塵，蠟屐故尋湖上春。", "千頃煙波初弄日，四年魚鳥恰知人。", "有時覽勝緣搜句，無術驅愁但飲醇。", "可笑山王今不數，敝裘索寞走天津。"]'),
('2274cd99-d093-46cc-bdf7-f8d7e1e09473','初到西湖  其一','王灼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖聲價甲天下，夢想平生初識之。',32,'全唐诗/poet.song.122000.json','["西湖聲價甲天下，夢想平生初識之。", "十里垂鞭幾多恨，不及見渠全盛時。"]'),
('ce0849a7-4eec-4eb3-a2cf-1aae1ba27a1a','初到西湖  其二','王灼','宋','宋诗','song-poetry','','["\u897f\u6e56"]','古來三百六十寺，春入頹基草木荒。',32,'全唐诗/poet.song.122000.json','["古來三百六十寺，春入頹基草木荒。", "解作高人無盡供，只餘山色與湖光。"]'),
('ce76542d-7d60-466a-a72e-1fbbacbc3679','呈陳崇青求娛親堂三大字  其一','王灼','宋','宋诗','song-poetry','','[]','椒柏浮觥盤列辛，今年春晚去年春。',64,'全唐诗/poet.song.122000.json','["椒柏浮觥盤列辛，今年春晚去年春。", "五侯門下正多事，九老圖中只一人。", "健筆橫飛鸞體態，童顔長鍊鶴精神。", "會看天上絲綸下，衛武還朝秉國鈞。"]'),
('a0a070a1-2b05-4d48-9f1f-244e62b33bf9','呈陳崇青求娛親堂三大字  其二','王灼','宋','宋诗','song-poetry','','[]','宵人有母鬢如銀，夜半丸熊誨子頻。',64,'全唐诗/poet.song.122000.json','["宵人有母鬢如銀，夜半丸熊誨子頻。", "幸竊斗升爲侍養，敢言科第止榮身。", "小堂欲作娛親扁，純孝誰推錫類仁。", "乞取先生三大字，要崇風教厲鄉鄰。"]'),
('1282a7cb-cd85-4c1c-a5ae-49a060864254','呈陳崇青求娛親堂三大字  其三','王灼','宋','宋诗','song-poetry','','["\u592a\u6e56"]','自掛衣冠神武門，依然戀闕赤心存。',64,'全唐诗/poet.song.122000.json','["自掛衣冠神武門，依然戀闕赤心存。", "清高寄興太湖石，盤礴行吟獨樂園。", "勝日過從無雜客，清宵侍坐有來孫。", "風神筋力新逾健，山色長青對壽樽。"]'),
('8ba84e3b-9075-48ac-bcd6-0d9be7633467','再和  其一','王灼','宋','宋诗','song-poetry','','[]','幼婦傳來舊受辛，知君滿腹貯陽春。',64,'全唐诗/poet.song.122000.json','["幼婦傳來舊受辛，知君滿腹貯陽春。", "壽星台宿應同邑，草聖詩仙合一人。", "紫橐禁中留賦詠，白蓮社裏鍊丰神。", "誰言林下長閑得，左席猶虛待秉鈞。"]'),
('e494222b-3e78-442a-a9de-6b32b03f8c17','再和  其二','王灼','宋','宋诗','song-poetry','','[]','湘東三管竹金銀，名勝均蒙品藻頻。',64,'全唐诗/poet.song.122000.json','["湘東三管竹金銀，名勝均蒙品藻頻。", "里巷自憐爲下士，門牆亦許託微身。", "吹噓短翮扶摇力，沾溉寒根造化仁。", "堂扁特書煩大手，少償孟母教遷鄰。"]'),
('d6346569-1ee5-4c9c-9f1c-6dbf17814a0c','再和  其三','王灼','宋','宋诗','song-poetry','','[]','早厭奔趨權貴門，中流勇退古風存。',64,'全唐诗/poet.song.122000.json','["早厭奔趨權貴門，中流勇退古風存。", "唱酬綠野今裴白，偃仰商山舊綺園。", "成熟坐看桃結子，平安幾報竹生孫。", "雨餘晴玉春無價，天遣清香入酒樽。"]'),
('dce16fcd-8f10-4ad1-a579-4c8e8d66dd30','三和謝娛親堂扁  其一','王灼','宋','宋诗','song-poetry','','[]','盛年曾效引裾辛，勇退歸休四十春。',64,'全唐诗/poet.song.122000.json','["盛年曾效引裾辛，勇退歸休四十春。", "閑却聖朝醫國手，來爲詩社作家人。", "尖新句子堪呈佛，峭拔毫端似有神。", "僕輩豈應陪唱和，却緣鼷鼠發千鈞。"]'),
('ad045f8e-c880-4c58-8c16-a14c1018b9a0','三和謝娛親堂扁  其二','王灼','宋','宋诗','song-poetry','','[]','爛然鐵畫間鈎銀，越薄蘇膏揮灑頻。',64,'全唐诗/poet.song.122000.json','["爛然鐵畫間鈎銀，越薄蘇膏揮灑頻。", "誰與鍾王傳妙訣，我知顔柳是前身。", "大書燕喜娛親扁，俯念烏慈反哺仁。", "因甚衡茅光徹夜，燭圍十丈許分鄰。"]'),
('f93cb3de-d6c9-4999-b90c-dbd97ae55a8b','三和謝娛親堂扁  其三','王灼','宋','宋诗','song-poetry','','[]','榮華夢事付朱門，茗碗爐燻所性存。',64,'全唐诗/poet.song.122000.json','["榮華夢事付朱門，茗碗爐燻所性存。", "對月朗吟將進酒，逢春細和樂遊園。", "坐中投轄時留客，膝上含飴日弄孫。", "四美難并公奄有，何曾一夕不開樽。"]'),
('1afc2959-4012-4e25-8088-41c270a973b0','代公慶上郭帥  其一','王灼','宋','宋诗','song-poetry','','[]','唐家尚父幾重孫，宿將齊推第一門。',64,'全唐诗/poet.song.122000.json','["唐家尚父幾重孫，宿將齊推第一門。", "新擁鋒車還北闕，暫辭戎律控西藩。", "柳營平日鏖輕敵，龍衮今年識至尊。", "好在樞庭展韜略，試看餘力整乾坤。"]'),
('0eee3c23-3f1f-4ac7-af6a-265fce0ad511','代公慶上郭帥  其二','王灼','宋','宋诗','song-poetry','','[]','昔年先廟謁汾陽，提筆從公寫短牆。',64,'全唐诗/poet.song.122000.json','["昔年先廟謁汾陽，提筆從公寫短牆。", "再別巴江油戟下，七逢天竺桂枝香。", "宦途自許安仁拙，浮俗誰憐處士狂。", "客舍無煙饑欲死，尚慚知己問行藏。"]'),
('c50926ee-68a3-4246-b682-6578b8b8ba79','題范季實秋山縱目圖','王灼','宋','宋诗','song-poetry','','[]','江天物態兩憑陵，借與懸崖倚瘦藤。',32,'全唐诗/poet.song.122000.json','["江天物態兩憑陵，借與懸崖倚瘦藤。", "又作吳中十年夢，胥山絕頂望西興。"]'),
('bb2172ba-bd47-4d62-9311-b15f714556d4','句','王灼','宋','宋诗','song-poetry','','[]','柳暗大堤曲，梅藏解佩人。',12,'全唐诗/poet.song.122000.json','["柳暗大堤曲，梅藏解佩人。"]'),
('43cc99b3-7ba8-4f4b-93e5-9e7ae78c9e00','鄉人禱雨有應時寓烏石','鄧深','宋','宋诗','song-poetry','','[]','力穡乃有秋，斯言聞自古。',252,'全唐诗/poet.song.122000.json','["力穡乃有秋，斯言聞自古。", "天時或不順，人事亦安取。", "今年問何如，常暘頗爲苦。", "大田紛拆裂，槁苗渴灌注。", "井甕走墟落，河車喧旦暮。", "江溪近復涸，手足了無措。", "禱旱急農夫，迓神擊村鼓。", "動以千百人，爲此萬一舉。", "烈日仍朝朝，乞靈空處處。", "誰知天地回，正在頃刻許。", "旱魃翻然收，豐隆激其怒。", "真龍奮寂寞，商羊自鼓舞。", "張蓋作濃雲，翻盆下甘雨。", "剩水有平疇，曠原無焦土。", "言功任鬼神，介我喜稷黍。", "飽飯可預期，晚歲復何慮。", "懽聲變愁嘆，憂心成悅豫。", "惟時對江村，所寓隘茅宇。", "因循已半月，侵凌奈酷暑。", "快此一日凉，美甚八珍具。", "澆腸欠濁醪，錢兄尋酒戶。"]'),
('15761267-8e8d-4e53-a89e-7a2baf44eaa9','探禹穴','鄧深','宋','宋诗','song-poetry','','[]','禹穴鎮名山，神龍夙呵衛。',288,'全唐诗/poet.song.122000.json','["禹穴鎮名山，神龍夙呵衛。", "告成餘此跡，天地相終始。", "昔在紹興中，弔古先君子。", "探穴勇躋攀，慨嘆不能已。", "援筆賦會稽，兼述風土美。", "趨庭童丱時，誦之能略記。", "頗識尋幽趣，便有東遊志。", "道路阻且長，日月疾難恃。", "此興墮渺茫，轉燭逾三紀。", "兩年寓臨安，相隔纔一水。", "登覽似可期，特未敢必耳。", "今年正月末，乃不料行止。", "雲隨渡江風，身著千巖裏。", "借問自何方，可訪夏后氏。", "或指高峰云，近在十五里。", "是日天氣清，好風濯衣袂。", "興來不假懶，偕行二三子。", "猶子試上庠，邂逅亦能侍。", "呼舟汎鏡湖，肌膚撲空翠。", "新荷點青錢，魚行不相避。", "水凈無波濤，曾不踰時至。", "捨棹叩仙扉，宮額賜龍瑞。", "古道怪松引，重門老柏倚。", "苔徑稍深登，曲折窮幽邃。"]'),
('29dba6bd-1cf1-4609-b6a9-f83a74673e55','遊北禪','鄧深','宋','宋诗','song-poetry','','[]','城市有深遠，爲興遠如近。',144,'全唐诗/poet.song.122000.json','["城市有深遠，爲興遠如近。", "冒暑一來遊，政使俗者哂。", "蕭然清浄界，軟語接支遁。", "小童敬杖屨，添香撥餘燼。", "煮餅擷園蔬，徐以茗椀進。", "窗外得小坡，野意頗無盡。", "胡床移最宜，清風來有信。", "靜暑荷送氣，敲凉竹成韻。", "夕陽歸鳥疾，參差不作陣。", "古寺忽橫煙，巧與畫張本。", "會心忻有得，貪坐苦易晚。", "酒固無獻酬，言亦忘答問。"]'),
('3863001c-3896-4153-b27e-562d7130bdc4','豐城道中','鄧深','宋','宋诗','song-poetry','','[]','西風著衣袂，凉意曉來加。',264,'全唐诗/poet.song.122000.json','["西風著衣袂，凉意曉來加。", "宿露眩光彩，朝陽濕精華。", "人烟互疏密，物色興嘆嗟。", "喧囂鴨子市，蕭索漁人家。", "皂裙婦多跣，及冠男猶髽。", "挽犁並雙牸，截江橫流沙。", "佐飯缺蔬茹，作糜和魚蝦。", "湖田不薅草，沙畦多蒔麻。", "露空立禾架，結屋卧牛車。", "水葉枯荷芰，山果瘦梨樝。", "烏桕動千樹，雜木不一了。", "緣塍豆欲實，編籬槿纔花。", "三分莫問酒，一啜不可茶。", "行行入暮烟，兩兩數歸鴉。", "聯步得姻戚，浪語殊讙譁。", "畢景自忘倦，所歷不覺遐。", "問宿于誰館，有軒臨水涯。", "暗壁飛蝙蝠，皓月升蝦蟆。", "式盤疊餅餌，擊缶出舊瓜。", "携來尚餘樽，取酌如流霞。", "少飲不必醉，遣興固自嘉。", "欲眠復出門，漁燈認蒹葭。"]'),
('6130e2e0-4dc7-4c57-a728-d1f6cc091c2c','醴泉','鄧深','宋','宋诗','song-poetry','','[]','醴陵以泉名，問泉良不遠。',168,'全唐诗/poet.song.122000.json','["醴陵以泉名，問泉良不遠。", "平田數頃開，方池三尺淺。", "含秋色幽幽，辟塵光淀淀。", "觱沸生其間，的皪紛可辨。", "纍纍似噴珠，一一如穿線。", "多至叢萬顆，少或作疏串。", "遲速固難期，南北初無限。", "占地喻尋丈，有時忽隱見。", "恍兮莫窮源，雜然應有眼。", "沙石那能窒，苔荇不得炫。", "千載曾未枯，一日知幾番。", "釀酒味固佳，煮茗香可羨。", "名泉世不乏，此奇吾未見。", "醒心聊一掬，賦詩寓三歎。"]'),
('a4db8cfd-f5fd-45b7-9bab-dd35574f167b','次韻答社友','鄧深','宋','宋诗','song-poetry','','[]','小軒名大隱，粗可供趺坐。',228,'全唐诗/poet.song.122000.json','["小軒名大隱，粗可供趺坐。", "遮眼時翻書，靜願結香火。", "似介還似癡，所向與時左。", "不踐名利途，竊謂志亦果。", "人生天地間，世路多坎坷。", "成敗端有數，巧力不容佐。", "昧者迷所之，大似蟻旋磨。", "君看禽高飛，翼倦千仞墮。", "太剛者易亡，太銳者必挫。", "得失相乘除，倚伏兩福禍。", "顧予何所樂，日晏得高卧。", "豈惟七不堪，萬事付懶惰。", "儕類每見寬，亦不攻其過。", "美人如敬翁，學問精而夥。", "松柏生澗壑，霜幹久長大。", "富貴應不免，時有可未可。", "何須窮婦吟，再三嘆寒餓。", "且冀寬此抱，會當有知我。", "屬和聊寫情，暫輟園蔬課。"]'),
('7f8e9779-b5ac-4ac0-8a42-edcc5c239918','次韻易高士','鄧深','宋','宋诗','song-poetry','','[]','新詩嘆干戈，流移痛眼邊。',48,'全唐诗/poet.song.122000.json','["新詩嘆干戈，流移痛眼邊。", "公若據要路，不惜金軀捐。", "同舟曾有約，儻行亦憂煎。", "政恐無此吟，掩卷空自憐。"]'),
('886d4e18-01a1-456a-839b-77bebec1d42d','齊雲','鄧深','宋','宋诗','song-poetry','','[]','閒雲無定在，爲問齊不齊。',48,'全唐诗/poet.song.122000.json','["閒雲無定在，爲問齊不齊。", "風高衣裳冷，天近日月低。", "寬虛快舒嘯，領覽時杖藜。", "南城塊蘇耳，擾擾人自迷。"]'),
('f0f4d539-26d7-410d-8c22-4799a003bb4c','賦椿楸二樹','鄧深','宋','宋诗','song-poetry','','[]','愛均召伯棠，名殊諸葛菜。',48,'全唐诗/poet.song.122000.json','["愛均召伯棠，名殊諸葛菜。", "軒檻頓輝光，東西相映带。", "此意存千年，其勢當兩大。", "梨棗況久生，於焉稱內外。"]'),
('a1cdabbd-6095-4834-b29a-28e34f369c51','寄題真樂齋','鄧深','宋','宋诗','song-poetry','','[]','魚潜深淵水，鳥巢茂林枝。',216,'全唐诗/poet.song.122000.json','["魚潜深淵水，鳥巢茂林枝。", "潜者忘於淵，洋洋縱尾鰭。", "巢者忘於林，飛鳴唯所宜。", "莊周嘆從容，未免惠子疑。", "師曠豈知聲，繆以占齊師。", "彼各有真樂，果孰得而窺。", "陋巷顔氏子，簞瓢甘忍饑。", "陶潜怕折腰，素琴絃不施。", "其樂可聞歟，夫蓋默識之。", "非絲亦非竹，且復非蛾眉。", "譬如執熱者，灑然濯凉颸。", "又如渴不禁，快飲清江湄。", "當其得意時，何以富貴爲。", "手舞而足蹈，誠不之自知。", "自知猶不可，人胡可度思。", "君闢真樂齋，我賦真樂詩。", "寫詩聊寄意，名齋儻在斯。", "置之勿復道，焚香誦楚詞。"]'),
('b85d8fc1-8143-4220-8f57-9aea13fb919e','遊羅正仲磬沼深得一字','鄧深','宋','宋诗','song-poetry','','[]','磬沼去郭近，得朋忻一出。',96,'全唐诗/poet.song.122000.json','["磬沼去郭近，得朋忻一出。", "曲水媚秋花，輕雲翳寒日。", "幽野愜心期，平遠快目力。", "率爾進所携，雜陳初匪一。", "初無惡客來，不妨歌妓密。", "浮白行觴政，追韻嚴詩律。", "晚醉語紛紛，夕寒風淅淅。", "策杖歸去來，書床鳴蟋蟀。"]'),
('efcc01fc-96ef-4261-8365-535cc1ddfc7a','山莊石室清坐','鄧深','宋','宋诗','song-poetry','','[]','時登大石樓，雅愛小石室。',96,'全唐诗/poet.song.122000.json','["時登大石樓，雅愛小石室。", "欠伸欲打頭，睡卧可舒膝。", "明潔意自寬，深沉境逾寂。", "藏春絕嚴風，生秋無畏日。", "天設世莫知，神工鬼有力。", "幼輿飽丘壑，馬融富書籍。", "洞門何嘗扃，俗客自滅跡。", "誰歟助微吟，幽蟲聲唧唧。"]'),
('d3891e51-7114-42b6-ae1c-60585c71b34e','諸人集予貧樂軒賞花以直把春賞酒都將命乞花爲韻深得把字','鄧深','宋','宋诗','song-poetry','','[]','旭日釀融和，化工幻夭冶。',108,'全唐诗/poet.song.122000.json','["旭日釀融和，化工幻夭冶。", "吾家最岑寂，亦有花枝亞。", "光浮蝶翅動，香倩蜂鬚惹。", "名傳文中譜，品入趙昌畫。", "春歸不可挽，恐被東風嫁。", "急呼我輩人，趺坐花陰下。", "雖無裙可幄，賴有草堪藉。", "但愁歡未闌，酒盡不容把。", "明年長安城，走馬逐東野。"]'),
('230166ae-4a08-4048-aea8-d4b989c5fb33','官舍梅樹','鄧深','宋','宋诗','song-poetry','','[]','東風慰寂寞，花到階前樹。',252,'全唐诗/poet.song.122000.json','["東風慰寂寞，花到階前樹。", "一枝花十餘，一樹枝四五。", "妙處在不多，酴醾更屏護。", "半開半未開，十分好態度。", "去年初來時，愛此當庭戶。", "便指爲紅梅，試問何以故。", "入簷一枝低，偃亞復數處。", "有是好風骨，他木安敢許。", "逮至臘前後，梅開不擇所。", "此獨未有芽，春信來何暮。", "時著手摩挲，切勿爲文具。", "相勞雖無酒，典衣吾有取。", "因循及初春，椒萼纔可數。", "慫恿荷微暖，紅英忽然吐。", "驚喜出不料，遶翫遂成屢。", "頳頰人共憐，慚顔我自誤。", "著眼未分明，殆須捲簾顧。", "昔嘗笑北人，渾作杏花睹。", "認桃無綠葉，吾不事斯語。", "吾本待以梅，恨不辨紅素。", "見花乃識花，康節應笑汝。"]'),
('0892f8a0-33bf-48d8-9137-4b9c79f6870e','忘歸','鄧深','宋','宋诗','song-poetry','','[]','端能來作棲霞侶，從他浮世悲今古。',32,'全唐诗/poet.song.122000.json','["端能來作棲霞侶，從他浮世悲今古。", "翻憐春色滿天台，劉阮掉頭留不住。"]'),
('80b4f570-ecd5-46ff-afa4-e04455f85410','中秋無月感而作歌','鄧深','宋','宋诗','song-poetry','','[]','天時相催日如流，今夕何夕云中秋。',256,'全唐诗/poet.song.122000.json','["天時相催日如流，今夕何夕云中秋。", "不見佳月默有感，試走退筆書其由。", "去年此時汝川客，一病纏綿真險厄。", "貪生强樂寸心酸，與死爲鄰片紙隔。", "破窗髣髴光朦朧，推枕起來呼小童。", "問云月高今幾尺，答以雲生俄滅蹤。", "擁衾獨坐謾空想，縱有桂華未能賞。", "重城幾許追歡娛，終宴無聊徒悵望。", "而今一榻烟村中，稍喜時同事不同。", "世味淡薄幽意足，元和咽漱真氣充。", "步屧出門舒逸興，清風灑面衣襟冷。", "暗雨淅瀝作寒聲，濃雲黯黲無光影。", "月兮月兮胡寡情，故向良時多不明。", "無乃韜光不自滿，故能養兔得長生。", "我今解悟月深意，榮華咄嗟復凋悴。", "歸來塞窗仍閉門，眾人昭昭我獨昏。"]'),
('1742f82e-c6be-46f8-bc69-80889f14424a','遡峽詩','鄧深','宋','宋诗','song-poetry','','[]','臚言峽山天下奇，欲觀愁隔三千里。',384,'全唐诗/poet.song.122000.json','["臚言峽山天下奇，欲觀愁隔三千里。", "常恐因循孤此興，非假夤緣那得至。", "偶逢月湖起仕宦，正指夔門愁凋敝。", "忻然謂我便登陟，久矣與予同臭味。", "何嘗佳處倦扶藜，莫憚西征共行李。", "繡旆前驅抵江陵，畫鷁迎車艤沙市。", "長年槌鼓轉船頭，川后回風送旂尾。", "侵尋崖石愜幽賞，洶湧波濤反輕視。", "霧船烟纜恣深遊，露宿風餐浥清氣。", "百巧千奇類神工，紛至沓來惱吟思。", "取句未佳恐難操，傳筆欲書還復止。", "去歲延陵駭心目，指摘形容寫行記。", "今年江夏襲見聞，掇拾緒餘循故事。", "試以七言用檃括，庶幾二妙相表裏。", "或若洞戶之谽谺，或若樓臺之峻峙。", "或若香山之插爐，或若筆架之橫几。", "或遮護如重簾幙，或張展如大旂幟。", "或戍削如城堞高，或森列如刀劍銳。", "或若蕉葉之斜紋，或若蓮花之疊起。", "或若頂相之初浄，或若蓬頭之未理。", "或剝落爲枯松身，或刻畫爲古篆體。", "或斧傷而痕跡亂，或鋸解而縫罅細。", "或如秋瓜作四分，或如籠餅裂十字。", "或如白鹽之浮霜，或如紅霞之散綺。"]'),
('61d23977-9ed9-4438-b67f-0b0f3518de0d','次正臣韻','鄧深','宋','宋诗','song-poetry','','[]','黄牛偶際半槽水，忻然解纜離江涘。',176,'全唐诗/poet.song.122000.json','["黄牛偶際半槽水，忻然解纜離江涘。", "舊聞峽山最多奇，非涉風波難說似。", "千金莫買丹青臨，今日真行圖畫裏。", "魂驚險怪千萬狀，眼洗清奇數千里。", "戲石鹿兒玩鐃鼓，緣木王孫賣弓矢。", "鷺鷥久立應有待，鸕鶿深沒殊無底。", "大淖瀑濆續續生，怒濤驚浪層層起。", "好風轉旂捷有神，長年捩柂翻堪倚。", "漁人生長謾不知，葉舟來去紛可喜。", "惟愁三峽總黄濁，安得一瓢獨清泚。", "甘泉剩貯蝦蟆碚，時瀹玉塵香漱齒。"]'),
('89bd9859-f97d-4214-b854-1f075e1cb98f','觀遊女次韻','鄧深','宋','宋诗','song-poetry','','[]','麗人春遊相百十，此風長沙云舊習。',96,'全唐诗/poet.song.122000.json','["麗人春遊相百十，此風長沙云舊習。", "綺羅映肌白玉鮮，珠翠壓鬢烏雲濕。", "借地持杯遞呼喚，笑指花枝時小立。", "晚風忽遣柳棉飛，竹逕梅亭巧穿入。", "惱亂遊人歸不去，使我樽中無以給。", "誰念朝來丘隴間，紙錢吹落無人拾。"]'),
('3286d62f-f4e1-44d7-8886-3c4a6871b5af','清隱爲知觀李元禮作','鄧深','宋','宋诗','song-poetry','','[]','世氣擾擾人遑遑，靜有八室無八方。',64,'全唐诗/poet.song.122000.json','["世氣擾擾人遑遑，靜有八室無八方。", "壺中酒好誰獨覺，橘間棋樂何可量。", "峨峨湯湯知音少，管絃嘔啞人稱好。", "歸來水深山更奇，玉徽不按心自知。"]'),
('011a84b2-12ff-4acb-a21b-ea9a8adce115','湧雲','鄧深','宋','宋诗','song-poetry','','[]','溪神騁技天公拙，非雪之雪白于雪。',32,'全唐诗/poet.song.122000.json','["溪神騁技天公拙，非雪之雪白于雪。", "倚欄小立不禁寒，却願天日長炎熱。"]'),
('6f15445c-0809-4175-b2ab-44f68cf3fae3','月湖新得浮石巖','鄧深','宋','宋诗','song-poetry','','[]','月湖先生樂山水，搜奇曾不遠千里。',384,'全唐诗/poet.song.122000.json','["月湖先生樂山水，搜奇曾不遠千里。", "那知去郭三牛鳴，浮石巖中晦佳致。", "神剜鬼劃有許工，天墜地出知幾世。", "平時樵徑所不由，一旦屐齒胡爲至。", "由來絕景難久藏，竟須好事與經始。", "見之三歎欲忘歸，市以千金不惜費。", "公之得此真無價，我亦聞之喜不寐。", "朝來幽事頗相關，乘興縱觀約聯騎。", "霜明日暖馬蹄輕，曾不踰時即其地。", "噴雲泄霧疑有神，旋呼斤斧誅榛葦。", "初驚巨石幾百尋，突兀嶙峋濕雲氣。", "嵌竇谽谺元自開，藤蔓駢羅巧相締。", "清涵竹木總堅瘦，陰生莓苔倍葱翠。", "老根側出掀虯髯，幽草倒生摇鳳尾。", "前山一抹橫蛾眉，隔盡俗塵如戶閉。", "褰裳振足履崎嶇，披棘捫蘿窮幽邃。", "忽有一徑出自然，委蛇深隱闊盈咫。", "四面周遭步轉高，心領目擊紛可喜。", "處處出石作奇怪，續續哦詩聊比擬。", "或黎其色如鐵繡，或赭其容如酒醉。", "或傲睨而癡自笑，或突怒而狠相視。", "或開幽室爲書院，或引長廊爲客次。", "或虛高下成樓閣，或嚴尊卑作堂陛。", "或分半月隱天形，或展胡床圈地勢。"]'),
('394d0eed-6c18-45b3-b889-5aa1f7e8d30c','寄清曠兄弟','鄧深','宋','宋诗','song-poetry','','[]','一別春三見，相思日幾回。',48,'全唐诗/poet.song.122000.json','["一別春三見，相思日幾回。", "自離夔府後，已過岳陽來。", "寒食還虛度，酴醾幸晚開。", "到時猶可及，應得共銜盃。"]'),
('70f5a4c0-73ee-402e-b6d2-9fb9b4349578','寄麻姑山李元禮','鄧深','宋','宋诗','song-poetry','','[]','不見山中客，還經四度春。',48,'全唐诗/poet.song.122000.json','["不見山中客，還經四度春。", "近聞歸舊隱，真箇是閒人。", "吹髮松風迥，當軒琴月新。", "懸知心更靜，夢不到紅塵。"]'),
('36a6bf8a-8aa3-404f-8e3d-343908683848','春寒','鄧深','宋','宋诗','song-poetry','','[]','二月寒如臘，群芳凍未芽。',48,'全唐诗/poet.song.122000.json','["二月寒如臘，群芳凍未芽。", "有人能剪水，無樹不飛花。", "終不禁風暖，難教带月華。", "却還桃李徑，次第散晴葩。"]'),
('a4be1e14-dbd1-47b3-aa4f-16bef34fee9a','默坐','鄧深','宋','宋诗','song-poetry','','[]','默坐形如槁，清閒智養恬。',48,'全唐诗/poet.song.122000.json','["默坐形如槁，清閒智養恬。", "飛蟲黏密網，鬭雀墮虛簷。", "却暑寧須扇，留香略下簾。", "無人撓清思，至夜待明蟾。"]'),
('873b8c0a-0d6e-432e-958c-4f01f9bca7c1','山莊冰壺避暑','鄧深','宋','宋诗','song-poetry','','[]','偏屋支巖穩，斜廊引路通。',48,'全唐诗/poet.song.122000.json','["偏屋支巖穩，斜廊引路通。", "虛明疑貯月，凄冷自迎風。", "六月尤宜此，紅塵不到中。", "灑然無熱惱，坐我廣寒宮。"]'),
('2c10f450-bcbd-4cec-85a2-16457589a61f','東池把酒','鄧深','宋','宋诗','song-poetry','','[]','隱顯亭臺舊，淺深桃杏新。',48,'全唐诗/poet.song.122000.json','["隱顯亭臺舊，淺深桃杏新。", "池光迷野鳥，春色醉遊人。", "改席那嫌數，持杯不記巡。", "海棠宜秉燭，歸恨隔城闉。"]'),
('e0b4db74-1fef-4fcd-a068-04e21893f888','鑑堂把酒','鄧深','宋','宋诗','song-poetry','','[]','池館媚春華，凭欄午更嘉。',48,'全唐诗/poet.song.122000.json','["池館媚春華，凭欄午更嘉。", "日光凝水面，波影炫簷牙。", "魚出衝浮梗，萍交載落花。", "半酣拏小艇，落調唱漁家。"]'),
('11ee90eb-0937-4019-a43c-395e0a260abd','三伏中一雨甦旱','鄧深','宋','宋诗','song-poetry','','[]','江漲如三月，天凉似九秋。',48,'全唐诗/poet.song.122000.json','["江漲如三月，天凉似九秋。", "遭逢今日雨，安穩一年收。", "處處香甕面，村村肥藁頭。", "小春前後好，待挂百錢遊。"]'),
('8125dc4a-dc37-45f7-b241-ab77cccddbe1','山齋早起','鄧深','宋','宋诗','song-poetry','','[]','推枕凌晨起，添衣奈冷何。',48,'全唐诗/poet.song.122000.json','["推枕凌晨起，添衣奈冷何。", "新霜浮瓦薄，缺月挂簷多。", "野燒猶殘焰，鄰雞尚凍歌。", "撥灰添宿火，一快爇松柯。"]'),
('d98cf1ef-c0ea-4532-bc08-38b90336c1a2','早秋','鄧深','宋','宋诗','song-poetry','','[]','風入題詩葉，清音已奏商。',48,'全唐诗/poet.song.122000.json','["風入題詩葉，清音已奏商。", "夜來堪簡冊，客至便衣裳。", "次第征鴻到，還令團扇藏。", "人情兼物意，殊覺漫炎凉。"]'),
('107670ad-3601-4926-9e24-e451bb070022','夢回','鄧深','宋','宋诗','song-poetry','','[]','日日風吹雨，秋深寒氣催。',48,'全唐诗/poet.song.122000.json','["日日風吹雨，秋深寒氣催。", "簷聲中夜斷，月色上窗來。", "冷砌蟲吟穩，幽屏蝶夢回。", "明朝應露重，晚菊正宜開。"]'),
('1f46df4b-78a3-413b-87e1-ab78e11519a3','遣興','鄧深','宋','宋诗','song-poetry','','[]','頗覺今朝好，全無俗事關。',48,'全唐诗/poet.song.122000.json','["頗覺今朝好，全無俗事關。", "風清林鶴喜，雨霽野雲閒。", "橘柚垂枝重，莓苔上砌斑。", "芼羹挑野菜，風味不吾慳。"]'),
('00588ee1-b100-4995-8e9d-38c75ef3527e','摘橘','鄧深','宋','宋诗','song-poetry','','[]','久矣經霜白，全然映日黄。',48,'全唐诗/poet.song.122000.json','["久矣經霜白，全然映日黄。", "仰頭忻自摘，流齒愜新嘗。", "未抵千奴利，應堪四老藏。", "猶勝橘洲上，滅跡不聞香。"]'),
('039b9506-a255-46b2-8766-e2f87d48dc0d','竹筩養梅置窗間','鄧深','宋','宋诗','song-poetry','','[]','竹與梅爲友，梅非竹不宜。',48,'全唐诗/poet.song.122000.json','["竹與梅爲友，梅非竹不宜。", "截筩存老節，折樹凍疏枝。", "靜牖初安處，清泉滿注時。", "暗香披拂外，細細覺風吹。"]'),
('669600c1-cb14-44d0-8b12-483fadd9184e','除夕把酒','鄧深','宋','宋诗','song-poetry','','[]','爆竹驚今夕，屠蘇薦詰朝。',48,'全唐诗/poet.song.122000.json','["爆竹驚今夕，屠蘇薦詰朝。", "去來時轉眼，新舊歲中腰。", "立地符先釘，倚門錢未燒。", "土人珍裂餅，聊以薦金蕉。"]'),
('0308d553-5f94-4358-9a7e-c1a1bd14209b','懷清曠兄弟','鄧深','宋','宋诗','song-poetry','','[]','殘臘迎除夕，新春接上元。',48,'全唐诗/poet.song.122000.json','["殘臘迎除夕，新春接上元。", "常時陪內集，排日醉芳樽。", "歲月驚殊俗，關山隔故園。", "談邊應記我，頻嚏怪黄昏。"]'),
('0c60d591-061e-45d2-9ecf-62a65c7959a4','感懷  其一','鄧深','宋','宋诗','song-poetry','','[]','舊日城壕興，真成一夢間。',48,'全唐诗/poet.song.122000.json','["舊日城壕興，真成一夢間。", "伯倫墳上土，叔子望中山。", "落日難留戀，孤雲自往還。", "秋風吹杖屢，回首涕空潸。"]'),
('c64c5def-a830-4783-863b-43c860e2708f','感懷  其二','鄧深','宋','宋诗','song-poetry','','[]','一棹載愁歸，翩翩旅旐飛。',48,'全唐诗/poet.song.122000.json','["一棹載愁歸，翩翩旅旐飛。", "鶺鴒空自急，鴻鴈失相依。", "水澀灘膠艇，風斜雨濕衣。", "感時無意緒，佇立暮烟霏。"]'),
('ebbeedeb-4f13-47f1-adcc-207762e5fb0b','即事','鄧深','宋','宋诗','song-poetry','','[]','水夾山圍近，天慳日到遲。',48,'全唐诗/poet.song.122000.json','["水夾山圍近，天慳日到遲。", "塞沙擎巨石，古木障崇祠。", "黄藁畬田粟，青烟茅舍炊。", "兩村生理足，樂處幾人知。"]'),
('0a9c0895-182e-4a61-a583-098e27754557','躬耕','鄧深','宋','宋诗','song-poetry','','[]','靖節田園興，子真巖谷情。',48,'全唐诗/poet.song.122000.json','["靖節田園興，子真巖谷情。", "古人雖不見，今代有同清。", "道義丘山重，軒裳羽翮輕。", "蕭然無俗累，心地湛虛明。"]'),
('1027971e-5a77-4930-a422-168ef0e301d3','寓寧庵縱步','鄧深','宋','宋诗','song-poetry','','[]','野潤雨初歇，曉陰雲未開。',48,'全唐诗/poet.song.122000.json','["野潤雨初歇，曉陰雲未開。", "訪君行李處，許我杖藜來。", "及到田家問，還聞轍跡回。", "西風黄葉下，悵望立蒼苔。"]'),
('80ea32e6-8d12-4a20-b830-7ffe97e8f5df','靜暉樓曉坐','鄧深','宋','宋诗','song-poetry','','[]','嶺宿寒雲薄，樓迎曉日斜。',48,'全唐诗/poet.song.122000.json','["嶺宿寒雲薄，樓迎曉日斜。", "危簷排語雀，落木點啼鴉。", "佛鼓依山寺，炊烟隔岸家。", "移時收足坐，清興會烟霞。"]'),
('64ff5922-e0fc-481e-a860-0f987b54a1ad','施食','鄧深','宋','宋诗','song-poetry','','[]','它鄉身總健，每食飯何如。',48,'全唐诗/poet.song.122000.json','["它鄉身總健，每食飯何如。", "一飽寧無限，三人動有餘。", "嬌鴉來木杪，喜鵲下庭除。", "施食僧家事，何妨領略渠。"]'),
('2070dc47-24b3-494f-bc2e-171abe2b9ee1','遊再興院','鄧深','宋','宋诗','song-poetry','','[]','山遠平田闊，村深古寺幽。',48,'全唐诗/poet.song.122000.json','["山遠平田闊，村深古寺幽。", "屋頭支老樹，門面闖雙流。", "歸翼碧天暮，寒蟬紅葉秋。", "瘦藤聊倚壁，勝處欲遲留。"]'),
('89971ed7-97e3-42ee-aec4-e4b6b6280c60','巖石山鼓','鄧深','宋','宋诗','song-poetry','','[]','有字留詩錦，無皮入藥囊。',48,'全唐诗/poet.song.122000.json','["有字留詩錦，無皮入藥囊。", "同堅唯鐵杖，易穴豈藜床。", "况有千年潤，能添六月凉。", "因巖作書院，馳譽比衡陽。"]'),
('395c1c09-fa0a-43ef-9093-022f23bea3b6','留報恩定老','鄧深','宋','宋诗','song-poetry','','[]','住山姑小試，同學偶相求。',48,'全唐诗/poet.song.122000.json','["住山姑小試，同學偶相求。", "兩手便分付，諸公堅挽留。", "退庵曾毒手，進步莫回頭。", "早晚江湖去，閒雲更自由。"]'),
('99752e15-78d7-4ef3-972e-f6af37a49005','涌翠爲知觀周允昇作','鄧深','宋','宋诗','song-poetry','','[]','山翠來如涌，開軒不怕深。',48,'全唐诗/poet.song.122000.json','["山翠來如涌，開軒不怕深。", "渾疑霏霧雨，已覺濕衣襟。", "世事歸楸局，泉聲當玉琴。", "道人塵外越，我欲剩追尋。"]'),
('c5209326-d165-486d-8b1a-39fc0c5c847d','新灘阻風','鄧深','宋','宋诗','song-poetry','','[]','高浪驚人處，新灘復眼中。',48,'全唐诗/poet.song.122000.json','["高浪驚人處，新灘復眼中。", "雖無曳尾淖，奈有打頭風。", "秉燭破春闇，看山坐雨濛。", "終朝收足坐，兀兀與僧同。"]'),
('de3acb4a-f0f8-43d7-8bd6-9586912e9d76','解舟','鄧深','宋','宋诗','song-poetry','','[]','波面孤篷窄，關頭古渡幽。',48,'全唐诗/poet.song.122000.json','["波面孤篷窄，關頭古渡幽。", "舟輕疾移岸，岸曲屢回舟。", "野潤蒸梅雨，天寒張麥秋。", "欠伸思晚步，舍棹涉芳洲。"]'),
('05c524e2-f55e-491b-8e91-6388332a8ed9','宿長湖尾','鄧深','宋','宋诗','song-poetry','','[]','古木侵沙路，柴門引竹籬。',48,'全唐诗/poet.song.122000.json','["古木侵沙路，柴門引竹籬。", "山低秋水闊，天遠夕陽遲。", "杳杳來鴻鴈，翩翩下鷺鷥。", "漁舟何處宿，橫笛未休吹。"]'),
('b1905ae3-415f-4f1f-bffe-f414cc065718','三游洞','鄧深','宋','宋诗','song-poetry','','[]','詰曲山蹊晚，清冷石澗秋。',48,'全唐诗/poet.song.122000.json','["詰曲山蹊晚，清冷石澗秋。", "三門儼呀豁，四壁極琱鎪。", "上穴重巖閟，中龕一室幽。", "斐然成五字，聊爾繼三游。"]'),
('1c9f6ea0-c1da-419c-9614-44c3def8e3d8','接天閣爲武將榮叔賦','鄧深','宋','宋诗','song-poetry','','[]','山色渾連水，波光總映空。',48,'全唐诗/poet.song.122000.json','["山色渾連水，波光總映空。", "捲簾秋雨後，注目夕陽中。", "低下翩翩鷺，斜行點點鴻。", "去天應尺五，歸去會乘風。"]'),
('150424e4-2b89-4120-9dd3-0ffa81a189b1','別長沙驛渡','鄧深','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','別去六年久，重來四日留。',48,'全唐诗/poet.song.122000.json','["別去六年久，重來四日留。", "笋輿離古驛，荻岸即方舟。", "雲淡楚天闊，風高湘水秋。", "洞庭知不遠，乘興欲盟鷗。"]'),
('ffff3c00-eaa8-4209-9a9c-789afb0b0346','留別趙徽猷','鄧深','宋','宋诗','song-poetry','','[]','自客湖州市，時登韞美堂。',48,'全唐诗/poet.song.122000.json','["自客湖州市，時登韞美堂。", "雲烟看揮染，風月共平章。", "酒子常同醉，梅兄已再香。", "遽爲今日別，欲乞舊詩囊。"]'),
('e0cd7f3e-2c7d-4ab4-a8c6-e78abf480469','賦何仲敏小蓬瀛','鄧深','宋','宋诗','song-poetry','','[]','特地去人遠，遶亭教水環。',48,'全唐诗/poet.song.122000.json','["特地去人遠，遶亭教水環。", "眼前今有此，海上更無山。", "風月隨時好，琴書盡日閒。", "方今重文館，勿久戀人間。"]'),
('11d5da16-4312-4f0a-9f54-aab6c5632656','題古亭詩','鄧深','宋','宋诗','song-poetry','','[]','日月車雙轂，功名黍一炊。',48,'全唐诗/poet.song.122000.json','["日月車雙轂，功名黍一炊。", "達人觀物化，萬事本兒嬉。", "濁酒聊澆舌，閒愁莫上眉。", "劉伶多事在，荷鍤竟何之。"]'),
('fbe12a4d-5de2-4b3e-a230-3d3bad4da1f9','春夜次韻答肯堂兄','鄧深','宋','宋诗','song-poetry','','[]','天賦疏慵性，身將四十年。',48,'全唐诗/poet.song.122000.json','["天賦疏慵性，身將四十年。", "逢歡開口笑，遇醉倒頭眠。", "世事多翻覆，時光易變遷。", "置之無足校，五字要清圓。"]'),
('eb469bf0-21bc-48e3-a7c6-4da9c73a7a7c','贈別饒司理述古','鄧深','宋','宋诗','song-poetry','','[]','岳麓一樽酒，湘江萬里秋。',48,'全唐诗/poet.song.122000.json','["岳麓一樽酒，湘江萬里秋。", "匆匆別後語，冉冉歲華流。", "正喜重相見，胡爲不少留。", "參軍詩俊逸，還肯寄來不。"]'),
('46f0ad1c-bae9-4b5a-99d2-a4d4bb8999da','贈別周德夫','鄧深','宋','宋诗','song-poetry','','[]','郡治資參佐，計臺須借留。',48,'全唐诗/poet.song.122000.json','["郡治資參佐，計臺須借留。", "居常元少事，有子更無憂。", "君問歸涪棹，予尋出峽舟。", "一樽談舊事，何日重相求。"]'),
('fa41fda7-208b-4098-8109-3d1abf8339fe','送仲敏東歸','鄧深','宋','宋诗','song-poetry','','[]','別僅三千里，書纔一載通。',48,'全唐诗/poet.song.122000.json','["別僅三千里，書纔一載通。", "固應難邂逅，那得許從容。", "今日君先去，何時我亦東。", "社中如借問，爲道轉疏慵。"]'),
('870dc5c1-8c26-44fb-b285-13ebc48c3785','賀陳仲思','鄧深','宋','宋诗','song-poetry','','[]','中鵠知誰好，烹魚始認名。',48,'全唐诗/poet.song.122000.json','["中鵠知誰好，烹魚始認名。", "報公勤有子，似我懶無甥。", "何日親相見，因風且寄聲。", "泥金聞喜處，樽酒欲同傾。"]'),
('23efe0d6-ea09-46c4-9ebd-dde200054dbe','寄徐廣文','鄧深','宋','宋诗','song-poetry','','[]','自我還荒徑，知君返寓居。',48,'全唐诗/poet.song.122000.json','["自我還荒徑，知君返寓居。", "秋來曾醉否，月下有詩無。", "兩地成千里，相看不一書。", "可能忘舊債，五字當追須。"]'),
('3686990d-56e9-436d-8150-a158da7eea7a','寄曾德廣','鄧深','宋','宋诗','song-poetry','','[]','懶慢多違俗，尋常倦作書。',48,'全唐诗/poet.song.122000.json','["懶慢多違俗，尋常倦作書。", "分襟還許久，爲况定何如。", "鴻鴈秋風冷，梧桐夜雨疏。", "相如病好否，何日過吾廬。"]'),
('4aaa0728-79bc-4d44-bd15-a402d9a12873','寄別國清月老','鄧深','宋','宋诗','song-poetry','','[]','珍重國清老，由來隱薜蘿。',72,'全唐诗/poet.song.122000.json','["珍重國清老，由來隱薜蘿。", "詩清堪供佛，禪定已降魔。", "不向名山住，其如講席何。", "無心聊一出，餘論自相多。", "別去今逾遠，後期難重過。", "丁寧一句子，還肯寄來麽。"]'),
('30f2ff51-6b13-44a4-8f3d-d508317273aa','春雪','鄧深','宋','宋诗','song-poetry','','[]','勾芒新政讓玄冥，一雪填門訝許平。',64,'全唐诗/poet.song.122000.json','["勾芒新政讓玄冥，一雪填門訝許平。", "不夜乾坤月留照，無塵世界玉裝成。", "如何辨認梅花發，只得誇張柳絮輕。", "數片簷前休掃去，且留窗下快書生。"]'),
('82d6146f-3ee9-4ff8-aa05-5aed6940cb49','月湖山谷勸耕次韻','鄧深','宋','宋诗','song-poetry','','[]','皂蓋朱幡遊近郭，野桃山杏炫紅旂。',64,'全唐诗/poet.song.122000.json','["皂蓋朱幡遊近郭，野桃山杏炫紅旂。", "看看新燕啣泥候，恰恰鳴鳩喚雨時。", "未用經丘思靖節，何妨學稼許樊遲。", "老農應悉使君意，六勸傳教到處知。"]'),
('e967f62a-50c6-452a-a454-4286ad059d05','陪吳正字賞花詩','鄧深','宋','宋诗','song-poetry','','[]','名園無物不芳妍，上箇籃輿緩遶旋。',64,'全唐诗/poet.song.122000.json','["名園無物不芳妍，上箇籃輿緩遶旋。", "曲徑幽亭留客地，微雲淡日養花天。", "四時公舉春爲最，萬事銓量酒是先。", "管領風光須一醉，要看詩筆落雲烟。"]'),
('4c513d95-7a9a-4a8c-a6ca-a7f390d6b1d6','橘花','鄧深','宋','宋诗','song-poetry','','[]','糝枝碎玉吐香奇，鼻觀頻參試論之。',64,'全唐诗/poet.song.122000.json','["糝枝碎玉吐香奇，鼻觀頻參試論之。", "清比木犀雖未的，烈如茉莉已無疑。", "自從白雪避花後，更好黄金鑄實時。", "四老隱居宜取此，可能無意賦新詩。"]'),
('e5366f09-6b4c-4368-a7f5-fdc9739b2de2','晚春','鄧深','宋','宋诗','song-poetry','','[]','雨催柔綠上桑枝，新霽浮雲未盡歸。',64,'全唐诗/poet.song.122000.json','["雨催柔綠上桑枝，新霽浮雲未盡歸。", "寂寂簾櫳留燕舞，陰陰楊柳護鶯衣。", "莫于綺席嫌籌併，已覺青春作鳥飛。", "滿徑落花愁踏損，羊欣切勿款柴扉。"]'),
('0586cb39-0b2f-427a-a7d6-7f8ba52fabb1','次韻晚春','鄧深','宋','宋诗','song-poetry','','[]','閬仙晦日惜春歸，尚喜爭他五日遲。',64,'全唐诗/poet.song.122000.json','["閬仙晦日惜春歸，尚喜爭他五日遲。", "延蝶晚花餘小蒨，藏鶯暗柳盡低垂。", "頻催布穀能謀野，苦勸提壺殆爲私。", "寄語社中須痛飲，喜晴山色也開眉。"]'),
('9068f6a8-c705-4310-b98d-0d6b06e746b0','夏日寓山齋','鄧深','宋','宋诗','song-poetry','','[]','山齋長夏斷過從，掃地長教塵滅蹤。',64,'全唐诗/poet.song.122000.json','["山齋長夏斷過從，掃地長教塵滅蹤。", "松架青毛雲翳日，扇摇白翅雪生風。", "書床琴匣時相近，茶鼎燻爐間自供。", "心地清凉無熱惱，炎天直與冷秋同。"]'),
('a6d9d561-7b4a-485e-a99c-aa1ab81f913d','鑑堂初夏把酒','鄧深','宋','宋诗','song-poetry','','[]','新笋過林竹有筠，老蠶登箔繭成身。',64,'全唐诗/poet.song.122000.json','["新笋過林竹有筠，老蠶登箔繭成身。", "日穿雲出潜驅霧，風捲花飛猛送春。", "乳燕簾櫳中晝後，綠陰池館一番新。", "欲酬佳致須何物，莫厭芳醪滿入唇。"]'),
('059d9b2a-81a4-40f1-b70c-24e8af3bac36','漕司君子堂把酒','鄧深','宋','宋诗','song-poetry','','[]','擁岸芙蓉媚晚秋，敗荷顛倒雨初收。',64,'全唐诗/poet.song.122000.json','["擁岸芙蓉媚晚秋，敗荷顛倒雨初收。", "盃盤不料今朝款，杖履如陪昔日遊。", "竹逕以東藏曲折，水村而下轉清幽。", "穉松戢戢存遺愛，不用詩來問好不。"]'),
('19426e6d-ef0b-4c65-831d-2d45c65d963e','喜雨','鄧深','宋','宋诗','song-poetry','','[]','間點疏花稻已香，老農猶未擬豐穰。',64,'全唐诗/poet.song.122000.json','["間點疏花稻已香，老農猶未擬豐穰。", "不堪雌霓頻妨雨，反厭雄風但作凉。", "傍日猖狂唯野馬，爲霖信息欠商羊。", "忽驚頭上雲雷集，甘注如傾洗夕陽。"]'),
('76d3741d-ace7-4116-85c1-51a2f9827e6a','月湖禱雨有應李渭賦詩次韻併呈','鄧深','宋','宋诗','song-poetry','','[]','一雨端由誠意通，不然筆落有神功。',64,'全唐诗/poet.song.122000.json','["一雨端由誠意通，不然筆落有神功。", "奔雲擁樹千山黑，迅電翻江萬丈紅。", "黍稷盈疇纔可望，塵埃瞇眼頓成空。", "民間歲晚知何事，飽飯無憂屬兩公。"]'),
('4613304c-8521-4915-829f-e9699f4221fe','秋大閱呈月湖先生','鄧深','宋','宋诗','song-poetry','','[]','將兵還似將風騷，軍帳從容自不勞。',64,'全唐诗/poet.song.122000.json','["將兵還似將風騷，軍帳從容自不勞。", "鼓角悲風肅人馬，旌旗蔽日閃弓刀。", "折衝正自煩樽俎，急檄寧聞借羽毛。", "洗眼臨淮新號令，憑誰挑戰醉揮毫。"]'),
('000b9ce3-faa2-458c-891a-8d12dd76fcd7','七夕競渡','鄧深','宋','宋诗','song-poetry','','[]','水馬相先急畫橈，朱樓紅粉宴笙簫。',64,'全唐诗/poet.song.122000.json','["水馬相先急畫橈，朱樓紅粉宴笙簫。", "月中誰念穿綵線，江上齊看奪錦標。", "冷眼諸人旁賈勇，爭頭一鼓喜成謠。", "憑誰試展乘槎手，直入銀灣看鵲橋。"]'),
('369ceaa9-9171-45fe-8ff6-ffafbb89cfa2','十四夜賞月','鄧深','宋','宋诗','song-poetry','','[]','月嬋娟對竹嬋娟，竹影蕭疏月轉妍。',64,'全唐诗/poet.song.122000.json','["月嬋娟對竹嬋娟，竹影蕭疏月轉妍。", "纔過中庭十分好，直疑明晚一般圓。", "銀河漾漾無塵界，玉宇昭昭不夜天。", "君飲不多須强飲，何妨醉裏却逃禪。"]'),
('c7d36cd7-7d87-4d95-9a55-ec857bd152a8','夜興','鄧深','宋','宋诗','song-poetry','','[]','官舍渾如僧舍幽，爐香靜坐興悠悠。',64,'全唐诗/poet.song.122000.json','["官舍渾如僧舍幽，爐香靜坐興悠悠。", "一窗燈火鳴蛩夜，千里湖山落鴈秋。", "只恐有詩成筆下，自餘無事到心頭。", "何妨信手翻書卷，不限更深困即休。"]'),
('7bae35e5-7289-4042-8c6d-428465d311be','九日靈興山沽酒賞菊','鄧深','宋','宋诗','song-poetry','','[]','眾山環遶一溪斜，低小軒窗眺望賒。',64,'全唐诗/poet.song.122000.json','["眾山環遶一溪斜，低小軒窗眺望賒。", "行遣方兄尋野店，坐邀歡伯過仙家。", "多情戀頂烏紗帽，不語向人黄菊花。", "山月上時歸更好，何妨有待至昏鴉。"]'),
('c4c0d24b-3464-4e48-b46f-001ff5e89015','重九宿王孫舖','鄧深','宋','宋诗','song-poetry','','[]','蘭江路盡接荆江，竹屋蕭條草樹荒。',64,'全唐诗/poet.song.122000.json','["蘭江路盡接荆江，竹屋蕭條草樹荒。", "許久長晴坐極暑，霎時疏雨做重陽。", "明眸縱少新開菊，隨量何妨淺舉觴。", "驛舍明朝便陳跡，牛山往事莫徒傷。"]'),
('3a2eca42-745f-4e1e-a02e-8cc49d413558','前五日賦重九','鄧深','宋','宋诗','song-poetry','','[]','侵尋重九雨餘秋，采菊登高事事幽。',64,'全唐诗/poet.song.122000.json','["侵尋重九雨餘秋，采菊登高事事幽。", "偶爾見山忘日夕，頹然落帽自風流。", "二三日外追清賞，千百年間繼舊遊。", "爛漫賦詩兼酩酊，不然嘉節若爲酬。"]'),
('f4807f53-f02d-4005-bc29-99a6fb9493a6','九日方壺','鄧深','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','返照重城暮色催，人家十萬出樓臺。',64,'全唐诗/poet.song.122000.json','["返照重城暮色催，人家十萬出樓臺。", "江流湛湛洞庭去，山色青青衡岳來。", "佳處綠樽窮日飲，故園黄菊向誰開。", "人間此會論今古，醉聽西風拂帽埃。"]'),
('24b321f0-6025-4a08-81dc-f8de0d361668','晚秋懷社中諸子','鄧深','宋','宋诗','song-poetry','','[]','池塘水落倒枯荷，橘綠橙黄晚菊多。',64,'全唐诗/poet.song.122000.json','["池塘水落倒枯荷，橘綠橙黄晚菊多。", "日暖懷沙鼈衷甲，霜清奔火蟹橫戈。", "如今時節從來好，得醉工夫似舊麽。", "儻有征鴻過巫峽，待憑詩句問如何。"]'),
('9111dd01-f42c-40ec-b667-0bc7eb43b861','次韻賦十月桃爲羅司理生朝','鄧深','宋','宋诗','song-poetry','','[]','根苗不自武陵鄉，挾暖凌寒獨有光。',64,'全唐诗/poet.song.122000.json','["根苗不自武陵鄉，挾暖凌寒獨有光。", "韻過海棠春带露，紅羞籬菊晚經霜。", "宅仙本結千年實，瑞世仍開十月芳。", "過插一枝誰稱面，後堂楊柳舞霓裳。"]'),
('2d2ad003-9e8a-411c-9115-a4197a579a0b','梅方開一花','鄧深','宋','宋诗','song-poetry','','[]','烟村清淺白沙溪，籬落槎枒老樹枝。',64,'全唐诗/poet.song.122000.json','["烟村清淺白沙溪，籬落槎枒老樹枝。", "一朵梅開如許早，幾多人過不曾知。", "風前遇我還青眼，花裏推渠是白眉。", "未辦酒樽澆磊塊，試憑詩句寫新奇。"]'),
('ebb0aece-9b2d-4fd9-9cea-f92954d11e38','早梅','鄧深','宋','宋诗','song-poetry','','[]','荒村野水小春時，縱有梅開人未知。',64,'全唐诗/poet.song.122000.json','["荒村野水小春時，縱有梅開人未知。", "幾度携筇無覓處，今朝映竹忽橫枝。", "脫非入骨清香動，恐被傳神淡墨欺。", "酸意中含和鼎實，相期遠到誦黄詩。"]'),
('20dedacb-7836-4f7a-877d-2a3071e8d3a7','臘月立春','鄧深','宋','宋诗','song-poetry','','[]','柳條弄色舞輕風，不與尋常歲暮同。',64,'全唐诗/poet.song.122000.json','["柳條弄色舞輕風，不與尋常歲暮同。", "寒氣望塵先歛退，陽和發軔已交通。", "菜絲盤玉還充席，幡字花房正代功。", "首迓東皇須痛飲，可能無句著新工。"]'),
('f2d071b4-006b-43f2-a34d-42cd4c2d6493','歲暮寄蘭窗兄在郴陽','鄧深','宋','宋诗','song-poetry','','[]','每日登樓望欲迷，家書寫罷復題詩。',64,'全唐诗/poet.song.122000.json','["每日登樓望欲迷，家書寫罷復題詩。", "對床夜雨還非昨，啜茗春風未可期。", "歲月催人驚合沓，夢魂覓路苦參差。", "也應梅竹多新句，千里因風慰我思。"]'),
('c9d906c1-670f-4576-8046-0604ac9cfadb','寄饒雲叟','鄧深','宋','宋诗','song-poetry','','[]','別來每辱遺雙鯉，頗怪吾儂不作書。',64,'全唐诗/poet.song.122000.json','["別來每辱遺雙鯉，頗怪吾儂不作書。", "非爲廣文官獨冷，自緣中散性常疏。", "靜暉待月昏鐘後，制勝登高曉雨餘。", "正憶去年同此會，只今相望問何如。"]'),
('f0055f06-97b3-4fd7-9674-ed6555be05b4','月湖樓晚霽呈侍郎','鄧深','宋','宋诗','song-poetry','','[]','湖光灧灧水平堤，醉倚欄干晚霽時。',64,'全唐诗/poet.song.122000.json','["湖光灧灧水平堤，醉倚欄干晚霽時。", "入鏡往來人倒影，窺天拂掠燕低飛。", "雨痕猶向梅粧見，風色偏於柳線知。", "景物相撩無好句，乞公詩作畫圖歸。"]'),
('7d8e7f28-b35e-432e-93e6-34d7ed1b0c40','內集閣','鄧深','宋','宋诗','song-poetry','','[]','畫閣深明雪壓冬，團欒宴賞酒樽同。',64,'全唐诗/poet.song.122000.json','["畫閣深明雪壓冬，團欒宴賞酒樽同。", "獸爐香霧辟寒氣，翠幙妓圍回暖風。", "起絮撒鹽酬唱外，清歌妙舞笑談中。", "寧無好事賢張禹，不獨相忘著戴崇。"]'),
('28cbe589-8b4b-46bc-98a1-54ba490b57bd','晚坐散花之室','鄧深','宋','宋诗','song-poetry','','[]','官居無處寄幽棲，洞戶深沉坐最宜。',64,'全唐诗/poet.song.122000.json','["官居無處寄幽棲，洞戶深沉坐最宜。", "靜撥爐薰挹香氣，間論畫壁數花枝。", "蟲鳴頗似雁來後，果熟還如鶯老時。", "吹徹角聲巫峽晚，片雲催雨更催詩。"]'),
('76626cc3-59a2-42ff-82f9-691637a679a1','玉虛洞其上有日月之象其旁有龍象之形','鄧深','宋','宋诗','song-poetry','','[]','立馬香溪喚渡船，羊腸遶盡洞呀然。',64,'全唐诗/poet.song.122000.json','["立馬香溪喚渡船，羊腸遶盡洞呀然。", "知誰開闢羣工巧，直許寬虛一室圓。", "龍象現形嚴佛土，烏蟾垂象燭壺天。", "惜哉不遇東坡賞，爲作新詩與世傳。"]'),
('6cc5a4c8-b6c9-4412-9c47-3dc7dae49623','市橋成次韻','鄧深','宋','宋诗','song-poetry','','[]','雷雹平時生馬蹄，偶衝暴漲去難追。',64,'全唐诗/poet.song.122000.json','["雷雹平時生馬蹄，偶衝暴漲去難追。", "一年病涉愁無奈，今日安行喜可知。", "虹飲江頭愁雨霽，龍橫水面暮雲垂。", "却憐舟楫無人渡，借我江心理釣絲。"]'),
('62cc412b-3373-4b61-9b28-1f25580cc30a','峽江','鄧深','宋','宋诗','song-poetry','','[]','擊電浮霜浪作堆，峽江試險眼初開。',64,'全唐诗/poet.song.122000.json','["擊電浮霜浪作堆，峽江試險眼初開。", "常驚四畔山圍繞，不見中間水去來。", "石出多奇吾甚愛，舟移太疾首頻回。", "瀕涯穩處憑誰問，我欲其間作釣臺。"]'),
('6403fe32-4120-45e0-90d7-d0799c709e0f','柔遠樓','鄧深','宋','宋诗','song-poetry','','[]','柔遠樓高豁寸眸，白鹽赤甲鎖關頭。',64,'全唐诗/poet.song.122000.json','["柔遠樓高豁寸眸，白鹽赤甲鎖關頭。", "四川形勝當前險，三峽波濤據上游。", "鳥道極天雲日近，靴城匝地市烟浮。", "時平久矣無戎馬，回首當年老杜憂。"]'),
('88059d4e-6ec7-4f53-8642-365cc385f91d','賦清映閣','鄧深','宋','宋诗','song-poetry','','[]','數椽茅屋小橋頭，地段無多景自幽。',64,'全唐诗/poet.song.122000.json','["數椽茅屋小橋頭，地段無多景自幽。", "爲愛平池三尺水，最宜明月一輪秋。", "靜留人影摇歌扇，輕動風漣下釣鈎。", "相去幽居無十步，不論時節恣來遊。"]'),
('83744c1d-84be-4f1a-a00d-af3f5ba52351','同友人新陂莊少憩','鄧深','宋','宋诗','song-poetry','','[]','家家轣轆絡絲聲，竹杖芒鞋取次行。',64,'全唐诗/poet.song.122000.json','["家家轣轆絡絲聲，竹杖芒鞋取次行。", "村笛牧羊烟欲暝，農歌秧稻雨初晴。", "隨瓶沽得酒堪醉，就野挑來菜可羹。", "此是田家真况味，吾曹借取片時清。"]'),
('e0d0f863-5f45-41ee-97e3-ae73b54fe063','賦清曠亭','鄧深','宋','宋诗','song-poetry','','[]','半村半郭事林丘，非閣非船傍釣舟。',64,'全唐诗/poet.song.122000.json','["半村半郭事林丘，非閣非船傍釣舟。", "秋月無邊凉細細，江天不盡水悠悠。", "誰開圖畫當前面，絕點塵埃到上頭。", "我輩不妨頻假榻，主人應喜共盟鷗。"]'),
('ecb4c0ca-8b53-4195-a75b-e140f9e6e107','登光寺塔','鄧深','宋','宋诗','song-poetry','','[]','凱之曾說越中行，塔級親登眼始驚。',64,'全唐诗/poet.song.122000.json','["凱之曾說越中行，塔級親登眼始驚。", "畫合千山翠濃淡，枝分萬水練縱橫。", "樹頭低壓昏烟重，鶴背斜拖夕照明。", "疑是丹成生羽翼，泠然雲表御風清。"]'),
('18fc1744-d1dc-4ef5-8884-26c913bfdc78','同廷美兄宿龍福寺','鄧深','宋','宋诗','song-poetry','','[]','峰回路轉竹間扃，古寺尋幽當下程。',64,'全唐诗/poet.song.122000.json','["峰回路轉竹間扃，古寺尋幽當下程。", "淺屋近山寒較早，小窗容榻意偏清。", "睡魔催枕如元約，山鬼吹燈似薄情。", "樽酒重溫休惜醉，恐君長夜厭蛩聲。"]'),
('86e092cf-2018-45ab-a426-adf70724dea9','過呂坊渡','鄧深','宋','宋诗','song-poetry','','[]','江闊寒風痛括肌，村醪無力破寒威。',64,'全唐诗/poet.song.122000.json','["江闊寒風痛括肌，村醪無力破寒威。", "融霜點滴松間雨，愛日晴明身上衣。", "闖竹柴扉黄犬吠，卧沙蓬艇白鷗飛。", "燒痕已覺春來近，稍放青青出土肥。"]'),
('e409f337-a4bb-4954-b9fe-36da3cc03734','自賦大隱','鄧深','宋','宋诗','song-poetry','','[]','柴門雖設日常關，衹有琴書几案間。',64,'全唐诗/poet.song.122000.json','["柴門雖設日常關，衹有琴書几案間。", "屋宇無多聊近市，塵埃不到即深山。", "悠悠世事非吾事，往往雲閒是我閒。", "出處尚疑陶靖節，倦如飛鳥始知還。"]'),
('75abb2b2-bad4-4609-aa5e-d0454123365e','賦芷','鄧深','宋','宋诗','song-poetry','','[]','縹裁衣袂紫中單，觸眼亭亭露未乾。',64,'全唐诗/poet.song.122000.json','["縹裁衣袂紫中單，觸眼亭亭露未乾。", "態度全然逼秋蕙，馨香的不讓春蘭。", "數枝瀟灑北窗晝，一室清幽六月寒。", "了不知名疑是芷，賦前詩後兩存看。"]'),
('f6061102-8fa8-47c6-9bbb-5022f3c22649','寄月湖先生兼簡渭叟','鄧深','宋','宋诗','song-poetry','','[]','山莊杖屨飽相從，每月須拚十日中。',64,'全唐诗/poet.song.122000.json','["山莊杖屨飽相從，每月須拚十日中。", "鼎足三人同宿留，甕頭一盞奉從容。", "別來不隔千山月，舊賞難乘兩腋風。", "更想先生新活計，烟波別業興方濃。"]'),
('4bd93d40-b78c-4f87-82d7-5633dac2d131','贈別饒雲叟赴萬州教官','鄧深','宋','宋诗','song-poetry','','[]','話別哦詩當酒甌，竹萌成笋麥方秋。',64,'全唐诗/poet.song.122000.json','["話別哦詩當酒甌，竹萌成笋麥方秋。", "數聲春後呼風鳥，百丈朝來送浪舟。", "已得通津好消息，何妨舊物小淹留。", "到官應動鄉關思，南浦西山若箇優。"]'),
('d7156210-f1ca-49f7-bc71-f914074d9f08','遣興次韻','鄧深','宋','宋诗','song-poetry','','[]','山閣舂容丈尺間，元無俗事撓清閒。',64,'全唐诗/poet.song.122000.json','["山閣舂容丈尺間，元無俗事撓清閒。", "有時把筆抄新句，整日開窗對舊山。", "葉帳靜看青似染，禽言細聽字終蠻。", "可憐蜂子尊王意，每到衙時似趁班。"]'),
('39dd71d5-4539-4a21-8321-c1fcca367261','追送何伯憲不及','鄧深','宋','宋诗','song-poetry','','[]','追送無從謾寄詩，道間安穩我能知。',64,'全唐诗/poet.song.122000.json','["追送無從謾寄詩，道間安穩我能知。", "情懷亦似居家樂，笑語依然奉母慈。", "巴水柳風新霽後，錢塘花雨暮春時。", "乃翁邂逅詢佳况，膝上時時置坦之。"]'),
('4a9bb885-4538-4e0d-8744-14fd993ab2c3','送王敦素','鄧深','宋','宋诗','song-poetry','','[]','龍蟠山色引衡廬，霜落江清影碧虛。',64,'全唐诗/poet.song.122000.json','["龍蟠山色引衡廬，霜落江清影碧虛。", "鼓枻厭騎沙苑馬，行厨飫食武昌魚。", "緩歌玉樹翻新曲，趣入金鑾續舊書。", "官達故人稀會面，君來相見肯如初。"]'),
('290c8a5b-7725-4b57-9342-2f8840672168','次韻方德秀','鄧深','宋','宋诗','song-poetry','','[]','清風一榻借冰壺，邂逅相逢日與俱。',64,'全唐诗/poet.song.122000.json','["清風一榻借冰壺，邂逅相逢日與俱。", "學辯癡龍君有見，詩窮饞犬我何癯。", "似聞圓覺常開卷，未到方橋欲問途。", "稍待秋風凉冷後，相從十日却歸歟。"]'),
('262a5984-b665-4546-a559-556a59ac2e71','次韻歐陽天聰','鄧深','宋','宋诗','song-poetry','','[]','今古由來幾廢興，人生底事謾勞生。',64,'全唐诗/poet.song.122000.json','["今古由來幾廢興，人生底事謾勞生。", "一身休作籠中鳥，萬事終歸牆角檠。", "且與風光閒作主，莫於詩社倦尋盟。", "相從只麽消閒暇，自快人間物外情。"]'),
('e0f86d68-3986-4e0f-9070-206c4e32aaed','次韻吳文美','鄧深','宋','宋诗','song-poetry','','[]','决科君輩不須疑，好采來如博局嬉。',64,'全唐诗/poet.song.122000.json','["决科君輩不須疑，好采來如博局嬉。", "拾芥紫青非外事，舉杯富貴可前期。", "相將競奏大人賦，慫恿常談小子詩。", "接武虞廷須八凱，潁陽深遁我何知。"]'),
('731ab57a-d65b-4cbc-8037-d94d30ffcba2','次韻答克修','鄧深','宋','宋诗','song-poetry','','[]','懶慢相成拙似初，親朋莫問近何如。',64,'全唐诗/poet.song.122000.json','["懶慢相成拙似初，親朋莫問近何如。", "居然野性成孤鶴，聊爾塵編撲蠹魚。", "才比劉牆猶自短，詩如陶粟了無儲。", "驪珠相畀知君厚，燕石輕酬笑我疏。"]'),
('ec6a192e-aefe-49ed-899c-662a7b64bc4d','又次韻答克修','鄧深','宋','宋诗','song-poetry','','[]','前回藜杖遶芳郊，底處梅花出好梢。',64,'全唐诗/poet.song.122000.json','["前回藜杖遶芳郊，底處梅花出好梢。", "野彴低橫盈尺水，竹籬深護數家茅。", "春風桃李成生客，臘雪松筠是故交。", "剩欲再携樽酒去，柴門應復許人敲。"]'),
('47cbce65-46fa-47c6-92ae-07e2db3fc66c','次韻答周公美','鄧深','宋','宋诗','song-poetry','','[]','溫風慫恿柳婆娑，兩見春來蜂蝶多。',64,'全唐诗/poet.song.122000.json','["溫風慫恿柳婆娑，兩見春來蜂蝶多。", "遷變時光如轉燭，遲留日影欠揮戈。", "思君欲問加餐未，苦思能令太瘦麽。", "歲晚忘言除習氣，寒灰試共撥陰何。"]'),
('f2103778-f3ab-476a-a807-df5d7bb386c1','次韻答公美二首  其一','鄧深','宋','宋诗','song-poetry','','[]','幽居正傍小溪斜，想見樵風似若耶。',64,'全唐诗/poet.song.122000.json','["幽居正傍小溪斜，想見樵風似若耶。", "固有詩章舒眼界，可無藥物助脾家。", "追歡難共長沙酒，遣睡姑嘗陸羽茶。", "更祝安心爲妙法，都將世事等空花。"]'),
('3f80ea86-7053-44b4-bff8-7b18cf7dd760','次韻答公美二首  其二','鄧深','宋','宋诗','song-poetry','','[]','四至長沙熟物情，留題勝處記吾曾。',64,'全唐诗/poet.song.122000.json','["四至長沙熟物情，留題勝處記吾曾。", "三生會是湖湘客，一鉢渾如雲水僧。", "贏得身輕閒有味，儘從人笑老無能。", "如君應飽田園樂，猶道啼饑有怨憎。"]'),
('d1b75d6e-b90a-439b-a1db-9c5f34277661','謁何世南','鄧深','宋','宋诗','song-poetry','','[]','愚溪草聖祖鍾王，宰木今傷葉屢黄。',64,'全唐诗/poet.song.122000.json','["愚溪草聖祖鍾王，宰木今傷葉屢黄。", "何處卷藏雲滿紙，唯君護惜錦成囊。", "不聆洒翰音聲入，欲認驚龍氣焰長。", "一見自消饑渴念，天厨珍味不須嘗。"]'),
('ac47ea42-5767-4dee-a4df-0d84166bc2c1','謁趙徽猷','鄧深','宋','宋诗','song-poetry','','[]','把麾持節舊鄉關，雖幸爲眠一枕安。',64,'全唐诗/poet.song.122000.json','["把麾持節舊鄉關，雖幸爲眠一枕安。", "未睹青天孤此眼，不圖今日見公顔。", "雲烟秋霽湖山靜，霜月晨清橘柚寒。", "應屬詩翁搜好句，相從正願得窺斑。"]'),
('3b6db63b-af30-4771-b2ab-d88083fb0528','再用韻','鄧深','宋','宋诗','song-poetry','','[]','葛巾藜杖款重關，不獨風流識謝安。',64,'全唐诗/poet.song.122000.json','["葛巾藜杖款重關，不獨風流識謝安。", "蘭玉滿庭驚醉眼，雲烟落紙照衰顔。", "也知鴻雁行應起，莫管鳧鷗盟漸寒。", "自笑斷鬚安字拙，空令短髮作詩斑。"]'),
('85510244-97c8-445f-82ea-387de5a8e6f0','懷清曠兄弟','鄧深','宋','宋诗','song-poetry','','[]','可觀閣上借牀眠，明月清風不用錢。',64,'全唐诗/poet.song.122000.json','["可觀閣上借牀眠，明月清風不用錢。", "會面向來無空日，離羣何事有經年。", "相望千思江湖地，正坐三秋風雨天。", "耿耿青燈空透影，可堪新雁一聲傳。"]'),
('9ce84b86-708a-4a18-a38b-1bacbd092f1b','夔府長至諸州之酒畢集每品嘗之或有味而無香或有香而無色月湖一日命酒匠置大甕悉以酒投其中而和之不費麯糵逡巡而化洗盞一吸奇絕出於意外于是從新封泥名之曰十州春請以七言賦之','鄧深','宋','宋诗','song-poetry','','[]','樽中賢聖雜然陳，點化須臾清且醇。',64,'全唐诗/poet.song.122000.json','["樽中賢聖雜然陳，點化須臾清且醇。", "味壓宜城九醞酒，名高夔府十州春。", "投丸仙子難爭手，合麯香山未盡神。", "從事有靈應自慶，而今十部萃吾身。"]'),
('c6096bef-7b18-41ee-bb01-f5b29c9fecff','村中病起','鄧深','宋','宋诗','song-poetry','','[]','訪醫墟落疾難痊，肘後奇方得舊編。',64,'全唐诗/poet.song.122000.json','["訪醫墟落疾難痊，肘後奇方得舊編。", "藥濟君臣親劑和，火停文武事烹煎。", "旁人笑道徒爲爾，午睡醒來已脫然。", "從此節宣防未病，那須扁鵲信真傳。"]'),
('cf7bb85a-240a-49c5-baa3-a3be39f081ed','贈唐道士','鄧深','宋','宋诗','song-poetry','','["\u8861\u5c71"]','靈應堂中一羽衣，衡山來此住多時。',64,'全唐诗/poet.song.122000.json','["靈應堂中一羽衣，衡山來此住多時。", "困來拂榻終朝卧，醉後敲門半夜歸。", "留客屢嘗教買酒，向人長自說吟詩。", "開軒略種閒花木，此外懸知少是非。"]'),
('69f3d537-16f0-4047-b44c-79cd58a3c9e2','畫壁','鄧深','宋','宋诗','song-poetry','','[]','松柏雙雙夾竹青，來遊仙客稱閒情。',64,'全唐诗/poet.song.122000.json','["松柏雙雙夾竹青，來遊仙客稱閒情。", "一時幻出誰能爾，四者依然太瘦生。", "鬰鬰相交堪掬翠，昂昂自得若聞聲。", "如何艷冶容繁杏，殆恐人嫌境過清。"]'),
('12b92dcd-4c2d-457a-b4b9-71dddd4f7a07','鐵拄杖次韻答趙侍郎','鄧深','宋','宋诗','song-poetry','','[]','非竹非藤性最剛，鐵君風骨凜秋霜。',64,'全唐诗/poet.song.122000.json','["非竹非藤性最剛，鐵君風骨凜秋霜。", "清堅閱世千年久，正直持身九節長。", "宜向山林扶矍鑠，難隨車馬入康莊。", "只愁雷電搜蛟蜃，併及新詩不許藏。"]'),
('445480d0-4009-485c-9282-f8b3fe3ca428','嘗雲安麴米春','鄧深','宋','宋诗','song-poetry','','[]','名自雲安已久傳，未嘗先覺口流涎。',64,'全唐诗/poet.song.122000.json','["名自雲安已久傳，未嘗先覺口流涎。", "三杯通道正須此，一盞醺人今信然。", "取醉間關憐杜老，聞香比擬憶蘇僊。", "豈知閒散江湖客，快飲瞿唐灧澦邊。"]'),
('1494b903-4357-4ebf-bbb0-2338ae0b01cf','何先生月湖樓','鄧深','宋','宋诗','song-poetry','','[]','青天素月古今流，奇觀還須自我謀。',64,'全唐诗/poet.song.122000.json','["青天素月古今流，奇觀還須自我謀。", "照有餘輝眾人共，取之不禁此湖收。", "水容天色交光處，玉鑑冰壺不夜秋。", "俯仰無塵清絕甚，欄干百尺獨宜搜。"]'),
('165e4f9e-5e7f-4e4e-b3c7-2d960696f803','書事','鄧深','宋','宋诗','song-poetry','','[]','柱礎晝生水，雲雷暮出山。',24,'全唐诗/poet.song.122000.json','["柱礎晝生水，雲雷暮出山。", "天時已秋杪，氣候尚春間。"]'),
('43a08bf2-6545-4aed-ab36-55d5faf30e44','伏暑','鄧深','宋','宋诗','song-poetry','','[]','正覺纖絺便，未容團扇閒。',24,'全唐诗/poet.song.122000.json','["正覺纖絺便，未容團扇閒。", "兒童昧災變，赤體更歡顔。"]'),
('b8dd8046-d9d4-49cf-8ece-4901d111e340','野外新秋','鄧深','宋','宋诗','song-poetry','','[]','平野寬無際，層雲撥不開。',24,'全唐诗/poet.song.122000.json','["平野寬無際，層雲撥不開。", "曉容收雨後，凉意送秋來。"]'),
('e5f7ef16-3af4-4881-8ccf-44ec45b5201f','野眺即景','鄧深','宋','宋诗','song-poetry','','[]','山晚餘紅照，林昏集眾鴉。',24,'全唐诗/poet.song.122000.json','["山晚餘紅照，林昏集眾鴉。", "泥深茭欲笋，水滿稻初花。"]'),
('48f818a0-576e-487e-88e3-3dfa55e4112f','江亭','鄧深','宋','宋诗','song-poetry','','[]','村舍隨山遠，沙寮傍岸還。',24,'全唐诗/poet.song.122000.json','["村舍隨山遠，沙寮傍岸還。", "輕烟魚復浦，殘雪手巾山。"]'),
('a62889f7-164b-469b-8338-03a46735e187','散花之室六言  其一','鄧深','宋','宋诗','song-poetry','','[]','無動現身說法，毗耶到處爲家。',28,'全唐诗/poet.song.122000.json','["無動現身說法，毗耶到處爲家。", "誰識逢場作戲，從教現女散花。"]'),
('8184661c-4151-45d3-b841-1e059acff13d','散花之室六言  其二','鄧深','宋','宋诗','song-poetry','','[]','本有獻花佛事，何妨乞食歌姬。',28,'全唐诗/poet.song.122000.json','["本有獻花佛事，何妨乞食歌姬。", "若了悟不住相，斯參透無言師。"]'),
('ff17358e-fe29-4d5e-ba5a-69ea4935d355','賦張以道寒綠  其一','鄧深','宋','宋诗','song-poetry','','[]','領略一軒寒綠，掃除萬種春紅。',28,'全唐诗/poet.song.122000.json','["領略一軒寒綠，掃除萬種春紅。", "飽取披烟沐雨，全勝抹月批風。"]'),
('7081677c-4363-4942-8a87-2b39fff8deff','賦張以道寒綠  其二','鄧深','宋','宋诗','song-poetry','','[]','百世東坡居士，千秋甫里先生。',28,'全唐诗/poet.song.122000.json','["百世東坡居士，千秋甫里先生。", "近識南湖高隱，相望今古同情。"]'),
('55908c37-f145-4632-a20c-222105190395','冬郊','鄧深','宋','宋诗','song-poetry','','[]','荒草岡頭牧笛，急舂屋角吹煙。',28,'全唐诗/poet.song.122000.json','["荒草岡頭牧笛，急舂屋角吹煙。", "短景做催冬日，微暖號小春天。"]'),
('55967b4c-bbc7-4026-b781-3ad2869bb510','枇杷六言','鄧深','宋','宋诗','song-poetry','','[]','大似明珠徑寸，黄如香蠟成丸。',28,'全唐诗/poet.song.122000.json','["大似明珠徑寸，黄如香蠟成丸。", "落處韓嫣遺彈，可憐不救饑寒。"]'),
('9ecc990f-775d-4363-9af9-c7ad9b4090d7','仲春即事','鄧深','宋','宋诗','song-poetry','','[]','嘲弄春晴禽鬭語，揄揚風色柳摇絲。',32,'全唐诗/poet.song.122000.json','["嘲弄春晴禽鬭語，揄揚風色柳摇絲。", "麥苗含穗枇杷熟，却似江南四月時。"]'),
('cdb70e7e-6093-4c5b-a7ec-70b1fb9bac15','楊花','鄧深','宋','宋诗','song-poetry','','[]','楊花似雪雪應嗔，散漫輕飛太逼真。',32,'全唐诗/poet.song.122000.json','["楊花似雪雪應嗔，散漫輕飛太逼真。", "結習已消那得住，却沾塵土不沾身。"]'),
('e2346556-0272-4ba1-8925-5b9936e49686','睡起','鄧深','宋','宋诗','song-poetry','','[]','案頭黄嬭溫存睡，榻上青奴誘引凉。',32,'全唐诗/poet.song.122000.json','["案頭黄嬭溫存睡，榻上青奴誘引凉。", "幽夢覺來山月上，一庭樹影滴金光。"]'),
('b89c7993-f3dc-40f0-b900-a5d8d1f78a30','晨雪渡洑陂','鄧深','宋','宋诗','song-poetry','','[]','竹外楊枝學小梅，竹間茅屋白皚皚。',32,'全唐诗/poet.song.122000.json','["竹外楊枝學小梅，竹間茅屋白皚皚。", "撐舟獨擁蓑衣出，堪畫何須待晚來。"]'),
('073a152d-4661-43ff-9043-fdd67d5cf4d3','雪消','鄧深','宋','宋诗','song-poetry','','[]','簷聲不斷元非雨，山色纔開豈是雲。',32,'全唐诗/poet.song.122000.json','["簷聲不斷元非雨，山色纔開豈是雲。", "萬象終然仍舊貫，詎須裝點巧紛紛。"]'),
('5b9902ea-3c81-4718-a7e8-a8fdd6715ec3','清曠靜坐','鄧深','宋','宋诗','song-poetry','','[]','草迷犢角掛林笋，風起繭毛揚樹花。',32,'全唐诗/poet.song.122000.json','["草迷犢角掛林笋，風起繭毛揚樹花。", "不見黄鶯飛上柳，得知深處暗藏鴉。"]'),
('66d6d88e-a36e-4fa3-a0a6-d1241c6dc2f5','偶感','鄧深','宋','宋诗','song-poetry','','[]','兀兀詩書早歲勤，而今掩卷養天真。',32,'全唐诗/poet.song.122000.json','["兀兀詩書早歲勤，而今掩卷養天真。", "政須無語參摩詰，底用清談學晉人。"]'),
('690e5942-535a-4def-9406-667dcb024421','即事六絕  其一','鄧深','宋','宋诗','song-poetry','','[]','卧櫓無聲百丈斜，牽夫匍匐入蘆花。',32,'全唐诗/poet.song.122000.json','["卧櫓無聲百丈斜，牽夫匍匐入蘆花。", "寒雲過雁愁相顧，踏損尋常落處沙。"]'),
('ac3fde82-eae0-497f-895b-06877dd1dc1e','即事六絕  其二','鄧深','宋','宋诗','song-poetry','','[]','凄風夜雨黄牛峽，愛日寒雲白狗岍。',32,'全唐诗/poet.song.122000.json','["凄風夜雨黄牛峽，愛日寒雲白狗岍。", "穩上瞿唐猶幾日，關山須看月初圓。"]'),
('daba4830-2b97-4f85-b0ca-706c16faae5b','即事六絕  其三','鄧深','宋','宋诗','song-poetry','','[]','舊年不雪新年雪，今日非春明日春。',32,'全唐诗/poet.song.122000.json','["舊年不雪新年雪，今日非春明日春。", "滕六勾芒真劣相，寒溫相語作比鄰。"]'),
('187318bd-ae34-48bf-bbbd-5dabbb39f3ee','即事六絕  其四','鄧深','宋','宋诗','song-poetry','','[]','纈紋斑駮遶山園，青带縈紆落澗泉。',32,'全唐诗/poet.song.122000.json','["纈紋斑駮遶山園，青带縈紆落澗泉。", "十月梨花開滿樹，直疑梅蘂破寒烟。"]'),
('fea3ff3c-24c5-452c-a35b-bb34630d5deb','即事六絕  其五','鄧深','宋','宋诗','song-poetry','','[]','昏烟漠漠雨霏霏，四月輕寒浸裌衣。',32,'全唐诗/poet.song.122000.json','["昏烟漠漠雨霏霏，四月輕寒浸裌衣。", "葉滿筠籃桑徑晚，杜鵑聲急楝花飛。"]'),
('0f3597ba-d435-49d8-88ab-6a3f0069b87c','即事六絕  其六','鄧深','宋','宋诗','song-poetry','','[]','林間無葉供風落，溪上有梅迎雪開。',32,'全唐诗/poet.song.122000.json','["林間無葉供風落，溪上有梅迎雪開。", "斜日未收門巷暖，兒童笑指蹇驢來。"]'),
('7c931ebc-246c-4a30-a3f5-363cab0bda63','翠竹人家','鄧深','宋','宋诗','song-poetry','','[]','戶外江平不肯流，短籬疏竹翠光浮。',32,'全唐诗/poet.song.122000.json','["戶外江平不肯流，短籬疏竹翠光浮。", "畦蔬遶舍畬田粟，一飽無求百不憂。"]'),
('c4023067-f64e-44c8-8c0d-51fb76d0ccd9','村童','鄧深','宋','宋诗','song-poetry','','[]','侵星裹飯下高山，負石趨城得米還。',32,'全唐诗/poet.song.122000.json','["侵星裹飯下高山，負石趨城得米還。", "不識往來爲幾里，衹言住處指雲間。"]'),
('4e9a94de-502d-43bf-b60c-990f384862d0','漁父詞二首  其一','鄧深','宋','宋诗','song-poetry','','[]','西風淅淅颭菰蒲，獨棹扁舟釣五湖。',32,'全唐诗/poet.song.122000.json','["西風淅淅颭菰蒲，獨棹扁舟釣五湖。", "買斷水鄉真樂處，月明雲冷笛聲孤。"]'),
('1e7b8a6b-b4be-4a2e-a923-ee960c9c7a41','漁父詞二首  其二','鄧深','宋','宋诗','song-poetry','','[]','活計平生一釣船，將魚換酒不論錢。',32,'全唐诗/poet.song.122000.json','["活計平生一釣船，將魚換酒不論錢。", "夜來醉倒蓬籠底，却在蘆花宿雁邊。"]'),
('0c79139f-11c1-46a2-84b7-f1ea5a896eaf','舟中即事三首  其一','鄧深','宋','宋诗','song-poetry','','[]','兩岸農家各自耕，相過正欠小舟撐。',32,'全唐诗/poet.song.122000.json','["兩岸農家各自耕，相過正欠小舟撐。", "牧童來往如平地，騎得吳牛入水行。"]'),
('f1e2c5a4-8f5b-4a7a-8269-d84affe44965','舟中即事三首  其二','鄧深','宋','宋诗','song-poetry','','[]','騰身赤鯉江心躍，浮鼻烏牛渡口過。',32,'全唐诗/poet.song.122000.json','["騰身赤鯉江心躍，浮鼻烏牛渡口過。", "雨後風清雲凈盡，一眉新月映寒波。"]'),
('2228f814-70c8-4f91-9655-078191f0a69f','舟中即事三首  其三','鄧深','宋','宋诗','song-poetry','','[]','曬翅鸕鶿映日斜，倒懸羣鴨趁魚蝦。',32,'全唐诗/poet.song.122000.json','["曬翅鸕鶿映日斜，倒懸羣鴨趁魚蝦。", "槿籬石徑通門處，茅屋松林賣酒家。"]'),
('8d839743-c558-4a7a-b6a4-35667e054269','雨卧舟中','鄧深','宋','宋诗','song-poetry','','[]','不許抬頭篷底下，僅容舒膝簟中間。',32,'全唐诗/poet.song.122000.json','["不許抬頭篷底下，僅容舒膝簟中間。", "聽風聽雨聽灘浪，纔得晴時出看山。"]'),
('91f0415a-9025-4c42-808c-304b7c8bef2e','樂口橋即事','鄧深','宋','宋诗','song-poetry','','[]','雨餘溪漲急機舂，緣岸人家柳弄風。',32,'全唐诗/poet.song.122000.json','["雨餘溪漲急機舂，緣岸人家柳弄風。", "路轉源深行步緩，青山映水野桃紅。"]'),
('be0b84c2-deba-4ff3-a2a5-88b000e8080f','宜春解纜','鄧深','宋','宋诗','song-poetry','','[]','江迥晨光獨早回，放船東下興悠哉。',32,'全唐诗/poet.song.122000.json','["江迥晨光獨早回，放船東下興悠哉。", "西風嫋嫋携將去，細雨冥冥看得來。"]'),
('f5fa270b-38b0-4e76-a3ac-bca859dddd82','瀼西亭即事','鄧深','宋','宋诗','song-poetry','','[]','危亭曲檻俯溪流，去去來來渡口舟。',32,'全唐诗/poet.song.122000.json','["危亭曲檻俯溪流，去去來來渡口舟。", "微雨不妨人刈麥，輕烟正可客垂鈎。"]'),
('d46524b2-e0d2-48d4-8ffe-38f122274d45','灧澦堆','鄧深','宋','宋诗','song-poetry','','[]','水合百源爭一關，正須灧澦控奔湍。',32,'全唐诗/poet.song.122000.json','["水合百源爭一關，正須灧澦控奔湍。", "露機象馬渾閒事，合作頹波砥柱看。"]'),
('db15c328-25b5-48b8-98b4-801940965dba','飛練','鄧深','宋','宋诗','song-poetry','','[]','見說天孫巧一機，銀河練就雪爭輝。',32,'全唐诗/poet.song.122000.json','["見說天孫巧一機，銀河練就雪爭輝。", "長風吹下三千尺，衹恐麻姑合得衣。"]'),
('0b4a1296-2768-44f2-a6eb-0a484a879810','登普濟寺慈氏閣','鄧深','宋','宋诗','song-poetry','','[]','柔遠樓中俯市囂，萬家蟻聚汩塵勞。',32,'全唐诗/poet.song.122000.json','["柔遠樓中俯市囂，萬家蟻聚汩塵勞。", "此中更覺樓低小，佛界由來著眼高。"]'),
('587cca96-36b3-4bc0-affe-427faddc101c','題壁平沙落雁','鄧深','宋','宋诗','song-poetry','','[]','江寒烟暮水明霞，曲折斜行雁落沙。',32,'全唐诗/poet.song.122000.json','["江寒烟暮水明霞，曲折斜行雁落沙。", "曾是瀟湘篷底見，還疑今夜宿蘆花。"]'),
('47ca026e-f74a-4506-b331-5bb224a7c211','次韻繡屏','鄧深','宋','宋诗','song-poetry','','[]','定是司花怯曉寒，花枝圍處密縈蟠。',32,'全唐诗/poet.song.122000.json','["定是司花怯曉寒，花枝圍處密縈蟠。", "草針柳線藏真巧，莫作尋常倚市看。"]'),
('891ea2ae-c87f-437a-98c8-c1e66cc28d68','戲留友人把酒','鄧深','宋','宋诗','song-poetry','','[]','柳還飛絮春餘幾，幸有清樽可共持。',32,'全唐诗/poet.song.122000.json','["柳還飛絮春餘幾，幸有清樽可共持。", "今我未眠卿莫去，古人皆飲子休辭。"]'),
('ce860357-af25-4751-9fe4-2863cd8f2fde','觀酒庫落成  其一','鄧深','宋','宋诗','song-poetry','','[]','畢卓夜行因滿甕，嗣宗喜仕爲盈厨。',32,'全唐诗/poet.song.122000.json','["畢卓夜行因滿甕，嗣宗喜仕爲盈厨。", "自憐小戶無如我，不斷瓶沽斷酒沽。"]'),
('0bda4a89-29f1-45f5-9af9-cebe0557f7d7','觀酒庫落成  其二','鄧深','宋','宋诗','song-poetry','','[]','泥沙糟粕不堪傳，有酒知盈幾百船。',32,'全唐诗/poet.song.122000.json','["泥沙糟粕不堪傳，有酒知盈幾百船。", "浪說添盃吹野水，何如真變錫山泉。"]'),
('ba5f134c-c657-455c-95bf-2498f029294e','荷  其一','鄧深','宋','宋诗','song-poetry','','[]','田田藕葉綠如裳，拍塞池亭盡是香。',32,'全唐诗/poet.song.122000.json','["田田藕葉綠如裳，拍塞池亭盡是香。", "不受纖塵偏受露，十分清絕倚晨光。"]'),
('801189ed-b853-479b-b740-e1a1c1a6d04a','荷  其二','鄧深','宋','宋诗','song-poetry','','[]','蓮未開時香在葉，他花縱好葉無香。',32,'全唐诗/poet.song.122000.json','["蓮未開時香在葉，他花縱好葉無香。", "製衣未入騷人手，象鼻何妨吸酒光。"]'),
('38203cdc-9cf7-4fbc-8387-64548df3ee5a','憫松','鄧深','宋','宋诗','song-poetry','','[]','誰借毛錐千字力，曲留髯叟百年身。',32,'全唐诗/poet.song.122000.json','["誰借毛錐千字力，曲留髯叟百年身。", "未能晦蹟終難保，樗櫟林間是散人。"]'),
('51cda384-12b6-47fb-a46b-60a4c2f21a9d','贈梅','鄧深','宋','宋诗','song-poetry','','[]','花蒙臘雪袁安卧，影落寒江正則魂。',32,'全唐诗/poet.song.122000.json','["花蒙臘雪袁安卧，影落寒江正則魂。", "忽見江南春信息，誰教驛使到夔門。"]'),
('93946871-fd19-4a2b-85c9-0a2c31fbadc6','別金華朱丞  其一','鄧深','宋','宋诗','song-poetry','','[]','客中相識便相知，日日相過不問時。',32,'全唐诗/poet.song.122000.json','["客中相識便相知，日日相過不問時。", "除却酒杯澆旅况，若非坐隱即論詩。"]'),
('ce171ee5-b984-4ffc-b6c5-a798d6b07e3d','別金華朱丞  其二','鄧深','宋','宋诗','song-poetry','','[]','梅信傳黄麥正秋，征衣抖擻去難留。',32,'全唐诗/poet.song.122000.json','["梅信傳黄麥正秋，征衣抖擻去難留。", "應從臨汝江邊過，傳語灘頭舊釣舟。"]'),
('2fa94e6f-a331-4eeb-98e3-fc2d84a90d99','答莊權之','鄧深','宋','宋诗','song-poetry','','[]','寒窗十載江湖夢，夜月三更風露秋。',32,'全唐诗/poet.song.122000.json','["寒窗十載江湖夢，夜月三更風露秋。", "靜坐觀心香一炷，平生詩病一時瘳。"]'),
('9e5a20cb-5d69-457d-b000-d9971ca8f22d','次韻答陳仲思  其一','鄧深','宋','宋诗','song-poetry','','[]','彤雲凍合晚來風，百里溪山雪色同。',32,'全唐诗/poet.song.122000.json','["彤雲凍合晚來風，百里溪山雪色同。", "李棨那能說詩興，嗣宗端復嘆途窮。"]'),
('487c8214-be20-46a3-8b96-1e1c106147ab','次韻答陳仲思  其二','鄧深','宋','宋诗','song-poetry','','[]','吟君詩罷不成歡，尚阻青燈話歲寒。',32,'全唐诗/poet.song.122000.json','["吟君詩罷不成歡，尚阻青燈話歲寒。", "亦欲分嘗竹窗碧，少須春後薦春盤。"]'),
('e3f235a2-f4ea-4a35-a2ba-baf40a93bb19','贈錢道人','鄧深','宋','宋诗','song-poetry','','[]','善說相傳唐世術，不言錢有晉人風。',32,'全唐诗/poet.song.122000.json','["善說相傳唐世術，不言錢有晉人風。", "非錢可况言真寔，肯與尋常賣相同。"]'),
('661159ee-e5a7-4c1f-a252-3646d5435c93','賦歐陽道士舞仙','鄧深','宋','宋诗','song-poetry','','[]','博山烟燼夜三更，萬籟聲沉月一庭。',32,'全唐诗/poet.song.122000.json','["博山烟燼夜三更，萬籟聲沉月一庭。", "拂拭琴床彈古調，松梢鶴睡洒然醒。"]'),
('c53b3e5e-4b8b-4c4d-a7a8-93dcc4d23af6','千葉石榴  其一','鄧深','宋','宋诗','song-poetry','','[]','丹房疊蘤炯雙眸，焰焰燒空夜不收。',32,'全唐诗/poet.song.122000.json','["丹房疊蘤炯雙眸，焰焰燒空夜不收。", "莫遣殘英顛倒落，一枝開早見釵頭。"]'),
('fddf4c46-544a-424c-bd1e-73a76ac419ea','千葉石榴  其二','鄧深','宋','宋诗','song-poetry','','[]','誰家巧婦爲花謀，針線殘零細意收。',32,'全唐诗/poet.song.122000.json','["誰家巧婦爲花謀，針線殘零細意收。", "不管生紅難熨貼，從教百皺綴枝頭。"]'),
('3535da61-db77-4e0d-a35a-bd7d92bdd50f','中秋無月肯堂邀小酌賦三五七言','鄧深','宋','宋诗','song-poetry','','[]','雨飄零，風凄清。',36,'全唐诗/poet.song.122000.json','["雨飄零，風凄清。", "坐念今夕月，知從何處明。", "未須無月更作惡，但願有酒常同傾。"]'),
('2b0fd8a9-9cd8-4e1c-8771-21b57a0a8d89','木芙蓉','鄧深','宋','宋诗','song-poetry','','[]','露冷煙凄草樹荒，木芙蓉好試平章。',64,'全唐诗/poet.song.122000.json','["露冷煙凄草樹荒，木芙蓉好試平章。", "蒲萄晚葉尤宜日，芍藥秋花正耐霜。", "蜀錦卷幃粧院落，秦宮開鏡照池塘。", "寫容安得劍南老，聊復殷勤酹一觴。"]'),
('fb73fe15-b847-4d16-a386-58fba7b1d892','六言四首  其一','鄧深','宋','宋诗','song-poetry','','[]','三峽上游煙水，四川極險關山。',28,'全唐诗/poet.song.122000.json','["三峽上游煙水，四川極險關山。", "滿市笙歌晝永，漫山桃李春閑。"]'),
('3f359275-473c-4259-bd49-fdfa2c85edc9','六言四首  其二','鄧深','宋','宋诗','song-poetry','','[]','處處賞心宜主，公來詩眼偏明。',28,'全唐诗/poet.song.122000.json','["處處賞心宜主，公來詩眼偏明。", "掃千軍有筆陣，可一日無酒兵。"]'),
('8bcae4dc-cce0-4983-a528-a9d047fedd32','六言四首  其三','鄧深','宋','宋诗','song-poetry','','[]','百千年陣磧在，六七月雪流來。',28,'全唐诗/poet.song.122000.json','["百千年陣磧在，六七月雪流來。", "文筆手巾南向，白鹽赤甲東回。"]'),
('9330b63e-fdf3-4dec-8711-176854ba96b5','六言四首  其四','鄧深','宋','宋诗','song-poetry','','[]','嗟此地得何晚，見孤芳陋羣妍。',28,'全唐诗/poet.song.122000.json','["嗟此地得何晚，見孤芳陋羣妍。", "小試鳳樓工巧，終圖麟閣風煙。"]'),
('1920dcc7-ac38-49d1-bb86-aec1cf27328b','絕句  其一','鄧深','宋','宋诗','song-poetry','','[]','兀坐長吟五十詩，怪來几案夜生輝。',32,'全唐诗/poet.song.122000.json','["兀坐長吟五十詩，怪來几案夜生輝。", "胸中錦段明如許，羞得吳娃懶上機。"]'),
('5fa02042-cbab-4f64-a670-f8a673ea28b5','絕句  其二','鄧深','宋','宋诗','song-poetry','','[]','桑里相聞路一程，無從款接笑談清。',32,'全唐诗/poet.song.122000.json','["桑里相聞路一程，無從款接笑談清。", "那知邂逅論詩處，秋滿瀟湘鴈送聲。"]'),
('2e0decc3-c751-4aeb-a5ec-3669cc0969fb','絕句','鄧深','宋','宋诗','song-poetry','','[]','毛穎諸孫二十輩，千里相看誰與同。',32,'全唐诗/poet.song.122000.json','["毛穎諸孫二十輩，千里相看誰與同。", "有兩客卿變名姓，烏有先生亡是公。"]'),
('d01e8447-b3e4-4fb5-9aae-8714f3230282','漫成','鄧深','宋','宋诗','song-poetry','','[]','飲罷浮蛆聊隱几，醒來捫虱謾看書。',32,'全唐诗/poet.song.122000.json','["飲罷浮蛆聊隱几，醒來捫虱謾看書。", "風清襟袖凉無限，雲晚溪山畫不如。"]'),
('9156f2cb-b113-4afb-9f5f-7e2ae3d2f815','遊仲文園池','鄧深','宋','宋诗','song-poetry','','[]','曲岸呼舟疾，幽園躡屐徐。',48,'全唐诗/poet.song.122000.json','["曲岸呼舟疾，幽園躡屐徐。", "軒窗數椽屋，雨露四時蔬。", "補塹新移竹，穿池待種魚。", "花間留客晚，數問酒何如。"]'),
('dc285c21-24f8-492d-b0a2-7eced8aaa28e','遊方壺','鄧深','宋','宋诗','song-poetry','','[]','摘勝尋幽須携壺，人生偷取醉工夫。',240,'全唐诗/poet.song.122000.json','["摘勝尋幽須携壺，人生偷取醉工夫。", "楚天雲浄秋雨餘，王孫招客追觀娛。", "晝寢忽來喚宰予，道有方壺宜同趨。", "江神解事驅龍魚，水波不興清風徐。", "柔櫓咿啞人歌呼，美酒滿載不待沽。", "登亭忻與竹鶴徒，有徑深穩醉何虞。", "住處領略貪須臾，頻頻改席殊趑趄。", "湘流渺渺含碧虛，孤煙落日不可模。", "市塵彼岸自一區，嘉木奇石鄰座隅。", "亭下蒲帆逝不居，往往望此如仙都。", "近對岳麓翠屏鋪，上頭目力到重湖。", "昔年登覽蔾杖扶，清凉甘露來香厨。", "相看不遠跡尚疏，濟勝之具空踟躕。", "興盡請以歲月書，仇香洒墨鸞鳳如。", "別后寄我詩成圖，爲問畫家傳本無。"]'),
('e99d1576-7d04-4466-bbda-1b2a8b01a0e4','詩一首','鄧深','宋','宋诗','song-poetry','','[]','鵝鴨江村曲，人家竹樹深。',48,'全唐诗/poet.song.122000.json','["鵝鴨江村曲，人家竹樹深。", "閑雲自來去，皎日屢晴陰。", "水送園蔬葉，谷傳樵斧音。", "瘦驢鞭不動，風處得披襟。"]'),
('c08bc685-27cb-4079-8c56-8ebf9264134b','遊東屯','鄧深','宋','宋诗','song-poetry','','[]','滿目燒畬險，那知此地偏。',48,'全唐诗/poet.song.122000.json','["滿目燒畬險，那知此地偏。", "一川通穩水，百頃著平田。", "茅屋址猶在，草堂名自傳。", "蠻歌晚來起，仍覺在天邊。"]'),
('8c6dfb89-d66f-47b8-9fa6-9aef0f296c42','次韻餞行','鄧深','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君到西湖四月天，酴醾過後藕花前。',64,'全唐诗/poet.song.122000.json','["君到西湖四月天，酴醾過後藕花前。", "却看梅子垂金彈，恰映楊花鋪白氈。", "擲帽袁耽無復戲，著鞭祖逖有誰先。", "姑蘇儻見平反使，生澀休言有此篇。"]'),
('8caa31e2-2571-4eae-ba9d-18912d8622be','留通商館數日','鄧深','宋','宋诗','song-poetry','','[]','商館非閑地，閑人偶在旁。',48,'全唐诗/poet.song.122000.json','["商館非閑地，閑人偶在旁。", "無端聲利役，有許去來忙。", "受雨芭蕉響，懷風䆉䅉香。", "江郊秋易盛，早獻十分凉。"]'),
('95efb269-b336-42ef-b45f-aa2d31a7fb64','訪天寶洞','鄧深','宋','宋诗','song-poetry','','[]','遠尋仙洞上崔嵬，洞口諸峰翠作堆。',32,'全唐诗/poet.song.122000.json','["遠尋仙洞上崔嵬，洞口諸峰翠作堆。", "先把姓名書洞竹，洞門終待玉匙開。"]'),
('6cd8c809-8a17-4c3d-82aa-e338b2b19298','清處爲書記曾魯卿作','鄧深','宋','宋诗','song-poetry','','[]','小竹聊須長，閑花懶復栽。',48,'全唐诗/poet.song.122000.json','["小竹聊須長，閑花懶復栽。", "泉聲洗歌吹，雲氣障塵埃。", "籟靜初香裊，琴橫月上來。", "有時聞警露，夢覺自蓬萊。"]'),
('375a5960-08ab-42dd-a98a-63bfff52efd3','題梅壇','王時彥','宋','宋诗','song-poetry','','[]','梅尉孤忠揭，芳名千古傳。',48,'全唐诗/poet.song.122000.json','["梅尉孤忠揭，芳名千古傳。", "官卑奚意隱，心正即神仙。", "敢諫憂時切，爲臣願主賢。", "旌陽稱令尹，對峙是丹泉。"]'),
('9a4f47f3-13fb-49bd-9a09-8273e99c36e3','題梅山雲悅樓','王時彥','宋','宋诗','song-poetry','','[]','一生活計一身閑，日與白雲相往還。',32,'全唐诗/poet.song.122000.json','["一生活計一身閑，日與白雲相往還。", "五百年間知此味，華山去後到梅山。"]'),
('4ea66e0c-0d48-4b62-b140-f0499073a7a0','題鵝鼻山','史幹','宋','宋诗','song-poetry','','[]','龍泉五盞張帆去，鵝鼻三杯衣錦歸。',32,'全唐诗/poet.song.122000.json','["龍泉五盞張帆去，鵝鼻三杯衣錦歸。", "寄語長泉後生者，年年盛事莫相違。"]'),
('beb46bb1-f6de-41a3-80f1-d2047b98e0f1','游大滌','王溉','宋','宋诗','song-poetry','','[]','山合群峰路屈盤，溪行九折勢蜿蜒。',64,'全唐诗/poet.song.122000.json','["山合群峰路屈盤，溪行九折勢蜿蜒。", "雲根長伴仙人迹，元蓋潛通大滌天。", "玉殿香消人寂寂，石壇花落草芊芊。", "黄冠解識尋幽興，爲洗寒鐺煮碧泉。"]'),
('9154cbe6-0f7e-4361-b91c-67a392f48357','老人村','王溉','宋','宋诗','song-poetry','','[]','山前老澤經行路，百歲翁翁猶健步。',48,'全唐诗/poet.song.122000.json','["山前老澤經行路，百歲翁翁猶健步。", "非仙非佛非鬼神，不識人間鹽與醋。", "嗜欲既淺亦機深，窟宅宜與仙家鄰。"]'),
('815e9783-5c4b-4112-919b-9694bc237d23','句  其一','王溉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只應喚作小西湖。',8,'全唐诗/poet.song.122000.json','["只應喚作小西湖。"]'),
('081da4d0-7d56-48d5-8b7c-efc63563a384','句  其二','王溉','宋','宋诗','song-poetry','','[]','仙人有宮號儲福，藏在千山萬山曲。',32,'全唐诗/poet.song.122000.json','["仙人有宮號儲福，藏在千山萬山曲。", "翠微高下壓簷楹，重疊堆峰三十六。"]'),
('2913987a-864b-4342-aab7-df2906ec5001','句  其三','王溉','宋','宋诗','song-poetry','','[]','西邊更擁上皇山，大面六頂不可攀。',16,'全唐诗/poet.song.122000.json','["西邊更擁上皇山，大面六頂不可攀。"]'),
('de2b3279-ce29-444a-b63f-37bc1575d3ef','句','許自誠','宋','宋诗','song-poetry','','[]','雄當蜀道三千里，巍壓荆南十五州。',16,'全唐诗/poet.song.122000.json','["雄當蜀道三千里，巍壓荆南十五州。"]'),
('338c3b6c-ad55-4b09-a15e-ca97c48f54a9','次袁說友巫山十二峰二十五韻','毌丘恪','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','縑素巧貌溪山姿，寶藏肯笑虎頭癡。',395,'全唐诗/poet.song.122000.json','["縑素巧貌溪山姿，寶藏肯笑虎頭癡。", "何人夜半胠篋去，信爲羽化無疑遲。", "魏明不惜萬夫力，鑿山累土誇神奇。", "景陽突起芳林苑，穀城文石光參差。", "葉公好龍廣射虎，大方安能不笑之。", "至人於物特寓目，遠象過眼心弗隨。", "我公看山正如此，肯趁兒童脚力疲。", "胸中五嶽鎮地軸，眼底三辰昭旂旗。", "擢由漢庭寵分鉞，來撫蜀土初褰帷。", "巫山一覽窺妙處，寫入長歌賡竹枝。", "坐令十二峰增重，已覺氣壓嵩華低。", "太室少室敢輩行，小孤大孤何兒嬉。", "岱宗日觀峻徒爾，崑崙天柱高安爲。", "出雲作雨均有是，泥金鏤玉彼一時。", "所謂造化一尤物，不在九華真在茲。", "中山前言恐遂廢，公之妙論已四馳。", "半語猶存大公正，蟠胸經濟看設施。", "要令利濟均四海，無間山崖與水湄。", "只今蒼生方屬望，休戚在公顰伸眉。", "願公更爲天下重，所養自養觀諸頤。", "量陂誰復能澂撓，德表居然無磷緇。", "巖石巍巍具瞻在，孰不嘆仰聲噫嘻。", "又何必東望瀛，南望嶷，北有天後之峻嶺，西有雲表之峨嵋。", "與公高名并不朽，配以今日巫山詩。"]'),
('6af6b729-fcf7-45b8-bea2-1636305c9cce','梅林分韻得詩字','呂宜之','宋','宋诗','song-poetry','','[]','寒梅如高人，冰雪凜風期。',120,'全唐诗/poet.song.122000.json','["寒梅如高人，冰雪凜風期。", "霜威凌萬木，孤芳綴疏枝。", "古來歲寒心，肯與時節移。", "家家浣溪南，橫斜映笆籬。", "老樹更崛奇，矯矯蛟龍姿。", "中有調鼎味，幾年江之湄。", "征衫十年寒，霜蹄快追隨。", "先生羊叔子，到處英名垂。", "對花有妙語，豪氣無百巵。", "興來屬湛輩，同出舂容詩。"]'),
('6c5ed8a2-a802-4753-a4bb-56fbc0372ea6','題文州安靜堂','呂宜之','宋','宋诗','song-poetry','','[]','峽束秋空一線青，萬山深處長官廳。',32,'全唐诗/poet.song.122000.json','["峽束秋空一線青，萬山深處長官廳。", "此堂虛曠無餘物，面面爲開碧玉屏。"]'),
('16aae13e-6bd8-437d-958e-d1589db02f42','夜泊李陽驛','高邁','宋','宋诗','song-poetry','','[]','風拂烏紗兩鬢秋，李陽溪上夜停舟。',64,'全唐诗/poet.song.122000.json','["風拂烏紗兩鬢秋，李陽溪上夜停舟。", "市燈閃月聞鳴犬，城柝敲風起睡鷗。", "千里遠馳承寵命，通宵不寐爲民憂。", "幽懷自信清如洗，獨倚篷窗看斗牛。"]'),
('39a25b98-c3dd-4ee1-a5a1-d575c34de8dc','勉婿史彌大','高邁','宋','宋诗','song-poetry','','[]','老朽歸田久，鳥紗白髮新。',24,'全唐诗/poet.song.122000.json','["老朽歸田久，鳥紗白髮新。", "經綸天下事，都屬少年人。"]'),
('9f5a1b92-c271-4b35-b226-a69dceebed9f','建德縣詠懷','高邁','宋','宋诗','song-poetry','','[]','日午琴堂吏散衙，不愁鬢雪點烏紗。',64,'全唐诗/poet.song.122000.json','["日午琴堂吏散衙，不愁鬢雪點烏紗。", "訟清犴獄塵封草，人靜公庭鳥啄花。", "惟願兒童無凍餒，每令野老勸桑麻。", "聖恩未報吾心赤，肯效青門學種瓜。"]'),
('04c35990-1aa2-4cfe-a7b5-64c8cc7812e1','道傍菊','高邁','宋','宋诗','song-poetry','','[]','荆棘叢中是故鄰，更無君子與相親。',32,'全唐诗/poet.song.122000.json','["荆棘叢中是故鄰，更無君子與相親。", "含英吐秀西風裏，空把芳心向路人。"]'),
('2ec244e6-0ceb-4d66-90b4-7a48de8d6bc9','寒梅野雀圖','高邁','宋','宋诗','song-poetry','','[]','陰陰榕葉覆寒梅，山徑無蹤盡綠苔。',32,'全唐诗/poet.song.122000.json','["陰陰榕葉覆寒梅，山徑無蹤盡綠苔。", "啼鳥自知安穩處，成群飛去又飛來。"]'),
('b42477f8-6cca-4203-b96d-1c82bcb50100','詠賨城景物之勝','何熙志','宋','宋诗','song-poetry','','[]','欲說賨城好，先誇方物妍。',48,'全唐诗/poet.song.122000.json','["欲說賨城好，先誇方物妍。", "金羹收稻後，紅腊落梅前。", "照座梨偏紫，堆盤荔更鮮。", "雪縢尤異產，應不數花牋。"]'),
('4a4ee943-11a5-4a1f-b5e7-09f0e90a80ae','續題鄭國華昌州牛尾驛','何熙志','宋','宋诗','song-poetry','','[]','十年去國真悠悠，祇今便可行歸休。',32,'全唐诗/poet.song.122000.json','["十年去國真悠悠，祇今便可行歸休。", "平生意氣羞牛後，去踏金鰲頂上遊。"]'),
('e8f69839-c44d-4d39-95bc-3c1d152039f2','句  其一','何熙志','宋','宋诗','song-poetry','','[]','拓開天外無窮景，望盡坤維到處山。',16,'全唐诗/poet.song.122000.json','["拓開天外無窮景，望盡坤維到處山。"]'),
('70d39790-2ae0-44bd-a5ac-8fe5aa3f427c','句  其二','何熙志','宋','宋诗','song-poetry','','[]','一山九頂燈常現，六月三峨雪未消。',16,'全唐诗/poet.song.122000.json','["一山九頂燈常現，六月三峨雪未消。"]'),
('53f5c525-f240-41f9-a143-f4da3c4c4b1a','紅梅','劉嗣慶','宋','宋诗','song-poetry','','[]','瞥眼繁華處處空，寒林獨透一枝紅。',32,'全唐诗/poet.song.122000.json','["瞥眼繁華處處空，寒林獨透一枝紅。", "入時姿態人爭羨，清韵須知冰雪同。"]'),
('97214fb4-ca77-4dc4-adfe-eec93be64006','題黄犢嶺','呂紘','宋','宋诗','song-poetry','','[]','疇昔聞高隱，紅塵隔遠林。',48,'全唐诗/poet.song.122000.json','["疇昔聞高隱，紅塵隔遠林。", "間乘黄犢出，踏破白雲深。", "自得忘歸樂，應多扣角吟。", "如今秋草沒，幾約與僧尋。"]'),
('008d2c28-3201-4d16-ba91-3f3271641279','九日次應侍郎仁伯韻','鄭洪','宋','宋诗','song-poetry','','[]','九日風高快客情，穹然天宇氣澄明。',64,'全唐诗/poet.song.122000.json','["九日風高快客情，穹然天宇氣澄明。", "白衣酒送人難得，黄菊花開句易成。", "對景渾忘披雪鬢，登高喜放遏雲聲。", "古人曾墮龍山帽，爲愛金風兩腋清。"]'),
('f914515a-8a78-430a-856e-5419917e9dcd','遊仙都  其一','吳謹微','宋','宋诗','song-poetry','','[]','薄宦驅人畏簡書，金柔暑濁倦征途。',32,'全唐诗/poet.song.122000.json','["薄宦驅人畏簡書，金柔暑濁倦征途。", "歸來有意尋真境，路入仙都不憚迂。"]'),
('2e1a86b6-7d43-4d1b-b35c-48f7ca7714b1','遊仙都  其二','吳謹微','宋','宋诗','song-poetry','','[]','轍迹峰前聊息迹，忘歸洞口未能歸。',32,'全唐诗/poet.song.122000.json','["轍迹峰前聊息迹，忘歸洞口未能歸。", "往來名利憧憧者，著脚仙都亦自稀。"]'),
('50b9dd03-edc8-425f-839e-10a52de5b048','遊仙都  其三','吳謹微','宋','宋诗','song-poetry','','[]','黄冠道士老而癯，相對談玄一事無。',32,'全唐诗/poet.song.122000.json','["黄冠道士老而癯，相對談玄一事無。", "勸我莫教沉宦海，人間亦自有仙都。"]'),
('ffbc3d9e-29f2-4483-a3dc-15fe016bd556','遊仙都  其四','吳謹微','宋','宋诗','song-poetry','','[]','石筍古傳八百丈，鼎湖仙去幾千年。',32,'全唐诗/poet.song.122000.json','["石筍古傳八百丈，鼎湖仙去幾千年。", "我疑二事無從政，但信仙都是洞天。"]'),
('fad9db7e-2eaa-4556-b555-c344993e45d9','遊仙都  其五','吳謹微','宋','宋诗','song-poetry','','[]','山下霏微雨灑塵，門前嘹唳鶴迎人。',32,'全唐诗/poet.song.122000.json','["山下霏微雨灑塵，門前嘹唳鶴迎人。", "遂成一覺仙都夢，更訪遺蹤得隱真。"]'),
('02021ea6-4159-422a-b983-9764f18461f5','題西門外筰橋下觀音院','仲昂','宋','宋诗','song-poetry','','[]','雨砌風亭長綠苔，壁間題字半塵埃。',32,'全唐诗/poet.song.122000.json','["雨砌風亭長綠苔，壁間題字半塵埃。", "城南蕭寺無人迹，幾度曾因送客來。"]'),
('bccc0db6-2641-4170-879f-f1058fda7e1c','句  其一','仲昂','宋','宋诗','song-poetry','','[]','慮澹常高枕。',6,'全唐诗/poet.song.122000.json','["慮澹常高枕。"]'),
('bc609b0a-2a1a-4d0b-ba7a-d50ec81bd26e','句  其二','仲昂','宋','宋诗','song-poetry','','[]','平生不識巴南路，夢到孤雲兩角西。',16,'全唐诗/poet.song.122000.json','["平生不識巴南路，夢到孤雲兩角西。"]'),
('c194accb-f854-41f5-9059-a48bbb9b020e','句','牟孔錫','宋','宋诗','song-poetry','','[]','天池十里如鑑湖，荷花可折魚可膾。',16,'全唐诗/poet.song.122000.json','["天池十里如鑑湖，荷花可折魚可膾。"]'),
('de624f73-1db9-4934-90ca-78ff90ddee70','用彥平韻賦石外舅短項翁','耿鎡','宋','宋诗','song-poetry','','[]','人生何地逃奇耦，白髮轉頭成宿莽。',160,'全唐诗/poet.song.122000.json','["人生何地逃奇耦，白髮轉頭成宿莽。", "百年同盡草一丘，誰見乘槎上牛斗。", "不如醉倒三萬場，何必龍山歲重九。", "先生元是古達人，身外所忻惟有酒。", "石交自得短項翁，燕頷鳶肩非我友。", "邇來带眼寬綠筠，結喉不造鴛鷺群。", "十年孛窣牆下塵，仰面詎識高崑崙。", "先生取人略形貌，翁獲展盡終不渾。", "我欲挽翁歸翠微，手栽杞菊如天隨。", "願翁醉客莫嫌擾，買山政賦淮南小。"]'),
('7a1bbe4f-7652-4ee9-9a41-57965a868d63','用功成韻賦外舅短項翁','耿鎡','宋','宋诗','song-poetry','','[]','君不見王績非狂生，筆墨掃盡惟酒經。',178,'全唐诗/poet.song.122000.json','["君不見王績非狂生，筆墨掃盡惟酒經。", "又不見志和非漫尉，江湖醉詠漁歌耳。", "文章得失兩夢事，一醉從渠俱不理。", "人間自有行秘書，此翁聊爲山澤儒。", "平生斟酌自飽滿，寧復有欠寧有餘。", "可憐蹣跚挽不前，屬車豈識從甘泉。", "不矜萬卷腹空洞，渴夢只恐東溟乾。", "莫疑此翁拘器窮，此翁有用非啞鐘。", "濁醪作賢清作聖，翁不異味同其空。", "我方畏縮立下風，伸頸一笑短項逢。", "脫冠與翁共醉倒，從人笑此兩禿翁。"]'),
('ccde9c11-907e-474b-b52d-b34d0f362ead','西樓','耿鎡','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西樓一曲舊笙歌，千古當樓面翠峨。',64,'全唐诗/poet.song.122000.json','["西樓一曲舊笙歌，千古當樓面翠峨。", "花發花殘香徑雨，月生月落洞庭波。", "地雄鼓角秋聲壯，天迥闌干夕照多。", "四百年來逢妙手，要看風物似元和。"]'),
('496aebc0-0c70-4efc-88c2-ae9200609656','玉虹泉','何錫汝','宋','宋诗','song-poetry','','[]','百尺雲巖佛閣前，晚鐘疏葉思悠然。',64,'全唐诗/poet.song.122000.json','["百尺雲巖佛閣前，晚鐘疏葉思悠然。", "岸邊酌酒和清露，石上題詩染翠烟。", "半嶺泉鳴通古澗，數峰秋盡隔寒川。", "西風似欲吹人起，去逐騎鯨汗漫仙。"]'),
('940d845c-00f1-4edd-ba15-4f7f74580d71','華蓋山','鄧犀如','宋','宋诗','song-poetry','','[]','日沈露下不勝寒，絕頂江南第一山。',64,'全唐诗/poet.song.122000.json','["日沈露下不勝寒，絕頂江南第一山。", "脚底雲平疑可步，身邊月近似容攀。", "諸天合在虛無際，清磬應聞縹緲間。", "欲拚今宵不成寐，遇風高處著仙班。"]'),
('bfb3657b-36c6-41a0-986e-908e0ad9cadc','槐林院二首  其一','鄧犀如','宋','宋诗','song-poetry','','[]','野色寒如許，山容瘦不禁。',48,'全唐诗/poet.song.122000.json','["野色寒如許，山容瘦不禁。", "因閒携竹杖，乘興宿槐林。", "衲子蒙頭坐，騷人擁鼻吟。", "南柯休入夢，軒冕本無心。"]'),
('8d9da8c1-26a2-4e07-b3ac-2ef89c989156','槐林院二首  其二','鄧犀如','宋','宋诗','song-poetry','','[]','竹樹參差合，川原遠近分。',48,'全唐诗/poet.song.122000.json','["竹樹參差合，川原遠近分。", "旛旛晴後見，鐘磬夜中聞。", "野碓閒春水，春橋冷度雲。", "庭空遊客散，鳴鳥自呼羣。"]'),
('2976c436-8186-4d74-aef1-dcb188c554d1','思維路','張世美','宋','宋诗','song-poetry','','[]','一來一往幾車馬，可北可南多路岐。',32,'全唐诗/poet.song.122000.json','["一來一往幾車馬，可北可南多路岐。", "莫待迷途重回首，未曾差處著思維。"]'),
('ea7d7f7d-46dd-4619-9144-80d96cdefd77','詩一首','宋泰發','宋','宋诗','song-poetry','','[]','薰風將雨熟黄梅，忙裏偷閑此地來。',32,'全唐诗/poet.song.122000.json','["薰風將雨熟黄梅，忙裏偷閑此地來。", "更欲少留償逸興，長官却怕晚衙催。"]'),
('951ccb44-25e4-40d6-99bc-7b9f5b652ce7','題天竺寺壁','李天才','宋','宋诗','song-poetry','','[]','走殺東頭供奉官，御香頻降雨猶慳。',32,'全唐诗/poet.song.122000.json','["走殺東頭供奉官，御香頻降雨猶慳。", "相公端坐都堂裏，天竺觀音又下山。"]'),
('3c176745-cec1-4fba-a730-02275be3bf6d','題句容酒肆壁','李天才','宋','宋诗','song-poetry','','[]','青裙白面哄挑菜，茅舍竹籬疏見梅。',32,'全唐诗/poet.song.122000.json','["青裙白面哄挑菜，茅舍竹籬疏見梅。", "春事隔年無信息，一聲啼鳥喚將來。"]'),
('f9649514-df6b-41ca-a787-f911897de723','廣寧橋懷韓有功','朱襲封','宋','宋诗','song-poetry','','[]','河梁風月故時秋，不見先生曳杖游。',32,'全唐诗/poet.song.122000.json','["河梁風月故時秋，不見先生曳杖游。", "萬疊遠青愁對起，一川漲綠淚爭流。"]'),
('90f1f128-db76-4fe3-bef2-14bd6c88fa8b','句','范元作','宋','宋诗','song-poetry','','[]','山連巫峽幾千里，水闊沅湘三四州。',16,'全唐诗/poet.song.122000.json','["山連巫峽幾千里，水闊沅湘三四州。"]'),
('80625e93-e8e4-496e-9005-7f20b5e0d153','過子美草堂','馬俌','宋','宋诗','song-poetry','','[]','棲遲九月錦水行，獨過草堂西出城。',184,'全唐诗/poet.song.122000.json','["棲遲九月錦水行，獨過草堂西出城。", "村樹苒苒秋照白，水花漪漪江水明。", "溪邊三重結茅屋，松蘿翳疏晚雨清。", "往來沽酒且有客，胡爲奔走不自停。", "四海紛然霾曀多，我憂豈但白馬盟。", "藜藿未足飽我腹，况又一頃供耕耘。", "只今騎驢望八極，終日飄飄浪如許。", "可堪顔色太癯生，憂愁盡入篇章苦。", "信眉一笑古復作，却似韓宣適東魯。", "此生蕩漾胡能留，雨脚風塵奚所休。", "此道滄浪付一漚，喚之千古與爾謀。", "吾亦往矣作春秋。"]'),
('42ff7d83-c452-42e6-a2cd-0964dac4139a','水月亭','馬俌','宋','宋诗','song-poetry','','[]','陽來中坤坎波翻，月本於地仍東還。',136,'全唐诗/poet.song.122000.json','["陽來中坤坎波翻，月本於地仍東還。", "誰爲聚之古祗柏，涵碧湛湛琉璃盤。", "珊瑚晶瑛澈凝湍，西風晚來覺秋寬。", "海蕩冰碎天飛旋，瞿曇指心以探禪。", "魄死澤困與爾言，夜游倚聲霓裳讙。", "捉影或墮不可援，幻癡益多吾懔然。", "明河繞衣吹佩環，毛髮飄蕭亂空寒。", "頗欲乘槎此窮源，脫屣濁世摶林騫。", "采華食葉爲玉仙。"]'),
('3856069b-2772-4170-a254-5a2a37684303','浣花溪','馬俌','宋','宋诗','song-poetry','','[]','浣花溪邊濯錦裳，百花滿潭溪水香。',112,'全唐诗/poet.song.122000.json','["浣花溪邊濯錦裳，百花滿潭溪水香。", "竇奩散盡有霜戟，草秣匹馬不可當。", "當時濯衣只偶爾，豈似取履張子房。", "烈烈遽見蔽此蜀，喪亂懷爾徒悲傷。", "年年春風媚楊柳，彩纜㛪姌雲霞張。", "溪邊遊冶紅粉娘，了不識字空悠颺。", "採花蕩槳不歸去，暮隔烟水眠幽芳。"]'),
('7f3fe5c1-fb79-4285-b2e8-4df3989b7c3f','題定明大像','閻禹錫','宋','宋诗','song-poetry','','[]','造化秘奇勝，洪流繞崇崗。',180,'全唐诗/poet.song.122000.json','["造化秘奇勝，洪流繞崇崗。", "層樓百仞高，下□雲水鄉。", "空嵌獨秀峰，雷霓揮銛鋩。", "神□□□丁，金仙儼垂裳。", "懸知天壤間，異事不可□。", "□嘉與甯川，二像遥相望。", "怒濤喬嶽中，涌出大法王。", "奇怪豈人力，窺測固渺茫。", "□□□□□，藤蘿罥幽香。", "夜深龍作禮，寶炬勝霞光。", "我生西南陬，薄宦游東方。", "睹此兩奇絕，儻怳如癡狂。", "由來豪放詞，不付白面郎。", "矧此無盡藏，綺語未足償。", "小詩勒岩阿，相與石像長。"]'),
('7ba80fc8-45e8-4c33-a375-cc13e034f4f7','賀鄭簿生孫','鄭暉老','宋','宋诗','song-poetry','','[]','望及清秋到眼明，建溪溪上現長庚。',64,'全唐诗/poet.song.122000.json','["望及清秋到眼明，建溪溪上現長庚。", "雲間鸑鷟人間見，天上麒麟地上行。", "釋氏抱來真傑特，寶公摩後必奇英。", "傳家已有今衣鉢，會見公侯衮衮生。"]'),
('de692b9d-5f22-4c15-a338-81907d14841b','贈海陵佘公老人','趙夔','宋','宋诗','song-poetry','','[]','爲人八十有三歲，遊歷名山幾洞天。',56,'全唐诗/poet.song.122000.json','["爲人八十有三歲，遊歷名山幾洞天。", "若問老翁何所得，無心學道不求仙。", "不求仙，仙自然，煉氣煉形精亦煉，精全神旺合長年。"]'),
('a959ca8c-b331-45af-b8db-60849d18e8e7','桂山諸巖歌','趙夔','宋','宋诗','song-poetry','','[]','秦皇開郡爲桂林，古號名邦五嶺陰。',240,'全唐诗/poet.song.122000.json','["秦皇開郡爲桂林，古號名邦五嶺陰。", "山琢玉簪攢萬疊，江分羅带繞千尋。", "青青四顧列羣山，生自天工巧若𨬖。", "玲瓏拔地聳層秀，崢嶸嵯峨星斗間。", "其中有巖十二所，伏波靈顯存祠宇。", "顔公讀書窟室中，疊彩北山如列布。", "何年龍隱沖霄去，鱗鬣形模鑱石路。", "仙人劉公飛升時，巖壁宛然遺舊題。", "穿雲仙跡次左右，□虛道氣多南溪。", "白雉聽經生人類，蕭寺豐碑有元記。", "信知一性無不通，石竇陰陰苔蘚蒙。", "西南中隱尤勝絕，穿處得名因呂公。", "曾公程公皆舊跡，遺愛在民傳古昔。", "沈沈巖谷有餘光，炎方勝槩神難藏。", "週迴不遠郛郭下，輪蹄追賞何忙忙。"]'),
('e743523d-1793-4f20-8e9e-327ed479889c','桂山諸洞歌','趙夔','宋','宋诗','song-poetry','','[]','宜人之地少陵詩，閱玩前賢詞意奇。',240,'全唐诗/poet.song.122000.json','["宜人之地少陵詩，閱玩前賢詞意奇。", "爛然五詠非虛語，位壓坤方占一維。", "青青四顧列羣山，生自天工巧若𨬖。", "玲瓏拔地聳層秀，崢嶸嵯峨星斗間。", "其中有洞十二所，七星山下栖霞府。", "日月華君顯迹靈，遇者當時鄭冠卿。", "歸到人間已三載，仙洞光陰時未改。", "至今舊記傳無窮，玄巖蟠蟄聞白龍。", "一泓沈碧寒潭瑩，水月圓明下翠峰。", "枕城樓觀環俯視，綠鎖喬林春日媚。", "秦碑柳記已難觀，漓水南流泛渺漫。", "慶林巽穴玄風出，華景高明隱丹室。", "西方虛秀貫山腰，南華朝陽風景饒。", "夕陽北牖通仙徑，白雀嘉蓮池淥浄。", "許多佳致卒難題，留與詞人賡雅詠。"]'),
('1a9ab7f1-f231-4d9e-ac80-77bab97b6a61','詩一首','趙夔','宋','宋诗','song-poetry','','[]','青嶂橫開高幾重，巉巖直上半天中。',64,'全唐诗/poet.song.122000.json','["青嶂橫開高幾重，巉巖直上半天中。", "虛明洞口千年久，澄澈流來一溜通。", "海蚌張頤方吸月，雲龍奮跡遂乘風。", "隼旗出有隨軒雨，指日秋成賀歲豐。"]'),
('bd5dd0f2-c90f-4bcd-a4b5-dab99075db59','道過遂縣泊舟瞻大像有作','趙夔','宋','宋诗','song-poetry','','[]','成佛經千祀，鎸崖已一章。',48,'全唐诗/poet.song.122000.json','["成佛經千祀，鎸崖已一章。", "爲憐塵世病，故作大醫王。", "黄面無苔蘚，青螺奈雪霜。", "灘聲門外轉，萬古閱舟航。"]'),
('7dc9668b-c5a6-444b-a553-f541c9f8e3dd','句','紹興某貴人','宋','宋诗','song-poetry','','[]','綠樹带雲山罨畫，斜陽入地竹銷金。',16,'全唐诗/poet.song.122000.json','["綠樹带雲山罨畫，斜陽入地竹銷金。"]'),
('d17a0935-7e9e-4cae-8d01-db1b7da6532e','投秦丞相','紹興選人','宋','宋诗','song-poetry','','[]','多少儒生新及第，高燒銀燭照蛾眉。',32,'全唐诗/poet.song.122000.json','["多少儒生新及第，高燒銀燭照蛾眉。", "格天閣上三更雨，猶誦車攻復古詩。"]'),
('a262f6cc-d2b6-4fa9-9829-a21b5c3f2974','句','紹興朝士','宋','宋诗','song-poetry','','[]','疾風勁草識忠臣。',8,'全唐诗/poet.song.122000.json','["疾風勁草識忠臣。"]'),
('34676143-d05a-4813-8a2b-6d6ca52e111d','偈','紹興道者','宋','宋诗','song-poetry','','[]','萬里雲歸洞，千山水向東。',24,'全唐诗/poet.song.122000.json','["萬里雲歸洞，千山水向東。", "玉爐香冷處，烟散碧霞中。"]'),
('467f7a87-bb61-488e-9cb2-0d97905a6d4d','偈','紹興太學生','宋','宋诗','song-poetry','','[]','萬鴿飛翔繞帝都，朝昏收放費功夫。',32,'全唐诗/poet.song.122000.json','["萬鴿飛翔繞帝都，朝昏收放費功夫。", "何如養取雲邊雁，沙漠能傳二聖書。"]'),
('62721987-5670-4b15-be15-9d158c790ee4','過凈名院觸目都似曾到問訊乃非也戲題絕句  其一','李薰','宋','宋诗','song-poetry','','[]','入門彷彿記曾來，問訊山僧始此回。',32,'全唐诗/poet.song.122000.json','["入門彷彿記曾來，問訊山僧始此回。", "却覓舊遊無是處，只應形似遣人猜。"]'),
('ca4f07aa-9c9d-4a68-8ada-a425e221ffd3','過凈名院觸目都似曾到問訊乃非也戲題絕句  其二','李薰','宋','宋诗','song-poetry','','[]','世間形似巧迷人，總是安排底處真。',32,'全唐诗/poet.song.122000.json','["世間形似巧迷人，總是安排底處真。", "縱復非真猶足喜，得來聊寄夢中身。"]'),
('50e2ffd8-2358-4fe8-8d38-1bc8589c4fe7','丙寅歲秋再抵長松奉等慈師入城作詩記一時事','李薰','宋','宋诗','song-poetry','','[]','前來送師歸，今日迎師去。',229,'全唐诗/poet.song.122000.json','["前來送師歸，今日迎師去。", "送迎我何勞，師乃困行路。", "天公將歸誰尤，耗斁此下土。", "一水禍未忘，旱勢復如許。", "小民惟怨咨，惜莫知其故。", "徑須憑佛力，庶可回帝怒。", "自憐操持約，一念寄香縷。", "氤氳才上徹，雲色暗窗戶。", "數聲跳珠急，忽已忘處所。", "老僧笑謂我，水旱要有數。", "德非與天通，造請輒違拒。", "官豈真德人，天意遽相與。", "更看鞭雷公，滂沛逐飛馭。", "定身固如如，未始間行住。", "抗走不少停，政恐塵埃污。", "傾心太平日，十五一風雨。", "官既罷迎送，師亦得安處。", "我聞低頭謝，勤爾相誨語。", "作詩書長松，來者尚有取。"]'),
('00884c70-8938-44eb-be4e-210e91547e6b','從薛元法會食保福意軒得徑字','李薰','宋','宋诗','song-poetry','','[]','春愁醉人心，灑面呼不醒。',168,'全唐诗/poet.song.122000.json','["春愁醉人心，灑面呼不醒。", "出門却入門，兀兀度晨暝。", "昨遊欣有得，水鏡謝磨瑩。", "豈惟勝紛華，頗復造禪定。", "君看青雲士，窘步爭捷徑。", "鏗爾詎舍瑟，硜乎方擊磬。", "何曾頃刻閑，通夕不遑瞑。", "彼應疾此固，我亦惡夫佞。", "人生出處耳，山林與朝廷。", "遲遲岐路間，去就須審訂。", "寧爲龜曳涂，勿作馬旋濘。", "羲馭靡容勒，風船猶可矴。", "但令尊不空，敢憚室垂罄。", "更結汗漫遊，後期君速聽。"]'),
('f793266c-a9b1-460b-898a-3a8a1d589da9','十五日同登大慈寺樓得遠字','李薰','宋','宋诗','song-poetry','','[]','重樓得雲氣深穩，戶牖誰能發關鍵。',192,'全唐诗/poet.song.122000.json','["重樓得雲氣深穩，戶牖誰能發關鍵。", "樓下輪蹄渙散馳，行人一顧不容返。", "好遊獨是我輩閒，褰衣直上相推挽。", "層軒危檻倚欲遍，更假胡床同息偃。", "西南繁會惟此都，昔號富饒今已損。", "填城華屋故依然，孰爲君王愛基本。", "茫茫八表聊縱目，情知日近長安遠。", "白雲浩蕩飛鳥沒，玉笙凄凉紅紛晚。", "梁王吹臺得李杜，黄公酒壚醉嵇阮。", "高峰千載凜莫攀，與世相濁徒混混。", "荷衣蕙带芙蓉裳，野服猶堪敵華衮。", "去梯熟復共君謀，殺馬毀車從此遁。"]'),
('574273f5-538b-41ab-a881-7ccf4eefc3e4','三月四日遊大雲寺分韻得三字佛龕多題名韋獨抗段文昌李景讓鄭愚四人者可考王文穆呂正閔治平嘉祐間過此亦有筆迹因以詩記','李薰','宋','宋诗','song-poetry','','[]','野寺依絕壁，化身滿諸龕。',288,'全唐诗/poet.song.122000.json','["野寺依絕壁，化身滿諸龕。", "後前莽難測，千億紛相參。", "妙斲謝斤斧，高樓軼烟嵐。", "旁行栗危棧，俯瞰驚深潭。", "歲月浸荒老，苔蘚爭封函。", "亦有好事者，增飭施朱藍。", "經營定自圖，諜雅奚未暗。", "款識或可辨，上下試與探。", "遠徵固寂寞，近取才二三。", "開元韋庶子，剖符劍之南。", "咄嗟檀施開，至今爲美談。", "墨卿少羈窶，節旄晚毿毿。", "樂和盛家法，國垢猶包含。", "鄭氏雖世儒，蠻禍竟莫戡。", "舊相粵冀級，經從各停驂。", "翰林寵則多，御史德豈慚。", "數公方盛壯，厥聲實訏覃。", "紛華竟安在，人壽無彭聃。", "彼石尚云朽，吾生諒何堪。", "華前一笑粲，現此優波曇。", "稽首識歸處，徑欲投佩簪。", "蠢蠢誰汝縛，竊食如春蠶。", "祓除偶辰巳，風景清且酣。", "相引著勝地，佛日况可貪。"]'),
('37363f9d-2358-4d76-a2af-da082e0be08b','偈','釋自清','宋','宋诗','song-poetry','','[]','糞箕扛去轎抬回，優鉢曇花向日開。',32,'全唐诗/poet.song.122000.json','["糞箕扛去轎抬回，優鉢曇花向日開。", "但願老僧高著眼，管教平地一聲雷。"]'),
('6111292e-4b5c-47e0-bae0-4d6e534802f7','晚春','釋守璋','宋','宋诗','song-poetry','','[]','草深烟景重，林茂夕陽微。',24,'全唐诗/poet.song.122000.json','["草深烟景重，林茂夕陽微。", "不雨花猶落，無風絮自飛。"]'),
('7b47ab94-0e4b-4767-9b7d-4e00d631235a','句','釋廣勤','宋','宋诗','song-poetry','','[]','筆端造化如東君，著物不簡亦不繁。',16,'全唐诗/poet.song.122000.json','["筆端造化如東君，著物不簡亦不繁。"]'),
('33de7f4a-1812-4755-b2a6-692e82110502','遺陳氈頭','張圓覺','宋','宋诗','song-poetry','','[]','釋氏三千金世界，道士十二玉樓臺。',32,'全唐诗/poet.song.122000.json','["釋氏三千金世界，道士十二玉樓臺。", "不知雲鶴今何處，空使氈頭夜卧階。"]'),
('3107b142-6c67-47b9-af08-30e14973dd7e','題白雲堂','陳田夫','宋','宋诗','song-poetry','','[]','我愛瀟湘境，朱陵後洞天。',48,'全唐诗/poet.song.122000.json','["我愛瀟湘境，朱陵後洞天。", "白雲堂裏客，青草渡頭眠。", "小艇牽紅鯉，幽池種白蓮。", "頤真堪此地，風月兩依然。"]'),
('c634b89a-93da-4494-9660-3025572a0557','白龜泉','陳田夫','宋','宋诗','song-poetry','','[]','天下白龜三處顯，怡山少室壽仙亭。',32,'全唐诗/poet.song.122000.json','["天下白龜三處顯，怡山少室壽仙亭。", "我今卜筑南山頂，得爾爲鄰祝聖齡。"]'),
('3b9ebd95-1fed-414b-b4cf-f63776df8d40','臨江太守生日','李季可','宋','宋诗','song-poetry','','[]','道路盡歌賢太守，祈頌萬人同一口。',32,'全唐诗/poet.song.122000.json','["道路盡歌賢太守，祈頌萬人同一口。", "只應憫及黄衣兒，亦使銜環致君壽。"]'),
('18f78245-4c53-4b21-880d-ea265c6f3d33','獨吟','盛曠','宋','宋诗','song-poetry','','["\u8861\u5c71"]','刊名紫簡群魔賓，扶桑暘谷奏玉晨。',32,'全唐诗/poet.song.122000.json','["刊名紫簡群魔賓，扶桑暘谷奏玉晨。", "控駕三素輔翊宸，敢忘南嶽魏夫人。"]'),
('e0955203-7d93-4ef1-8832-8a29f9a174cf','句','趙逵','宋','宋诗','song-poetry','','[]','皇心未敢宴安圖。',8,'全唐诗/poet.song.122000.json','["皇心未敢宴安圖。"]'),
('0dd76f0a-e1bd-410c-8005-99950cbc3400','使虜過汴京作','龐謙孺','宋','宋诗','song-poetry','','[]','蒼龍觀闕東風外，黄道星辰北斗邊。',32,'全唐诗/poet.song.122000.json','["蒼龍觀闕東風外，黄道星辰北斗邊。", "月照九衢平似水，胡兒吹笛內門前。"]'),
('d5eae3ce-43a5-48a3-8c7f-99463360f787','日暮','龐謙孺','宋','宋诗','song-poetry','','[]','水底晃微霞，孤村古路叉。',48,'全唐诗/poet.song.122000.json','["水底晃微霞，孤村古路叉。", "稻簷排凍雀，牛背落昏鴉。", "行客猶貪路，歸帆未到家。", "交遊書札斷，寂寞過天涯。"]'),
('feb2fdfe-1011-464c-bfd7-9aef9f5659e3','題渡水羅漢畫','龐謙孺','宋','宋诗','song-poetry','','[]','偏袒右肩赤一膊，開顔含笑不作惡。',147,'全唐诗/poet.song.122000.json','["偏袒右肩赤一膊，開顔含笑不作惡。", "廣深莫種金蓮花，故使浮杯襯雙脚。", "心既忘形亦忘怖，徒使旁觀毛髮豎。", "本無行止令人圖，竟到彼岸歸何處。", "我知畫者意識真，是故古來傳至今。", "亦無此心可得驚，亦無此身可得沈。", "浪頭乘風正得路，不動莊嚴幾時去。", "從今不往亦不還，一幅之間作常住。", "君不聞古人祇作如是觀，請公莫問何以故。"]'),
('8807aaf4-32f6-4347-b6ff-edf11eeb1558','郊居九日','龐謙孺','宋','宋诗','song-poetry','','[]','樹夾門方正，谿侵岸欲隤。',48,'全唐诗/poet.song.122000.json','["樹夾門方正，谿侵岸欲隤。", "水摇雲影動，風抑鳥聲回。", "籬缺舟常過，庭空客不來。", "故人經歲月，又見菊花開。"]'),
('e71fc736-b4a1-4df0-9bab-58caa42fb159','古詩  其一','龐謙孺','宋','宋诗','song-poetry','','[]','處身乾坤中，適意乃其常。',108,'全唐诗/poet.song.122000.json','["處身乾坤中，適意乃其常。", "貧賤亦天然，尤怨徒自傷。", "平生賦命薄，守己豈不良。", "量分稍過差，神理翻百殃。", "苟無濟世具，希進未免狂。", "鄙哉綿上人，遠迹空潛藏。", "市朝車馬喧，不礙松菊芳。", "何妨著衣冠，用捨姑逢場。", "儻無僥倖心，世亦不見戕。"]'),
('63679b1b-b7d8-4d1e-8d3b-debf18876e78','古詩  其二','龐謙孺','宋','宋诗','song-poetry','','[]','十旬五旬病，三日兩日餓。',120,'全唐诗/poet.song.122000.json','["十旬五旬病，三日兩日餓。", "閉門本求安，歲月不可過。", "秋成尚百日，急迫如星火。", "西風吹楸林，木葉朝來墮。", "夕陽下城頭，蟋蟀鳴戶左。", "褰裳臨溪水，照影非昔我。", "悲歌動鄰里，慘慘風滿座。", "懷深聲愈凄，辭絕意難和。", "人生一世間，太半逢坎坷。", "爲樂須及時，倏忽傷老大。"]'),
('4c3b7e5b-4086-41dc-8731-aec5a72873c4','古詩  其三','龐謙孺','宋','宋诗','song-poetry','','[]','西風正浩蕩，出門無所尋。',120,'全唐诗/poet.song.122000.json','["西風正浩蕩，出門無所尋。", "强起理菊花，聊以慰我心。", "傍籬見南山，經旬阻秋霖。", "豈不欲傲遊，慮此泥濘深。", "凉飚带寒烟，暝色著高林。", "歸鳥未遑棲，槭槭風葉吟。", "遊子悲故鄉，感嘆歲月深。", "一室蔽蓬蒿，空壺絕孤斟。", "徘徊東牆下，仰視林端參。", "耿耿夜何長，白露濕衣襟。"]'),
('b4a2b95f-a24d-4166-bdbf-cef83ad18731','古詩  其四','龐謙孺','宋','宋诗','song-poetry','','[]','初日照池底，游魚戲漣漪。',84,'全唐诗/poet.song.122000.json','["初日照池底，游魚戲漣漪。", "落日延西林，蜻蜓弄斜暉。", "忘情體自適，不但禽鳥微。", "以茲慰心胸，富貴如何違。", "捨策看清溪，步屧臨荆扉。", "青天委長流，孤雲無所依。", "居然忘物我，身世忽若遺。"]'),
('093106ee-9068-448d-9120-262c675817b5','古詩  其五','龐謙孺','宋','宋诗','song-poetry','','[]','凡人種園花，但取紅紫麗。',96,'全唐诗/poet.song.122000.json','["凡人種園花，但取紅紫麗。", "今我種園花，所樂在生意。", "侵晨草露濕，園林有清氣。", "寢興不裹首，散策遶花次。", "次第除繁枝，分明去浪蕊。", "客至旋結襟，捨柯惜餘味。", "新稍纔過屋，弱幹漸拂地。", "是中有深趣，欣然心自慰。"]'),
('4662b12b-4d2c-46fe-bcc7-ba8203d44990','古詩  其六','龐謙孺','宋','宋诗','song-poetry','','[]','送客出河門，返手閉籬關。',84,'全唐诗/poet.song.122000.json','["送客出河門，返手閉籬關。", "歸來懸午窗，坐看屋上山。", "眾雛困未覺，擣藥聲已殘。", "倦鳥止不飛，雞犬亦在欄。", "高林靜白日，時覺鳥聲閑。", "寂寂窮巷中，翳翳桑柘間。", "不妨麻稻香，無時來鼻端。"]'),
('d6bba858-913c-4d2e-a39d-e660d57ba070','古詩四首呈劉行簡給事丈  其一','龐謙孺','宋','宋诗','song-poetry','','[]','人生寄寒暑，銷鑠如然薪。',84,'全唐诗/poet.song.122000.json','["人生寄寒暑，銷鑠如然薪。", "但見烈火炎，倏忽糜灰塵。", "不過數十改，即已無此身。", "豈不甚哀哉，言之爲酸辛。", "達士易與足，一飽即自伸。", "遇者運多途，貪婪喪其真。", "如此不飲酒，徒爲世上人。"]'),
('b1c25565-17b5-45fb-8389-f33308418cc3','古詩四首呈劉行簡給事丈  其二','龐謙孺','宋','宋诗','song-poetry','','[]','一室守丘壑，四海無遐想。',84,'全唐诗/poet.song.122000.json','["一室守丘壑，四海無遐想。", "樂此鄰里歡，坐閱草木長。", "燕寢北窗下，枕几遂俯仰。", "清風動柴荆，白日照窮巷。", "接目有佳色，到耳無驚響。", "樂哉心迹安，庶保神氣養。", "百年茅簷下，邈矣千載上。"]'),
('777e3876-0a16-4ff3-9a2d-dc3aaedba748','古詩四首呈劉行簡給事丈  其三','龐謙孺','宋','宋诗','song-poetry','','[]','少年負豪氣，乃心在有爲。',96,'全唐诗/poet.song.122000.json','["少年負豪氣，乃心在有爲。", "天下非我能，胡爲久棲棲。", "聖賢既在上，治具皆設施。", "一廛爲天氓，豈不樂在茲。", "但願禾黍肥，富貴從此辭。", "雨露被東皋，草木含華滋。", "一物遂生成，仰荷皇天私。", "努力且加餐，已矣復何期。"]'),
('0c06ff3f-0dfa-4fac-8f01-00d0982deaf6','古詩四首呈劉行簡給事丈  其四','龐謙孺','宋','宋诗','song-poetry','','[]','人無百年期，乃爲千歲根。',108,'全唐诗/poet.song.122000.json','["人無百年期，乃爲千歲根。", "蓄積爲眾鶵，此意古所敦。", "憫余貧賤士，窘束未易論。", "今歲夏潦至，信宿水浸門。", "舊粟已告竭，新稼無一存。", "朝分糠籺餐，暮掇藜藿吞。", "一身未保活，况敢念子孫。", "雖云傷我懷，賦命不可奔。", "未死尚爲氓，一息猶天恩。"]'),
('c725a963-6e49-4767-b866-843fe86ea281','絕句','龐謙孺','宋','宋诗','song-poetry','','[]','小雨收溪北，微雲沒舍西。',24,'全唐诗/poet.song.122000.json','["小雨收溪北，微雲沒舍西。", "地暄鸚鵡鬭，日暖鷓鴣啼。"]'),
('2d0e5e9b-3cba-4ac7-b423-1fed8e122377','無題二首  其一','龐謙孺','宋','宋诗','song-poetry','','[]','春風桃李容，能得幾時好。',24,'全唐诗/poet.song.122000.json','["春風桃李容，能得幾時好。", "誰憐澗底花，自對春風老。"]'),
('2579157b-bed6-4039-950c-20d0e5fb1198','無題二首  其二','龐謙孺','宋','宋诗','song-poetry','','[]','可惜花無主，分明枉過春。',24,'全唐诗/poet.song.122000.json','["可惜花無主，分明枉過春。", "誰憐桃李艷，却屬路行人。"]'),
('c67eb6bd-440a-4dbb-ba2e-07082fd9cbd1','絕句三首  其一','龐謙孺','宋','宋诗','song-poetry','','[]','楚天落日暮雲浮，痛飲狂歌不覺愁。',32,'全唐诗/poet.song.122000.json','["楚天落日暮雲浮，痛飲狂歌不覺愁。", "醉眼山光似鄉曲，怎知身在漢江頭。"]'),
('115ca088-fbfd-42b0-938c-37b65da92d19','絕句三首  其二','龐謙孺','宋','宋诗','song-poetry','','[]','漢口風光惱殺人，綠楊無數繞江津。',32,'全唐诗/poet.song.122000.json','["漢口風光惱殺人，綠楊無數繞江津。", "草堂日日來新燕，釣艇時時得錦鱗。"]'),
('8a08f6a4-e0e0-4905-9f85-27dd44ccc106','絕句三首  其三','龐謙孺','宋','宋诗','song-poetry','','[]','大別寺前春草深，鳳棲山下漢江清。',32,'全唐诗/poet.song.122000.json','["大別寺前春草深，鳳棲山下漢江清。", "空村野隴誰爲主，賴有流移旅客耕。"]'),
('58c57bea-f006-4d94-b424-22de492b745e','表侄趙文鼎監稅傳老拙所定九品杜詩說正宗作詩告之','龐謙孺','宋','宋诗','song-poetry','','[]','平生竭力參詩句，久矣冥搜見機杼。',160,'全唐诗/poet.song.122000.json','["平生竭力參詩句，久矣冥搜見機杼。", "豈惟藴蓄徹遮欄，要使幽深盡呈露。", "君今學詩叩妙理，頗已具眼識精粗。", "他年陶冶融心神，好與造化開門戶。", "讀之便感誰使然，若見其事在其處。", "會須體物奪天機，便可分庭抗李杜。", "風騷樂府久寂寞，但見坡谷正馳騖。", "君才妙齡中科選，第恐此道非先務。", "詩分九品吾所創，妄與正宗闢行路。", "君今持此欲誰論，勿使羣言生謗怒。"]'),
('9560500f-20d9-4ede-979e-7bfa2d5f168e','還至吳興春事已過綠陰森然小圃可愛摘青梅嘗煮酒一首','龐謙孺','宋','宋诗','song-poetry','','[]','爲客清霜重，歸來夏木蒼。',48,'全唐诗/poet.song.122000.json','["爲客清霜重，歸來夏木蒼。", "雞鵝驚甚大，童稚覺微長。", "花絮今無迹，園林未肯荒。", "青梅應可摘，臘酒要開嘗。"]'),
('5e2c3f55-11b5-4c70-a67a-d463f6290f8f','聞虜人敗于柘皋作口號十首  其一','龐謙孺','宋','宋诗','song-poetry','','[]','正陽門下草還生，宮殿無人也自春。',32,'全唐诗/poet.song.122000.json','["正陽門下草還生，宮殿無人也自春。", "上皇昔日登臨地，愁殺當時老大臣。"]'),
('c1e8b942-db18-4530-a95d-a417f368ad31','聞虜人敗于柘皋作口號十首  其二','龐謙孺','宋','宋诗','song-poetry','','[]','鐵鷂乘時轉海津，兜牟閃閃白如銀。',32,'全唐诗/poet.song.122000.json','["鐵鷂乘時轉海津，兜牟閃閃白如銀。", "只今邊郡羞投拜，淮北淮南正殺人。"]'),
('30eb1660-cc97-4e6d-bb81-cc7f551df274','聞虜人敗于柘皋作口號十首  其三','龐謙孺','宋','宋诗','song-poetry','','[]','文武宣和盛兩班，當時都道取燕山。',32,'全唐诗/poet.song.122000.json','["文武宣和盛兩班，當時都道取燕山。", "三京隨手殘燒盡，今日誰迎二聖還。"]'),
('23379bb7-33ac-4d0d-b723-64e02ad51065','聞虜人敗于柘皋作口號十首  其四','龐謙孺','宋','宋诗','song-poetry','','[]','黏罕中間陷兩京，當時兀朮尚無名。',32,'全唐诗/poet.song.122000.json','["黏罕中間陷兩京，當時兀朮尚無名。", "如今索鬭無時了，不使山川見太平。"]'),
('296a2bd5-57f8-4ac6-9223-4b5d1772cb7a','聞虜人敗于柘皋作口號十首  其五','龐謙孺','宋','宋诗','song-poetry','','[]','胡馬縱橫壓上流，朝廷歲歲講防秋。',32,'全唐诗/poet.song.122000.json','["胡馬縱橫壓上流，朝廷歲歲講防秋。", "相公必欲安淮甸，早發官兵據壽州。"]'),
('b4dc53b4-ee24-4394-a024-1a5b0e8327e6','聞虜人敗于柘皋作口號十首  其六','龐謙孺','宋','宋诗','song-poetry','','[]','京口人來說禁江，似聞胡騎再跳梁。',32,'全唐诗/poet.song.122000.json','["京口人來說禁江，似聞胡騎再跳梁。", "夜來急遞傳新報，見說官軍戰順昌。"]'),
('66ed8050-b063-4c02-bd1d-fae38436bc28','聞虜人敗于柘皋作口號十首  其七','龐謙孺','宋','宋诗','song-poetry','','[]','聞道諸軍遣背嵬，柘皋合戰打頭回。',32,'全唐诗/poet.song.122000.json','["聞道諸軍遣背嵬，柘皋合戰打頭回。", "不煩宣撫親提劍，鐵塔前鋒一布摧。"]'),
('322c4cf6-ca24-4f4c-902b-eead6c6356c3','聞虜人敗于柘皋作口號十首  其八','龐謙孺','宋','宋诗','song-poetry','','[]','戰伐無多生女真，人傳强半是簽軍。',32,'全唐诗/poet.song.122000.json','["戰伐無多生女真，人傳强半是簽軍。", "可憐盡死天兵手，但恐官家不得聞。"]'),
('658d1eb7-d747-4ac6-94a0-fe778bf74fbc','聞虜人敗于柘皋作口號十首  其九','龐謙孺','宋','宋诗','song-poetry','','[]','一自官軍報捷頻，番人無數願歸明。',32,'全唐诗/poet.song.122000.json','["一自官軍報捷頻，番人無數願歸明。", "渠魁未必能方略，所恃多多以力爭。"]'),
('aa65456e-6990-480b-ad5e-e6366b1c770d','聞虜人敗于柘皋作口號十首  其一○','龐謙孺','宋','宋诗','song-poetry','','[]','今年太歲火逢辛，火德炎炎照紫宸。',32,'全唐诗/poet.song.122000.json','["今年太歲火逢辛，火德炎炎照紫宸。", "眼看點虜遭天破，未必朝廷用一人。"]'),
('6a776ac2-b5a3-47a7-bc2a-5c5ab1fc497d','聞虜酋被戕淮南漸平喜而作詩','龐謙孺','宋','宋诗','song-poetry','','[]','聖主久臨御，戢戈息生靈。',180,'全唐诗/poet.song.122000.json','["聖主久臨御，戢戈息生靈。", "狂胡犯天紀，躍馬捨虜庭。", "四海漲烽烟，白晝亦晦冥。", "不惟師無名，豈有間可乘。", "大將失經略，淮壖氣如蒸。", "虜騎犯和州，采石勢不勝。", "登壇刑白馬，意氣甚憑陵。", "朝廷頗憂虞，眾心若摇旌。", "誰知肘腋禍，自彼蕭牆興。", "皇天相我多，一失遂有能。", "黔黎賣釵釧，果見酒價騰。", "坐收不戰功，宵旰今已寧。", "宸章粲星斗，蜂目見丹青。", "行行若死然，此亦不足稱。", "誰云暴無傷，以茲庶可懲。"]'),
('a19379d2-c6a2-4fb0-9ee4-3b030eb478f6','答何中丞伯壽','龐謙孺','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三載皇輿駐武林，宮前新柳漸成陰。',64,'全唐诗/poet.song.122000.json','["三載皇輿駐武林，宮前新柳漸成陰。", "西湖風月愁難度，艮嶽峰巒夢枉尋。", "老馬驚思歸汴路，寒江吼激破胡心。", "白蘋洲上懷鄉久，夜夜啼鵑卧未深。"]'),
('1c1b7ac8-85db-4acf-984e-fad723e41fcf','題天柱山鴻都觀','惠哲','宋','宋诗','song-poetry','','[]','鐘鼓千年後，耕桑萬嶺巔。',48,'全唐诗/poet.song.122000.json','["鐘鼓千年後，耕桑萬嶺巔。", "松杉森老氣，桃李弄餘妍。", "烟暝東西塢，泉分上下田。", "直疑秦避世，自古一山川。"]'),
('8a34e54b-e23a-4b8b-ac3e-36dc0b17415a','西湖社成集來鵲樓詩','李蘩','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖清且淺，中有蘭與蕙。',96,'全唐诗/poet.song.122000.json','["西湖清且淺，中有蘭與蕙。", "烟霧變晦明，鱗蟲潛水裔。", "飛構冒層阜，仙筵敞平澨。", "野饌何芳鮮，烹調列甘脆。", "翩躚麟鳳集，適遇風雲際。", "簪佩耀林皋，觴酌宣文藝。", "社以白蓮申，盟用青松誓。", "莫謂傾蓋新，山林結遺契。"]'),
('6328a78f-2781-4708-872c-9f70f202e1a9','富沙','王逨','宋','宋诗','song-poetry','','[]','忽驚羈旅身，已落富沙灣。',24,'全唐诗/poet.song.122000.json','["忽驚羈旅身，已落富沙灣。", "江海舊茅屋，遥岑带潺湲。"]'),
('cd28d12e-b6eb-4e9f-a202-58debfcc56ff','偈','釋智策','宋','宋诗','song-poetry','','[]','著意忘懷，掘地深埋。',52,'全唐诗/poet.song.122000.json','["著意忘懷，掘地深埋。", "空洞無象，髑髏妄想。", "譬如兩鏡相照，中間早已立象。", "直饒東澗水流西澗水，南山燒炭北山紅。"]'),
('c728ba81-2ebd-4533-bec6-8173a4704bb2','辭眾偈','釋智策','宋','宋诗','song-poetry','','[]','四大既分飛，烟雲任意歸。',24,'全唐诗/poet.song.122000.json','["四大既分飛，烟雲任意歸。", "秋天霜夜月，萬里轉光輝。"]'),
('27893b93-9d36-4638-9eb7-40ba24490129','高宗皇帝挽詞  其一','蕭燧','宋','宋诗','song-poetry','','[]','撥亂中興事，艱難創業同。',48,'全唐诗/poet.song.122000.json','["撥亂中興事，艱難創業同。", "好生天地德，立極帝王功。", "與子基圖永，居尊福祿崇。", "一朝違大養，悽愴櫟陽宮。"]'),
('2cc3758d-90e2-4379-8200-03ad2f1804c3','高宗皇帝挽詞  其二','蕭燧','宋','宋诗','song-poetry','','[]','畫翣排仙仗，龍輴去莫攀。',48,'全唐诗/poet.song.122000.json','["畫翣排仙仗，龍輴去莫攀。", "衣冠藏漢廟，弓劍閟橋山。", "宇宙精神慘，臣民涕泗潸。", "堯階蓂莢在，無復望慈顔。"]'),
('0abd732f-f5da-41e9-a8c7-a08d4919c441','曉步','李繒','宋','宋诗','song-poetry','','[]','曉步閒隨蛺蝶行，村南村北雨新晴。',32,'全唐诗/poet.song.122000.json','["曉步閒隨蛺蝶行，村南村北雨新晴。", "山花野草自幽意，布穀一聲春水生。"]'),
('943951ef-3bde-46c6-bdc1-6a69d9c80c14','頌古三十八首  其一','釋從瑾','宋','宋诗','song-poetry','','[]','誰在畫樓西，相逢語笑低。',24,'全唐诗/poet.song.122000.json','["誰在畫樓西，相逢語笑低。", "到家春色晚，花落鷓鴣啼。"]'),
('1a7d16d2-8482-471b-9c0b-ac182be24809','頌古三十八首  其二','釋從瑾','宋','宋诗','song-poetry','','[]','大地絕纖塵，面南看北斗。',24,'全唐诗/poet.song.122000.json','["大地絕纖塵，面南看北斗。", "嫁雞逐雞飛，嫁狗逐狗走。"]'),
('7c079b23-c33b-49aa-a797-54470d288742','頌古三十八首  其三','釋從瑾','宋','宋诗','song-poetry','','[]','隔牆見角便騎牛，騎入紅塵鬧市遊。',32,'全唐诗/poet.song.122000.json','["隔牆見角便騎牛，騎入紅塵鬧市遊。", "遊徧歸來欄裏卧，三更半夜失踪由。"]'),
('40c2fa09-eedd-444a-9e7f-2ac337b207b0','頌古三十八首  其四','釋從瑾','宋','宋诗','song-poetry','','[]','家家門口透長安，不見纖毫眼界寬。',32,'全唐诗/poet.song.122000.json','["家家門口透長安，不見纖毫眼界寬。", "無法無人誰付囑，難兄難弟自相謾。"]'),
('a083aceb-ac05-4004-b77b-483c1d3c5869','頌古三十八首  其五','釋從瑾','宋','宋诗','song-poetry','','[]','藴空誰見法中王，覿體何曾礙劍光。',32,'全唐诗/poet.song.122000.json','["藴空誰見法中王，覿體何曾礙劍光。", "古廟藤蘿穿戶牖，斷碑風雨碎文章。"]'),
('fb59bfc6-69f6-4bd8-8eea-566cd956b7cf','頌古三十八首  其六','釋從瑾','宋','宋诗','song-poetry','','[]','踏翻地軸地不動，推倒天關天更高。',32,'全唐诗/poet.song.122000.json','["踏翻地軸地不動，推倒天關天更高。", "穩泛鐵船歸少室，至今天下起風濤。"]'),
('de326669-4a4e-4232-b791-d800cf7e7e54','頌古三十八首  其七','釋從瑾','宋','宋诗','song-poetry','','[]','九年冷坐已敗闕，隻履西歸更脫空。',32,'全唐诗/poet.song.122000.json','["九年冷坐已敗闕，隻履西歸更脫空。", "後代兒孫空妄想，鷗鴣啼不爲春風。"]'),
('112979cb-fbcf-41da-900b-3b297bf234db','頌古三十八首  其八','釋從瑾','宋','宋诗','song-poetry','','[]','自有覓不得，無端面發紅。',24,'全唐诗/poet.song.122000.json','["自有覓不得，無端面發紅。", "翻身喫一𨈀，兩手摸虛空。"]'),
('5a01fe5d-3b20-4e3a-aaa3-8674bfcdb233','頌古三十八首  其九','釋從瑾','宋','宋诗','song-poetry','','[]','不會黄梅佛法，夢中合眼惺惺。',28,'全唐诗/poet.song.122000.json','["不會黄梅佛法，夢中合眼惺惺。", "此地無金二兩，俗人酤酒三升。"]'),
('2abfa344-38e0-4c2e-b95d-92d201017548','頌古三十八首  其一○','釋從瑾','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','一箭射雙鵰，雙鵰隨手落。',24,'全唐诗/poet.song.122000.json','["一箭射雙鵰，雙鵰隨手落。", "波摇岳陽城，月滿滕王閣。"]'),
('de56ad74-df8d-424b-94c7-f1d1cc310ba4','頌古三十八首  其一一','釋從瑾','宋','宋诗','song-poetry','','[]','當年高甲已登科，讀盡人間萬卷書。',32,'全唐诗/poet.song.122000.json','["當年高甲已登科，讀盡人間萬卷書。", "今日一身天地窄，思量好事不如無。"]'),
('215ec8e0-7749-4ab2-848f-f8480761f35b','頌古三十八首  其一二','釋從瑾','宋','宋诗','song-poetry','','[]','一喝當頭雷電奔，人間說亦暗銷魂。',32,'全唐诗/poet.song.122000.json','["一喝當頭雷電奔，人間說亦暗銷魂。", "看來豈止聾三日，直至如今海嶽昏。"]'),
('a29b5a77-46bc-4d8a-9a06-360aa447a9ce','頌古三十八首  其一三','釋從瑾','宋','宋诗','song-poetry','','[]','剃頭頭光生，洗脚脚清爽。',24,'全唐诗/poet.song.122000.json','["剃頭頭光生，洗脚脚清爽。", "脫衣上牀眠，抓著通身癢。"]'),
('7f98d781-00d8-48d6-bc5a-6320bb477732','頌古三十八首  其一四','釋從瑾','宋','宋诗','song-poetry','','[]','竹籬茆舍酒旗斜，一個胡蘆敗兩家。',32,'全唐诗/poet.song.122000.json','["竹籬茆舍酒旗斜，一個胡蘆敗兩家。", "酒後不知天與地，皈來滿地是桃花。"]'),
('18753b6f-2733-4dc9-9d76-6af47410acf4','頌古三十八首  其一五','釋從瑾','宋','宋诗','song-poetry','','[]','徹底冰壺無影像，倒翻筋斗模難成。',32,'全唐诗/poet.song.122000.json','["徹底冰壺無影像，倒翻筋斗模難成。", "千峰雨歇黄梅後，桂魄還從海上生。"]'),
('a5701831-3812-45a0-bf9e-e05b3fadee1d','頌古三十八首  其一六','釋從瑾','宋','宋诗','song-poetry','','[]','無目仙人揣骨頭，暗中摸索認王侯。',32,'全唐诗/poet.song.122000.json','["無目仙人揣骨頭，暗中摸索認王侯。", "價高畢竟無人買，冷却勾欄懡㦬休。"]'),
('7e209622-e6ca-4242-aa34-3dd7d28b87ae','頌古三十八首  其一七','釋從瑾','宋','宋诗','song-poetry','','[]','恁麽不得總不得，脫却布衫赤骨律。',32,'全唐诗/poet.song.122000.json','["恁麽不得總不得，脫却布衫赤骨律。", "劈頭一搭忽翻身，便見口開并眼白。"]'),
('7c4cb568-d569-4e80-be00-964248dc639c','頌古三十八首  其一八','釋從瑾','宋','宋诗','song-poetry','','[]','同根一體都如夢，夢裏惺惺眼又花。',32,'全唐诗/poet.song.122000.json','["同根一體都如夢，夢裏惺惺眼又花。", "蝴蝶飛來過牆去，不知春色落誰家。"]'),
('2bcd1171-2280-4229-a669-c18c38f8833b','頌古三十八首  其一九','釋從瑾','宋','宋诗','song-poetry','','[]','甘贄設粥，南泉打鍋。',34,'全唐诗/poet.song.122000.json','["甘贄設粥，南泉打鍋。", "一般病痛，徹底誵訛。", "更有些兒好笑，明朝餓殺禪和。"]'),
('10356ed8-82c6-4020-8eb3-1ee47775c9c1','頌古三十八首  其二○','釋從瑾','宋','宋诗','song-poetry','','[]','悟得平常達本鄉，時人多怕落平常。',32,'全唐诗/poet.song.122000.json','["悟得平常達本鄉，時人多怕落平常。", "青春只有九十日，爛醉都無一百場。"]'),
('5805dd8b-b65f-4d16-b84a-5134975d33cb','頌古三十八首  其二一','釋從瑾','宋','宋诗','song-poetry','','[]','鐘送黄昏雞報曉，趙州何用閒煩惱。',32,'全唐诗/poet.song.122000.json','["鐘送黄昏雞報曉，趙州何用閒煩惱。", "裂破虛空作兩邊，古廟香爐出芝草。"]'),
('0873194b-300e-4bda-865f-92a7f399fe0f','頌古三十八首  其二二','釋從瑾','宋','宋诗','song-poetry','','[]','臨濟趙州，禪林宗匠。',36,'全唐诗/poet.song.122000.json','["臨濟趙州，禪林宗匠。", "特地相逢，恰似相撲。", "撞見今時行脚僧，呼爲兩箇閒和尚。"]'),
('b0c53127-40a4-4d97-b176-7918bb388675','頌古三十八首  其二三','釋從瑾','宋','宋诗','song-poetry','','[]','威風凜凜不容攀，跳入懷中便解顔。',32,'全唐诗/poet.song.122000.json','["威風凜凜不容攀，跳入懷中便解顔。", "不是酒腸寬似海，爭知詩膽大如山。"]'),
('862cf77b-1f1b-46c8-b620-f1e718b6f0b0','頌古三十八首  其二四','釋從瑾','宋','宋诗','song-poetry','','[]','無魔無我已降魔，添得時人眼裏花。',32,'全唐诗/poet.song.122000.json','["無魔無我已降魔，添得時人眼裏花。", "今日鏌铘無用處，也知賊不打貧家。"]'),
('d401b915-906c-409c-8708-84cef55376fe','頌古三十八首  其二五','釋從瑾','宋','宋诗','song-poetry','','[]','棒頭有眼，眼裏無筋。',36,'全唐诗/poet.song.122000.json','["棒頭有眼，眼裏無筋。", "多逢濁富，罕遇清貧。", "自入洞門烟鎖斷，不知世上幾經春。"]'),
('ade8bc0b-840e-4d8c-9fd6-13bbecc60a75','頌古三十八首  其二六','釋從瑾','宋','宋诗','song-poetry','','[]','棚前夜半弄傀儡，行動威儀去就全。',32,'全唐诗/poet.song.122000.json','["棚前夜半弄傀儡，行動威儀去就全。", "子細思量無道理，裏頭畢竟有人牽。"]'),
('41fd926c-2717-46d8-aec7-51ac5c3e8d5f','頌古三十八首  其二七','釋從瑾','宋','宋诗','song-poetry','','[]','一喝兩喝，全機出沒。',32,'全唐诗/poet.song.122000.json','["一喝兩喝，全機出沒。", "賓主歷然，未免俱瞎。", "半夜摸烏龜，明月照積雪。"]'),
('71c9593f-baeb-4921-bf49-2e68193e550e','頌古三十八首  其二八','釋從瑾','宋','宋诗','song-poetry','','[]','須彌倒卓，海水逆流。',31,'全唐诗/poet.song.122000.json','["須彌倒卓，海水逆流。", "同參相訪，作盡冤讎。", "休休，明日黄花蝶也愁。"]'),
('dde7f9a6-4375-43ce-ad37-312b9a22e818','頌古三十八首  其二九','釋從瑾','宋','宋诗','song-poetry','','[]','古帆未掛時，後園驢吃草。',24,'全唐诗/poet.song.122000.json','["古帆未掛時，後園驢吃草。", "日短苦夜長，行人須及早。"]'),
('2f0007c5-8210-4296-9265-e93974e5201e','頌古三十八首  其三○','釋從瑾','宋','宋诗','song-poetry','','[]','當面非暗投，應機皆直說。',36,'全唐诗/poet.song.122000.json','["當面非暗投，應機皆直說。", "乾峰與雲門，兩口同一舌。", "若是續貂人，弄巧便成拙。"]'),
('edc65b4e-1f73-4e4a-9509-d833c82f1149','頌古三十八首  其三一','釋從瑾','宋','宋诗','song-poetry','','[]','頓超見色聞聲句，不涉明心悟道言。',32,'全唐诗/poet.song.122000.json','["頓超見色聞聲句，不涉明心悟道言。", "花落鳥啼巖下寺，月明人喚渡頭船。"]'),
('62a42cc3-d901-4d78-9ee9-a5e0022084c9','頌古三十八首  其三二','釋從瑾','宋','宋诗','song-poetry','','[]','當陽打動番南鼓，萬象森羅立地聞。',32,'全唐诗/poet.song.122000.json','["當陽打動番南鼓，萬象森羅立地聞。", "不是大家齊則劇，難消白日到黄昏。"]'),
('7d802633-ce04-4b87-8ff0-22780bfc9bf4','頌古三十八首  其三三','釋從瑾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭湖裏失却船，赤脚波斯水底眠。',32,'全唐诗/poet.song.122000.json','["洞庭湖裏失却船，赤脚波斯水底眠。", "盡大地人呼不起，春風吹入杏花村。"]'),
('5fe17a89-03fc-482d-9fa3-22531954cd5c','頌古三十八首  其三四','釋從瑾','宋','宋诗','song-poetry','','[]','我手何似佛手，合掌面南看北斗。',31,'全唐诗/poet.song.122000.json','["我手何似佛手，合掌面南看北斗。", "兔推明月上千峰，引得寒山開笑口。"]'),
('412cd5d3-00bb-4171-8210-c8ca84fc4c44','頌古三十八首  其三五','釋從瑾','宋','宋诗','song-poetry','','[]','我脚何似驢脚，急走歸家日將落。',31,'全唐诗/poet.song.122000.json','["我脚何似驢脚，急走歸家日將落。", "自古長安如鏡平，無端醉倒黄幡綽。"]'),
('c02f5f6a-2813-4926-a30a-625861137666','頌古三十八首  其三六','釋從瑾','宋','宋诗','song-poetry','','[]','人人有箇生緣，且非東土與西天。',31,'全唐诗/poet.song.122000.json','["人人有箇生緣，且非東土與西天。", "擊珊瑚樹枝枝好，撒水銀珠顆顆圓。"]'),
('9ca9bbe8-b2df-4b05-9019-7629a82e7d4f','頌古三十八首  其三七','釋從瑾','宋','宋诗','song-poetry','','[]','佛手驢脚生緣，南海波斯泛鐵船。',31,'全唐诗/poet.song.122000.json','["佛手驢脚生緣，南海波斯泛鐵船。", "精金美玉團堆賣，畢竟何曾直一錢。"]'),
('296d4d25-fa39-4200-b50b-5883a442f801','頌古三十八首  其三八','釋從瑾','宋','宋诗','song-poetry','','[]','南枝向暖北枝寒，何事春風作兩般。',32,'全唐诗/poet.song.122000.json','["南枝向暖北枝寒，何事春風作兩般。", "憑仗高樓莫吹笛，大家留取倚闌看。"]'),
('1761dbce-9bdc-4c18-9a75-0ee9c4b7b5b2','頌古三首  其一','釋從瑾','宋','宋诗','song-poetry','','[]','睦州擔板漢，從來見一邊。',24,'全唐诗/poet.song.122000.json','["睦州擔板漢，從來見一邊。", "淺深三尺水，上下兩重天。"]'),
('cb880b7f-43ab-4cf6-825a-a539e97341e8','頌古三首  其二','釋從瑾','宋','宋诗','song-poetry','','[]','開口不見齒，伸手不見掌。',24,'全唐诗/poet.song.122000.json','["開口不見齒，伸手不見掌。", "夜半忽相逢，葛藤長萬丈。"]'),
('4c5dd184-d025-468c-b101-7edd6dc05f54','頌古三首  其三','釋從瑾','宋','宋诗','song-poetry','','[]','玄沙驢前，雲門馬後。',20,'全唐诗/poet.song.122000.json','["玄沙驢前，雲門馬後。", "更問如何，合取狗口。"]'),
('ac63c357-b964-4968-8d41-c754a0c0a9d1','青陽驛  其一','石才孺','宋','宋诗','song-poetry','','[]','幸蜀奔波爲祿兒，聞鈴夜雨有餘悲。',32,'全唐诗/poet.song.122000.json','["幸蜀奔波爲祿兒，聞鈴夜雨有餘悲。", "青陽一夕難高寢，黼幄千官減盛儀。"]'),
('d464cb0c-ea6e-4415-8cb0-787b5b944255','青陽驛  其二','石才孺','宋','宋诗','song-poetry','','[]','錦繃只擬情方昵，繡襪那知禍已成。',32,'全唐诗/poet.song.122000.json','["錦繃只擬情方昵，繡襪那知禍已成。", "自古覆車循一轍，哲王寧不玷聰明。"]'),
('d75784b0-5326-4ab8-9bb8-87abb71d15b3','沈黎使君與客飲王建梅林分韻作詩過沈犀以詩相示闕樹字令漢廣補之','樊漢廣','宋','宋诗','song-poetry','','[]','牆頭冉冉新陽露，忽作玲瓏玉千樹。',128,'全唐诗/poet.song.122000.json','["牆頭冉冉新陽露，忽作玲瓏玉千樹。", "老蛟偃蹇獨避人，卷回飛雪江皋莫。", "何處鳴禽來好音，四月枝垂起黄霧。", "摧折霜餘初不懼，笑看春光等閒度。", "百年夢幻欲無言，吹落吹開豈風故。", "時來薦鼎真偶爾，小住疏籬非不遇。", "我知天地絕茫茫，無爲展轉獨多慮。", "爲花悽斷却回頭，爾亦微酸苦難茹。"]'),
('d24540be-7697-4da3-8986-20d0ea565a16','題龍潭石','吳彥夔','宋','宋诗','song-poetry','','[]','雲山隱隱草芊芊，水色迷離怪石邊。',64,'全唐诗/poet.song.122000.json','["雲山隱隱草芊芊，水色迷離怪石邊。", "百囀黄鸝消永日，千尋白練映長天。", "竹垂清露添詩硯，燕蹴飛花落舞筵。", "林外不知春雨歇，正宜携酒望前川。"]'),
('e3b5f658-5bda-482d-9fe4-04996f45ce78','藤道','范寅孫','宋','宋诗','song-poetry','','[]','峻極藤爲道，盤旋百轉多。',48,'全唐诗/poet.song.122000.json','["峻極藤爲道，盤旋百轉多。", "崖懸枯樹杪，澗折怪巖阿。", "雁入雲霄去，猿從荆棘過。", "誰云西蜀險，較此更如何。"]'),
('63a0924e-eb14-42f2-9704-c5d6673e8b01','和岑子上鄭廣文詩','滕岑父','宋','宋诗','song-poetry','','[]','吾儕不解事，剛欲羊棗嗜。',120,'全唐诗/poet.song.122000.json','["吾儕不解事，剛欲羊棗嗜。", "居然藜莧腸，厚味非天置。", "甘此腐儒餐，庶幾不爲祟。", "朅來釣瀨濱，溪山相嫵媚。", "况復有詩人，深悟作者秘。", "諸公競推挽，其柰造物戲。", "青衫晚從事，著以供燕侍。", "文章可華國，誰云祇小技。", "堂堂陳無敵，敢不三舍避。", "載酒踐前盟，時當問奇字。"]'),
('49f47f29-b667-4c29-9bce-90e5655ece2e','烏石山','黄某','宋','宋诗','song-poetry','','[]','□□□□石，硉突倚山顛。',48,'全唐诗/poet.song.122000.json','["□□□□石，硉突倚山顛。", "□□□羊伏，漫漫萬馬聯。", "何年□□□，終古□桑田。", "□□□□□，□仙□允傳。"]'),
('ea864c3f-0962-4f2f-8402-afdd47f12e39','詠梅','陳伯西','宋','宋诗','song-poetry','','[]','病骨棱棱瘦欲飛，業根猶墮愛梅非。',32,'全唐诗/poet.song.122000.json','["病骨棱棱瘦欲飛，業根猶墮愛梅非。", "夢魂夜夜尋花去，時带寒香踏月歸。"]'),
('905b51e3-44b2-44e1-8ad1-243ca287a735','擬古十三首 行行重行行','洪适','宋','宋诗','song-poetry','','[]','行行重行行，南北各倦游。',96,'全唐诗/poet.song.122000.json','["行行重行行，南北各倦游。", "昔人重別離，一日嗟三秋。", "如何三秋暮，相見尚悠悠。", "方寸正紆軫，何以寫我憂。", "仰瞻衡漢移，俯對蘭菊遂。", "臭味雖云同，光塵若爲異。", "迴風凄且發，飄我別時袂。", "欲知長相思，披衣不勝體。"]'),
('03281bc8-f55c-4811-9b4c-f15f61f0d78c','擬古十三首 青青河畔草','洪适','宋','宋诗','song-poetry','','[]','青青河畔草，英英籬邊菊。',60,'全唐诗/poet.song.122000.json','["青青河畔草，英英籬邊菊。", "雅雅當窗女，濯濯手如玉。", "淵淵錦中意，粲粲未盈幅。", "藁砧天一涯，刀頭誤行卜。", "却鑑怨新眉，誰教遠山綠。"]'),
('043a0bd8-b20c-400b-afe8-6c0150422af9','擬古十三首 青青陵上柏','洪适','宋','宋诗','song-poetry','','[]','青青陵上柏，橚橚庭中竹。',96,'全唐诗/poet.song.122000.json','["青青陵上柏，橚橚庭中竹。", "人壽能幾何，譬彼電過目。", "一觴命暱交，且以慰心曲。", "駕言長安游，川光晨可掬。", "神州何赫戲，高城矗延屬。", "嶢榭干星斗，彫栭錯珠玉。", "鱗鱗王公第，華纓夾繡轂。", "放懷恣槃虞，端憂竟誰逐。"]'),
('aa39556d-9897-4a33-8993-1d0438f32eb3','擬古十三首 今日良宴會','洪适','宋','宋诗','song-poetry','','[]','今日良宴會，朋簪故人家。',84,'全唐诗/poet.song.122000.json','["今日良宴會，朋簪故人家。", "摇情綠綺琴，度曲漁陽撾。", "放歌掀醉髯，晤語粲春葩。", "列坐各知心，游揚相齒牙。", "芬芳須及時，東扶忽西斜。", "胡不厲逸翮，天津問仙槎。", "無爲甘寂漠，痼疾守烟霞。"]'),
('548e387c-3c09-408b-a7e9-2623c0987626','擬古十三首 西北有高樓','洪适','宋','宋诗','song-poetry','','[]','北有高樓，偃蹇軼千門。',95,'全唐诗/poet.song.122000.json','["北有高樓，偃蹇軼千門。", "綺櫳納飛月，璧璫礙翔雲。", "上有絃歌女，哀聲啟鶯唇。", "誰能爲此曲，無乃返香人。", "一章三致志，脩蛾有餘顰。", "不惜饒清響，暗驚梁上塵。", "所悲聽者心，中無涇渭分。", "願作南冥鳥，夕飲玉池津。"]'),
('e7af73f9-c568-4430-a081-fa7cea379f9b','擬古十三首 涉江采芙蓉','洪适','宋','宋诗','song-poetry','','[]','涉江采芙蓉，芳蕤蔭幽沚。',48,'全唐诗/poet.song.122000.json','["涉江采芙蓉，芳蕤蔭幽沚。", "相思不相見，芬香欲誰遺。", "秋容感人心，浪浪睫涵淚。", "不如膝上琴，哀音入君耳。"]'),
('52a98e71-d4b9-4f71-b2ef-62d6b60203d4','擬古十三首 明月皎夜光','洪适','宋','宋诗','song-poetry','','[]','明月皎夜光，瑟瑟扇商籟。',96,'全唐诗/poet.song.122000.json','["明月皎夜光，瑟瑟扇商籟。", "衡紀直西躔，雲章斜左界。", "感彼林薄凋，歲律倏云邁。", "蜻蛚誰汝憐，悽悽鳴戶外。", "昔我耐久朋，著鞭道方泰。", "尉藉繒縞輕，金蘭舊盟改。", "東井不及泉，須女無儔配。", "君看貢公綦，白頭愧傾蓋。"]'),
('74552feb-53a1-4398-95b0-0dc0467b2bb5','擬古十三首 冉冉孤生竹','洪适','宋','宋诗','song-poetry','','[]','冉冉孤生竹，成陰幽谷中。',96,'全唐诗/poet.song.122000.json','["冉冉孤生竹，成陰幽谷中。", "聿來君子室，葛藟施喬松。", "喬松千百尋，攀附猶可窮。", "思君江水深，褰裳難往從。", "同心而偏棲，愧彼摩霄鴻。", "灼灼芙蓉花，凌波媚芳風。", "非不努力愛，秋至無歸鴻。", "昔盟儻不寒，誰歎久西東。"]'),
('ce624c23-3811-4074-8d43-7d02246a7117','擬古十三首 庭前有奇樹','洪适','宋','宋诗','song-poetry','','[]','庭前有奇樹，黄鳥巢其枝。',48,'全唐诗/poet.song.122000.json','["庭前有奇樹，黄鳥巢其枝。", "之子不顧返，失此熙春期。", "采采未盈掬，夕風已紛披。", "路遠悵莫致，雖多亦奚爲。"]'),
('c8455744-ddaa-457c-a1f5-028239ddab5e','擬古十三首 迢迢牽牛星','洪适','宋','宋诗','song-poetry','','[]','迢迢牽牛星，奕奕停梭女。',60,'全唐诗/poet.song.122000.json','["迢迢牽牛星，奕奕停梭女。", "尋盟整瑶轡，緘情遵漢渚。", "欣讌未斯須，別愁眉已度。", "黄月不我留，殘機忍重顧。", "翻羨巫山雲，朝朝楚王遇。"]'),
('7ea9a3e1-014c-407a-847d-d8fafa0893e7','擬古十三首 人生不滿百','洪适','宋','宋诗','song-poetry','','[]','人生不滿百，蟪蛄等春秋。',60,'全唐诗/poet.song.122000.json','["人生不滿百，蟪蛄等春秋。", "花月多風雨，何不蠟屐游。", "朱光忽以馳，退舍未易留。", "生前一杯樂，難與昧者謀。", "臨流羨芳沚，歡言泛輕舟。"]'),
('566fc83b-4f5b-4933-b4a4-35d0ecb65475','擬古十三首 孟冬寒氣至','洪适','宋','宋诗','song-poetry','','[]','孟冬寒氣至，衝風一何厲。',84,'全唐诗/poet.song.122000.json','["孟冬寒氣至，衝風一何厲。", "宿楚失故陰，思蟲柱哀喙。", "客來門冬冬，袖有尺書遺。", "一讀淚先零，再讀心已醉。", "妾如初開花，君如長流水。", "花挽水回難，水捐花去易。", "流水何時休，春榮難久恃。"]'),
('ff4bb719-e1b5-48c1-ad88-ff5603a76c1e','擬古十三首 明月何皎皎','洪适','宋','宋诗','song-poetry','','[]','明月何皎皎，舒光瑩窗綺。',60,'全唐诗/poet.song.122000.json','["明月何皎皎，舒光瑩窗綺。", "宛轉羞空床，披軒步庭際。", "故愛同一心，新愁今兩耳。", "咫尺相會難，迢迢若千里。", "况復千里隔，憂端無窮已。"]'),
('65325185-16bd-419e-b7b5-7ad1a6e4572a','謝洪慶善提刑遺法帖','洪适','宋','宋诗','song-poetry','','[]','紛紛渴驥競秋蛇，鎸鑱收拾俱名家。',96,'全唐诗/poet.song.122000.json','["紛紛渴驥競秋蛇，鎸鑱收拾俱名家。", "吾宗尺牘擅天下，年來野鶩誰肩差。", "庭前書带凝寒綠，架上牙籤富新軸。", "中藏墨妙更奇奇，長物不留沾賸馥。", "生平小楷拘蠅頭，豈知蠆尾與銀鈎。", "從今已辦筆成塚，學奇還許登門不。"]'),
('dbe2b549-ba20-4bdb-9c8a-c8c7cd022af7','春思','洪适','宋','宋诗','song-poetry','','[]','自聞郊外景，多病負年光。',48,'全唐诗/poet.song.122000.json','["自聞郊外景，多病負年光。", "沐雨桃容膩，耽春蝶興狂。", "幽期知我背，遲日爲誰長。", "一枕虛窗寂，爐烟續舊香。"]'),
('3529fb74-fc32-4dc7-88f8-4a76bcc346ad','晚望','洪适','宋','宋诗','song-poetry','','[]','古堞高亭暮，登臨遠眺時。',48,'全唐诗/poet.song.122000.json','["古堞高亭暮，登臨遠眺時。", "菊房棲渥露，荷蓋偃清漪。", "遵渚歸鴻集，投林嘯狖悲。", "關情聊繪句，獨立自遲遲。"]'),
('2f6d3c12-73ad-4bf4-a8fb-65ce05e13725','欲雨','洪适','宋','宋诗','song-poetry','','[]','雨意泄琴床，桃笙驟覺凉。',48,'全唐诗/poet.song.122000.json','["雨意泄琴床，桃笙驟覺凉。", "衝飚方賈勇，藻景荐韜光。", "去室憐鳩婦，封閭看蟻王。", "青燈可吾伴，黄卷任更長。"]'),
('3268b167-949c-43ae-896e-e819e45e7620','客至','洪适','宋','宋诗','song-poetry','','[]','閉關聽剝啄，有客款蓬蒿。',48,'全唐诗/poet.song.122000.json','["閉關聽剝啄，有客款蓬蒿。", "譚壘萬人敵，詞源八月濤。", "園蔬供菜甲，盤實餖桃毛。", "冷淡琴書味，由來屬我曹。"]'),
('66bec49d-a6dd-4052-9fb5-38114213be95','秋懷二首  其一','洪适','宋','宋诗','song-poetry','','[]','送喜得新凉，秋情未憖忘。',48,'全唐诗/poet.song.122000.json','["送喜得新凉，秋情未憖忘。", "弱枝紅皺重，平野碧滋長。", "林迥蟬初亂，籬疏菊自芳。", "吟成轉蕭瑟，徑醉任蒼蒼。"]'),
('8b639b3d-5be0-492a-b35e-e80d569794c0','秋懷二首  其二','洪适','宋','宋诗','song-poetry','','[]','愁緒苦縈人，寒螿殆叵聞。',48,'全唐诗/poet.song.122000.json','["愁緒苦縈人，寒螿殆叵聞。", "瓜疇殘蔓去，蘭畹秀蕤薰。", "遠水涵秋態，餘霞冠夕曛。", "揚揚今夜月，獨與廣庭分。"]'),
('abc64f94-5759-4304-9c47-a7b5cb3e63a0','送人之姑蘇','洪适','宋','宋诗','song-poetry','','[]','吳門千里役，別話不堪聞。',48,'全唐诗/poet.song.122000.json','["吳門千里役，別話不堪聞。", "暫發參商歎，長懷星斗文。", "菊叢黄彩亂，槐路綠行分。", "日冀書郵至，冥鴻接暮雲。"]'),
('dd94984d-ad62-49d4-964e-9b6552aa10a2','送吳傅朋知盱眙','洪适','宋','宋诗','song-poetry','','[]','龜山其下古淮濡，上駟駸駸穩著鞭。',64,'全唐诗/poet.song.122000.json','["龜山其下古淮濡，上駟駸駸穩著鞭。", "千里八年聞皂蓋，九重一旦下青氈。", "名郎他日曾趨禁，靜鎮今朝疊典邊。", "簪筆侍書公雅意，薰風殿閣待誠懸。"]');
